import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider, AuthContext } from "./context/AuthContext";
import { useContext } from "react";
import { Toaster } from "react-hot-toast";

import LandingPage from "./pages/LandingPage";
import Login from "./pages/auth/Login";

import AdminLayout from "./pages/admin/AdminLayout";
import AdminDashboard from "./pages/admin/AdminDashboard";
import AdminStudents from "./pages/admin/AdminStudents";
import AdminFaculty from "./pages/admin/AdminFaculty";
import AdminCourses from "./pages/admin/AdminCourses";
import ManageCourse from "./pages/admin/ManageCourse";
import AdminAttendance from "./pages/admin/AdminAttendance";
import AdminMaterials from "./pages/admin/AdminMaterials";
import AdminResults from "./pages/admin/AdminResults";
import AdminNotices from "./pages/admin/AdminNotices";
import AdminAnalytics from "./pages/admin/AdminAnalytics";
import AdminHours from "./pages/admin/AdminHours";
import AdminTimetable from "./pages/admin/AdminTimetable";
import AdminSettings from "./pages/admin/AdminSettings";
import AdminQuizzes from "./pages/admin/AdminQuizzes";
import AdminQRCheckin from "./pages/admin/AdminQRCheckin";

import FacultyLayout from "./pages/faculty/FacultyLayout";
import FacultyDashboard from "./pages/faculty/FacultyDashboard";
import FacultyAttendance from "./pages/faculty/FacultyAttendance";
import FacultyResults from "./pages/faculty/FacultyResults";
import FacultyBatches from "./pages/faculty/FacultyBatches";
import FacultyTimetable from "./pages/faculty/FacultyTimetable";
import FacultyNotices from "./pages/faculty/FacultyNotices";
import FacultyHours from "./pages/faculty/FacultyHours";
import FacultyMaterials from "./pages/faculty/FacultyMaterials";
import FacultyProfile from "./pages/faculty/FacultyProfile";

import StudentLayout from "./pages/student/StudentLayout";
import StudentDashboard from "./pages/student/StudentDashboard";
import StudentAttendance from "./pages/student/StudentAttendance";
import StudentResults from "./pages/student/StudentResults";
import StudentMaterials from "./pages/student/StudentMaterials";
import StudentTimetable from "./pages/student/StudentTimetable";
import StudentNotices from "./pages/student/StudentNotices";
import StudentProfile from "./pages/student/StudentProfile";
import StudentQuizzes from "./pages/student/StudentQuizzes";
import QuizPortal from "./pages/student/QuizPortal";

// Protected Route Wrapper
const ProtectedRoute = ({ children, allowedRoles }) => {
  const { user, loading } = useContext(AuthContext);

  if (loading) return <div className="min-h-screen flex items-center justify-center">Loading...</div>;

  if (!user) return <Navigate to="/login" replace />;

  if (allowedRoles && !allowedRoles.includes(user.role)) {
    return <Navigate to="/" replace />; // Redirect if unauthorized
  }

  return children;
};

function App() {
  return (
    <AuthProvider>
      <Toaster position="top-center" reverseOrder={false} />
      <BrowserRouter>
        <Routes>
          <Route path="/" element={<LandingPage />} />
          <Route path="/login" element={<Login />} />

          {/* Nested Admin Routes */}
          <Route path="/admin" element={
            <ProtectedRoute allowedRoles={["admin"]}>
              <AdminLayout />
            </ProtectedRoute>
          }>
            <Route index element={<AdminDashboard />} />
            <Route path="students" element={<AdminStudents />} />
            <Route path="faculty" element={<AdminFaculty />} />
            <Route path="courses" element={<AdminCourses />} />
            <Route path="courses/:id" element={<ManageCourse />} />
            <Route path="attendance" element={<AdminAttendance />} />
            <Route path="materials" element={<AdminMaterials />} />
            <Route path="results" element={<AdminResults />} />
            <Route path="notices" element={<AdminNotices />} />
            <Route path="analytics" element={<AdminAnalytics />} />
            <Route path="hours" element={<AdminHours />} />
            <Route path="timetable" element={<AdminTimetable />} />
            <Route path="settings" element={<AdminSettings />} />
            <Route path="quizzes" element={<AdminQuizzes />} />
            <Route path="qr-checkin" element={<AdminQRCheckin />} />
          </Route>

          {/* Nested Faculty Routes */}
          <Route path="/faculty" element={
            <ProtectedRoute allowedRoles={["faculty", "admin"]}>
              <FacultyLayout />
            </ProtectedRoute>
          }>
            <Route index element={<FacultyDashboard />} />
            <Route path="attendance" element={<FacultyAttendance />} />
            <Route path="results" element={<FacultyResults />} />
            <Route path="batches" element={<FacultyBatches />} />
            <Route path="timetable" element={<FacultyTimetable />} />
            <Route path="notices" element={<FacultyNotices />} />
            <Route path="hours" element={<FacultyHours />} />
            <Route path="materials" element={<FacultyMaterials />} />
            <Route path="profile" element={<FacultyProfile />} />
            <Route path="quizzes" element={<AdminQuizzes />} />
          </Route>

          {/* Nested Student Routes */}
          <Route path="/student" element={
            <ProtectedRoute allowedRoles={["student"]}>
              <StudentLayout />
            </ProtectedRoute>
          }>
            <Route index element={<StudentDashboard />} />
            <Route path="attendance" element={<StudentAttendance />} />
            <Route path="results" element={<StudentResults />} />
            <Route path="materials" element={<StudentMaterials />} />
            <Route path="timetable" element={<StudentTimetable />} />
            <Route path="notices" element={<StudentNotices />} />
            <Route path="profile" element={<StudentProfile />} />
            <Route path="quizzes" element={<StudentQuizzes />} />
          </Route>

          {/* Quiz Portal - No Sidebar */}
          <Route path="/student/quizzes/:id" element={
            <ProtectedRoute allowedRoles={["student"]}>
              <QuizPortal />
            </ProtectedRoute>
          } />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;

