import { useState, useEffect } from "react";
import { X, Save, UserSquare2 } from "lucide-react";
import toast from "react-hot-toast";
import axios from "axios";

const FacultyFormModal = ({ isOpen, onClose, faculty, onSaveSuccess }) => {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    subject: "",
    experience: "",
    status: "Active",
  });

  useEffect(() => {
    if (faculty) {
      setFormData({
        name: faculty.name,
        email: faculty.email,
        subject: faculty.subject,
        experience: faculty.experience,
        status: faculty.status,
      });
    } else {
      setFormData({
        name: "",
        email: "",
        subject: "",
        experience: "",
        status: "Active",
      });
    }
  }, [faculty, isOpen]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const loadingToast = toast.loading(faculty ? "Updating faculty..." : "Adding faculty...");
    try {
      if (faculty) {
        await axios.put(`http://localhost:5001/api/faculty/${faculty._id}`, formData);
        toast.success("Faculty updated successfully", { id: loadingToast });
      } else {
        await axios.post("http://localhost:5001/api/faculty", formData);
        toast.success("Faculty added successfully", { id: loadingToast });
      }
      onSaveSuccess();
      onClose();
    } catch (error) {
      toast.error(error.response?.data?.message || "Something went wrong", { id: loadingToast });
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={onClose}></div>
      <div className="relative bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
        <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center">
              <UserSquare2 size={24} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">
                {faculty ? "Edit Faculty" : "Add New Faculty"}
              </h2>
              <p className="text-slate-400 text-sm font-medium">Faculty Member Details</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition text-slate-400">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Full Name</label>
              <input 
                name="name"
                value={formData.name}
                onChange={handleChange}
                required
                type="text" 
                placeholder="Dr. Arvind Mehta"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-indigo-600 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
              <input 
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                type="email" 
                placeholder="mehta.physics@srs.com"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-indigo-600 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Subject</label>
                <input 
                  name="subject"
                  value={formData.subject}
                  onChange={handleChange}
                  required
                  type="text" 
                  placeholder="Physics"
                  className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-indigo-600 outline-none transition-all font-bold text-slate-700" 
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Experience</label>
                <input 
                  name="experience"
                  value={formData.experience}
                  onChange={handleChange}
                  required
                  type="text" 
                  placeholder="10 Years"
                  className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-indigo-600 outline-none transition-all font-bold text-slate-700" 
                />
              </div>
            </div>
            {faculty && (
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Status</label>
                <select 
                  name="status"
                  value={formData.status}
                  onChange={handleChange}
                  className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-indigo-600 outline-none transition-all font-bold text-slate-700 cursor-pointer"
                >
                  <option value="Active">Active</option>
                  <option value="Leave">Leave</option>
                  <option value="Inactive">Inactive</option>
                </select>
              </div>
            )}
          </div>

          <div className="pt-6 flex gap-4">
            <button 
              type="button"
              onClick={onClose}
              className="flex-1 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 transition uppercase tracking-widest text-xs"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex-1 py-4 bg-indigo-600 text-white font-black rounded-2xl shadow-xl shadow-indigo-600/20 hover:bg-indigo-700 transition flex items-center justify-center gap-2 uppercase tracking-widest text-xs"
            >
              <Save size={18} /> {faculty ? "Update Faculty" : "Save Faculty"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default FacultyFormModal;

