import { useRef } from "react";
import { Download, Upload } from "lucide-react";
import toast from "react-hot-toast";
import axios from "axios";

const CSVUploadButton = ({ onUploadSuccess }) => {
  const fileInputRef = useRef(null);

  const handleFileChange = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (file.type !== "text/csv" && !file.name.endsWith(".csv")) {
      toast.error("Please upload a valid CSV file");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    const loadingToast = toast.loading("Importing students...");
    try {
      const { data } = await axios.post("http://localhost:5001/api/students/import", formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });
      toast.success(data.message, { id: loadingToast });
      onUploadSuccess();
      // Reset file input
      if (fileInputRef.current) fileInputRef.current.value = "";
    } catch (error) {
      toast.error(error.response?.data?.message || "Error importing students", { id: loadingToast });
    }
  };

  return (
    <div>
      <input 
        type="file" 
        ref={fileInputRef}
        onChange={handleFileChange}
        accept=".csv"
        className="hidden"
      />
      <button 
        onClick={() => fileInputRef.current?.click()}
        className="flex items-center gap-2 px-5 py-3 bg-white border border-slate-200 text-slate-700 font-bold rounded-2xl hover:bg-slate-50 transition shadow-sm"
      >
        <Download size={18} /> Bulk Import (CSV)
      </button>
    </div>
  );
};

export default CSVUploadButton;

