import { useState, useEffect } from "react";
import { X, Save, User } from "lucide-react";
import toast from "react-hot-toast";
import axios from "axios";

const StudentFormModal = ({ isOpen, onClose, student, onSaveSuccess }) => {
  const [formData, setFormData] = useState({
    name: "",
    rollNo: "",
    email: "",
    phone: "",
    batch: "",
    course: "",
    feesStatus: "pending",
  });

  useEffect(() => {
    if (student) {
      setFormData({
        name: student.name,
        rollNo: student.rollNo,
        email: student.email,
        phone: student.phone,
        batch: student.batch,
        course: student.course,
        feesStatus: student.feesStatus,
      });
    } else {
      setFormData({
        name: "",
        rollNo: "",
        email: "",
        phone: "",
        batch: "",
        course: "",
        feesStatus: "pending",
      });
    }
  }, [student, isOpen]);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const loadingToast = toast.loading(student ? "Updating student..." : "Adding student...");
    try {
      if (student) {
        await axios.put(`http://localhost:5001/api/students/${student._id}`, formData);
        toast.success("Student updated successfully", { id: loadingToast });
      } else {
        await axios.post("http://localhost:5001/api/students", formData);
        toast.success("Student added successfully", { id: loadingToast });
      }
      onSaveSuccess();
      onClose();
    } catch (error) {
      toast.error(error.response?.data?.message || "Something went wrong", { id: loadingToast });
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={onClose}></div>
      <div className="relative bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
        <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
