            <div className="w-12 h-12 rounded-2xl bg-blue-900 text-white flex items-center justify-center">
              <User size={24} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-800 tracking-tight">
                {student ? "Edit Student" : "Add New Student"}
              </h2>
              <p className="text-slate-400 text-sm font-medium">Fill in the details below</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition text-slate-400">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Full Name</label>
              <input 
                name="name"
                value={formData.name}
                onChange={handleChange}
                required
                type="text" 
                placeholder="John Doe"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Roll Number</label>
              <input 
                name="rollNo"
                value={formData.rollNo}
                onChange={handleChange}
                required
                type="text" 
                placeholder="SRS-101"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Email Address</label>
              <input 
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                type="email" 
                placeholder="john@example.com"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Phone Number</label>
              <input 
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                required
                type="text" 
                placeholder="+91 9988776655"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Batch</label>
              <input 
                name="batch"
                value={formData.batch}
                onChange={handleChange}
                required
                type="text" 
                placeholder="JEE Target 2026"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Course</label>
              <input 
                name="course"
                value={formData.course}
                onChange={handleChange}
                required
                type="text" 
                placeholder="JEE / NEET"
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Fees Status</label>
              <select 
                name="feesStatus"
                value={formData.feesStatus}
                onChange={handleChange}
                className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 bg-slate-50 focus:bg-white focus:border-blue-900 outline-none transition-all font-bold text-slate-700 cursor-pointer"
              >
                <option value="paid">Paid</option>
                <option value="pending">Pending</option>
                <option value="partial">Partial</option>
              </select>
            </div>
          </div>

          <div className="pt-6 flex gap-4">
            <button 
              type="button"
              onClick={onClose}
              className="flex-1 py-4 bg-slate-100 text-slate-600 font-black rounded-2xl hover:bg-slate-200 transition uppercase tracking-widest text-xs"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex-1 py-4 bg-blue-900 text-white font-black rounded-2xl shadow-xl shadow-blue-900/20 hover:bg-blue-800 transition flex items-center justify-center gap-2 uppercase tracking-widest text-xs"
            >
              <Save size={18} /> {student ? "Update Student" : "Save Student"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default StudentFormModal;

