import { useEffect, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:5001/api";

const ACCENTS = [
  "from-blue-900 to-blue-700",
  "from-amber-500 to-orange-500",
  "from-slate-900 to-slate-700",
  "from-emerald-600 to-teal-600",
  "from-rose-600 to-pink-600",
  "from-violet-600 to-indigo-600",
];

const CoursesSection = () => {
  const [courses, setCourses] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchCourses = async () => {
      try {
        const { data } = await axios.get(`${API_URL}/courses`);
        setCourses(data);
      } catch (error) {
        console.error("Failed to fetch courses:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchCourses();
  }, []);

  return (
    <section id="courses" className="bg-white px-4 py-16 sm:px-6 lg:px-8 lg:py-24">
      <div className="mx-auto max-w-7xl">
        <div className="flex flex-col gap-4 lg:flex-row lg:items-end lg:justify-between">
          <div className="max-w-2xl">
            <p className="text-sm font-semibold uppercase tracking-[0.28em] text-blue-900">
              Courses & Batches
            </p>
            <h2 className="mt-3 text-3xl font-bold tracking-tight text-slate-950 sm:text-4xl">
              Structured programs for every stage of the student journey
            </h2>
          </div>
          <p className="max-w-xl text-sm leading-7 text-slate-600">
            Foundation support, board-integrated coaching, and repeater-focused
            preparation built around consistency and exam performance.
          </p>
        </div>

        {loading ? (
          <div className="mt-10 flex justify-center py-20">
            <div className="h-10 w-10 animate-spin rounded-full border-4 border-blue-900 border-t-transparent"></div>
          </div>
        ) : courses.length === 0 ? (
          <div className="mt-10 text-center py-20 text-slate-500 font-medium">
            No courses available at the moment. Please check back later.
          </div>
        ) : (
          <div className="mt-10 grid gap-6 lg:grid-cols-3">
            {courses.map((course, index) => (
              <article
                key={course._id}
                className="overflow-hidden rounded-[30px] border border-slate-100 bg-slate-50 shadow-sm transition-all duration-300 hover:shadow-xl hover:shadow-blue-900/5"
              >
                <div className={`h-2 bg-gradient-to-r ${ACCENTS[index % ACCENTS.length]}`} />
                <div className="p-7">
                  <div className="inline-flex rounded-full bg-white px-3 py-1 text-xs font-semibold uppercase tracking-[0.2em] text-slate-500 shadow-sm">
                    {course.type || "New Batch"}
                  </div>
                  <h3 className="mt-5 text-2xl font-semibold text-slate-950">
                    {course.name}
                  </h3>
                  <div className="mt-6 space-y-4">
                    <div className="rounded-2xl bg-white p-4 shadow-sm min-h-[100px]">
                      <p className="text-xs font-semibold uppercase tracking-[0.2em] text-slate-400">
                        Description
                      </p>
                      <p className="mt-2 text-sm text-slate-700 line-clamp-3">
                        {course.description || "Comprehensive coaching program designed for academic excellence."}
                      </p>
                    </div>
                    <div className="flex gap-4">
                      <div className="flex-1 rounded-2xl bg-white p-4 shadow-sm text-center">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Batches</p>
                        <p className="mt-1 text-sm font-bold text-slate-700">{course.batchCount || 0}</p>
                      </div>
                      <div className="flex-1 rounded-2xl bg-white p-4 shadow-sm text-center">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Students</p>
                        <p className="mt-1 text-sm font-bold text-slate-700">{course.studentCount || 0}</p>
                      </div>
                    </div>
                  </div>
