import { useMemo } from "react";

const AttendanceHeatmap = ({ data }) => {
  // Generate last 365 days
  const days = useMemo(() => {
    const result = [];
    const today = new Date();
    for (let i = 364; i >= 0; i--) {
      const d = new Date(today);
      d.setDate(today.getDate() - i);
      const dateStr = d.toISOString().split("T")[0];
      const record = data.find((r) => r.date === dateStr);
      result.push({
        date: d,
        dateStr,
        status: record ? record.status : "no_class",
      });
    }
    return result;
  }, [data]);

  const getColor = (status) => {
    switch (status) {
      case "present":
        return "bg-emerald-500 shadow-sm shadow-emerald-500/20";
      case "absent":
        return "bg-red-500 shadow-sm shadow-red-500/20";
      default:
        return "bg-slate-200";
    }
  };

  const months = [
    "Jan", "Feb", "Mar", "Apr", "May", "Jun", 
    "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"
  ];

