import { useEffect, useState } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { Activity, BarChart3 } from "lucide-react";
import { ComposedChart, Line, Area, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from "recharts";

// API base URL is handled by axiosInstance

const AdminAnalytics = () => {
  const [stats, setStats] = useState({ monthlyGrowth: [], attendanceByDay: [] });
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([axios.get("/admin/stats"), axios.get("/results")])
      .then(([statsRes, resultsRes]) => {
        setStats(statsRes.data);
        setResults(resultsRes.data || []);
      })
      .catch((error) => toast.error(error.response?.data?.message || "Failed to load analytics"))
      .finally(() => setLoading(false));
  }, []);

  const chartData = (stats.monthlyGrowth || []).map((row, index) => ({
    name: row.month,
    attendance: stats.attendanceByDay?.[index]?.rate || 0,
    enrollment: row.students || 0,
    fees: row.fees || 0,
  }));

  const totalResultEntries = results.reduce((sum, result) => sum + result.records.length, 0);
  const avgScore = totalResultEntries
    ? Math.round(
        results.reduce(
          (sum, result) => sum + result.records.reduce((inner, record) => inner + (result.totalMarks ? (record.marks / result.totalMarks) * 100 : 0), 0),
          0
        ) / totalResultEntries
      )
    : 0;

  return (
    <div className="space-y-10 animate-fade-in">
      <header>
        <h1 className="text-3xl font-black text-slate-800 tracking-tight">Advanced Analytics</h1>
        <p className="text-slate-500 mt-1 font-medium">Live institute growth, attendance, financial, and result trends.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-[2fr_1fr] gap-8">
        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-8">
            <div>
              <h2 className="text-2xl font-black text-slate-800">Live Correlation</h2>
              <p className="text-slate-400 text-sm font-medium">Attendance, enrollment, and fees from database records.</p>
            </div>
            <Activity className="text-emerald-500" />
          </div>
          <div className="h-[400px] w-full">
            {loading ? (
              <div className="h-full flex items-center justify-center text-slate-400">Loading...</div>
            ) : chartData.length === 0 ? (
              <div className="h-full flex items-center justify-center text-slate-400">No analytics data yet.</div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <ComposedChart data={chartData}>
                  <CartesianGrid stroke="#f1f5f9" vertical={false} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: "#94a3b8", fontSize: 12 }} />
                  <YAxis axisLine={false} tickLine={false} tick={{ fill: "#94a3b8", fontSize: 12 }} />
