import { useEffect, useState, useCallback } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Search, AlertTriangle, UserCheck, RefreshCw } from "lucide-react";

const API = "http://localhost:5001/api";

const AdminAttendance = () => {
  const [batches, setBatches] = useState([]);
  const [selectedBatch, setSelectedBatch] = useState("");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
  const [logs, setLogs] = useState([]);
  const [todayPercentage, setTodayPercentage] = useState(0);
  const [todayAbsent, setTodayAbsent] = useState(0);
  const [lowStudents, setLowStudents] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(false);
  const [loadingLow, setLoadingLow] = useState(true);
  const [initialLoaded, setInitialLoaded] = useState(false);

  // Load all batches for dropdown
  useEffect(() => {
    axios
      .get(`${API}/attendance/admin/batches`)
      .then(({ data }) => setBatches(data))
      .catch(() => {});
  }, []);

  // Load low attendance alerts
  const fetchLowAttendance = useCallback(() => {
    setLoadingLow(true);
    axios
      .get(`${API}/attendance/admin/low`)
      .then(({ data }) => setLowStudents(data))
      .catch(() => toast.error("Failed to load critical alerts"))
      .finally(() => setLoadingLow(false));
  }, []);

  useEffect(() => { fetchLowAttendance(); }, [fetchLowAttendance]);

  // Fetch overview — uses current state values passed as args to avoid stale closure
  const fetchOverview = useCallback(async (batchId, dateVal) => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (dateVal) params.append("date", dateVal);
      if (batchId) params.append("batch", batchId);

      const { data } = await axios.get(`${API}/attendance/admin/overview?${params}`);
      setLogs(data.logs || []);
      setTodayPercentage(data.todayPercentage ?? 0);
      setTodayAbsent(data.todayAbsent ?? 0);
    } catch {
      toast.error("Failed to load attendance data");
    } finally {
      setLoading(false);
      setInitialLoaded(true);
    }
  }, []);

  // Load on mount with today's date
  useEffect(() => {
    fetchOverview("", new Date().toISOString().split("T")[0]);
  }, [fetchOverview]);

  const handleApplyFilters = () => {
    fetchOverview(selectedBatch, date);
  };

  const filteredLogs = logs.filter((l) =>
    l.batch.toLowerCase().includes(search.toLowerCase()) ||
    l.teacher.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-10 animate-fade-in">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Attendance Monitoring</h1>
          <p className="text-slate-500 mt-1 font-medium">Global oversight of student discipline across all batches.</p>
        </div>
        <div className="flex gap-3 bg-white p-2 rounded-[1.5rem] border border-slate-100 shadow-sm">
          <div className="flex items-center gap-2 px-4 py-2 border-r border-slate-100">
            <span className="w-2.5 h-2.5 rounded-full bg-emerald-500" />
            <span className="text-sm font-bold text-slate-700">{todayPercentage}% Today</span>
          </div>
          <div className="flex items-center gap-2 px-4 py-2">
            <span className="w-2.5 h-2.5 rounded-full bg-red-500" />
            <span className="text-sm font-bold text-slate-700">{todayAbsent} Absentees</span>
          </div>
        </div>
      </header>

      {/* Filters */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <div className="grid md:grid-cols-3 gap-4 w-full">
          <div>
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1 mb-1.5 block">
              Select Batch
            </label>
            <select
              value={selectedBatch}
              onChange={(e) => setSelectedBatch(e.target.value)}
              className="w-full px-5 py-3 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all"
            >
              <option value="">All Batches</option>
              {batches.map((b) => (
                <option key={b._id} value={b._id}>
                  {b.name}{b.course ? ` (${b.course.name})` : ""}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1 mb-1.5 block">
              Select Date
            </label>
            <input
              type="date"
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full px-5 py-3 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all"
            />
          </div>
          <div className="flex items-end">
            <button
              onClick={handleApplyFilters}
              disabled={loading}
              className="w-full py-3 bg-slate-900 text-white font-black rounded-2xl hover:bg-slate-800 disabled:opacity-50 transition shadow-lg shadow-slate-900/20 uppercase tracking-widest text-xs flex items-center justify-center gap-2"
            >
              {loading ? (
                <><RefreshCw size={14} className="animate-spin" /> Loading...</>
              ) : (
                "Apply Filters"
              )}
            </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-[1.5fr_1fr] gap-8">
        {/* Batch Logs */}
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/30">
            <div>
              <h2 className="text-xl font-bold text-slate-800">Batch Logs</h2>
              {initialLoaded && (
                <p className="text-xs text-slate-400 mt-0.5">{filteredLogs.length} record(s) found</p>
              )}
            </div>
            <div className="relative w-48">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                type="text"
                placeholder="Search batch / faculty..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-xl text-xs focus:border-blue-900 outline-none"
              />
            </div>
          </div>

          {loading ? (
            <div className="flex items-center justify-center py-20">
              <div className="animate-spin w-8 h-8 border-4 border-blue-200 border-t-blue-600 rounded-full" />
            </div>
          ) : filteredLogs.length === 0 ? (
            <div className="text-center py-20 text-slate-400">
              <UserCheck size={32} className="mx-auto mb-3 opacity-30" />
              <p className="text-sm font-medium">No attendance records found.</p>
              <p className="text-xs mt-1">Faculty must mark attendance first.</p>
            </div>
          ) : (
            <div className="divide-y divide-slate-50">
              {filteredLogs.map((log) => {
                const pct = log.total ? Math.round((log.present / log.total) * 100) : 0;
                return (
                  <div key={log._id} className="p-6 flex items-center justify-between hover:bg-slate-50/50 transition">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                        pct >= 75 ? "bg-emerald-50 text-emerald-600" : pct >= 50 ? "bg-amber-50 text-amber-600" : "bg-red-50 text-red-600"
                      }`}>
                        <UserCheck size={20} />
                      </div>
                      <div>
                        <h3 className="font-bold text-slate-800">{log.batch}</h3>
                        <p className="text-xs text-slate-400 font-medium mt-0.5">
                          {log.teacher} &bull;{" "}
                          {new Date(log.date).toLocaleDateString("en-US", {
                            weekday: "short", month: "short", day: "numeric", year: "numeric",
                          })}
                        </p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-lg font-black text-slate-700">{log.present}/{log.total}</p>
                      <p className={`text-xs font-black uppercase tracking-tight ${
                        pct >= 75 ? "text-emerald-500" : pct >= 50 ? "text-amber-500" : "text-red-500"
                      }`}>
                        {pct}%
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Low Attendance Alerts */}
        <div className="bg-red-50 p-8 rounded-[2.5rem] border border-red-100 shadow-sm flex flex-col">
          <div className="flex items-center justify-between mb-2">
            <h2 className="text-xl font-bold text-red-900 flex items-center gap-2">
              <AlertTriangle size={20} className="text-red-600" /> Critical Alerts
            </h2>
            <button
              onClick={fetchLowAttendance}
              disabled={loadingLow}
              className="p-2 rounded-xl hover:bg-red-100 text-red-400 transition"
              title="Refresh"
            >
              <RefreshCw size={14} className={loadingLow ? "animate-spin" : ""} />
            </button>
          </div>
          <p className="text-red-700/60 text-xs font-black uppercase tracking-widest mb-6">
            Students with &lt; 75% Attendance
          </p>

          {loadingLow ? (
            <div className="flex items-center justify-center flex-1 py-12">
              <div className="animate-spin w-7 h-7 border-4 border-red-200 border-t-red-500 rounded-full" />
            </div>
          ) : lowStudents.length === 0 ? (
            <div className="flex-1 flex flex-col items-center justify-center py-12 text-center">
              <div className="w-12 h-12 rounded-full bg-emerald-100 flex items-center justify-center mb-3">
                <span className="text-2xl">🎉</span>
              </div>
              <p className="text-sm font-bold text-slate-600">All students above 75%</p>
              <p className="text-xs text-slate-400 mt-1">No critical alerts at this time.</p>
            </div>
          ) : (
            <div className="space-y-3 overflow-y-auto max-h-[420px] pr-1">
              {lowStudents.map((s, i) => (
                <div key={i} className="p-4 bg-white rounded-2xl border border-red-200 shadow-sm flex items-center justify-between">
                  <div>
                    <p className="font-bold text-slate-800 text-sm">{s.name}</p>
                    <p className="text-xs text-slate-500 mt-0.5">{s.batch}</p>
                    <p className="text-[10px] text-slate-400">{s.rollNo}</p>
                  </div>
                  <div className="text-right">
                    <p className="text-xl font-black text-red-600">{s.percentage}%</p>
                    <div className="w-16 h-1.5 bg-red-100 rounded-full mt-1.5 overflow-hidden">
                      <div
                        className="h-full bg-red-500 rounded-full"
                        style={{ width: `${s.percentage}%` }}
                      />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminAttendance;

