                    <p className="text-lg font-black text-slate-800">{batch.name}</p>
                    <p className="text-xs font-bold text-slate-400">{batch.faculty?.name || "—"}</p>
                    <p className="text-[10px] text-slate-400">{batch.course?.name || "—"}</p>
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-center mb-2">
                      <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Syllabus Progress</p>
                      <p className="text-xs font-black text-slate-800">{batch.progress}%</p>
                    </div>
                    <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden">
                      <div className={`h-full ${fill} rounded-full transition-all duration-1000`} style={{ width: `${batch.progress}%` }} />
                    </div>
                  </div>
                  <div className="flex gap-2 flex-shrink-0">
                    <button onClick={() => setRosterBatch(batch)}
                      className="px-5 py-2.5 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl text-xs hover:bg-slate-100 transition shadow-sm">
                      View Roster
                    </button>
                    <button onClick={() => openEditBatch(batch)}
                      className="p-2.5 bg-white border border-slate-200 text-slate-500 rounded-xl hover:bg-slate-100 transition shadow-sm">
                      <Pencil size={14} />
                    </button>
                    <button onClick={() => deleteBatch(batch._id)}
                      className="p-2.5 bg-white border border-red-100 text-red-400 rounded-xl hover:bg-red-50 transition shadow-sm">
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Modals */}
      {courseModal && (
        <Modal title={courseModal === "create" ? "New Course" : "Edit Course"} onClose={() => setCourseModal(null)}>
          <CourseForm initial={courseModal !== "create" ? courseModal : null} onSave={saveCourse} onClose={() => setCourseModal(null)} />
        </Modal>
      )}

      {batchModal && (
        <Modal title={batchModal === "create" ? "Create Batch" : "Edit Batch"} onClose={() => setBatchModal(null)}>
          <BatchForm
            courses={courses}
            faculties={faculties}
            students={allStudents}
            initial={batchModal !== "create" ? batchModal : null}
            onSave={saveBatch}
            onClose={() => setBatchModal(null)}
          />
        </Modal>
      )}

      {rosterBatch && <RosterModal batch={rosterBatch} onClose={() => setRosterBatch(null)} />}
    </div>
  );
};

export default AdminCourses;

