import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";
import toast from "react-hot-toast";
import { Plus, GraduationCap, BookOpen, Users, ChevronRight, Pencil, Trash2, X } from "lucide-react";

const API = "http://localhost:5001/api";
const COLORS = ["bg-blue-600", "bg-emerald-600", "bg-amber-600", "bg-violet-600", "bg-rose-600", "bg-cyan-600"];

// ── Modal ────────────────────────────────────────────────
function Modal({ title, onClose, children }) {
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg mx-4 p-8 relative">
        <button onClick={onClose} className="absolute top-5 right-5 text-slate-400 hover:text-slate-700">
          <X size={20} />
        </button>
        <h2 className="text-xl font-black text-slate-800 mb-6">{title}</h2>
        {children}
      </div>
    </div>
  );
}

// ── Course Form ──────────────────────────────────────────
function CourseForm({ initial, onSave, onClose }) {
  const [form, setForm] = useState(initial || { name: "", type: "", description: "" });
  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    await onSave(form);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Course Name</label>
        <input required value={form.name} onChange={(e) => set("name", e.target.value)}
          className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
      </div>
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Type</label>
        <select required value={form.type} onChange={(e) => set("type", e.target.value)}
          className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500">
          <option value="">Select type</option>
          {["JEE", "NEET", "Foundation", "Board", "CET","Crash","5th","6th","7th","8th","9th","10th","Other"].map((t) => <option key={t}>{t}</option>)}
        </select>
      </div>
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Description</label>
        <textarea value={form.description} onChange={(e) => set("description", e.target.value)} rows={3}
          className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
      </div>
      <div className="flex gap-3 pt-2">
        <button type="button" onClick={onClose} className="flex-1 py-2.5 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50">Cancel</button>
        <button type="submit" className="flex-1 py-2.5 bg-blue-900 text-white rounded-xl text-sm font-bold hover:bg-blue-800">Save</button>
      </div>
    </form>
  );
}

// ── Batch Form ───────────────────────────────────────────
function BatchForm({ courses, faculties, students, initial, onSave, onClose }) {
  const [form, setForm] = useState(
    initial
      ? { ...initial, course: initial.course?._id || initial.course, faculty: initial.faculty?._id || initial.faculty, students: initial.students?.map((s) => s._id || s) || [] }
      : { name: "", course: "", faculty: "", students: [], progress: 0 }
  );
  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const toggleStudent = (id) =>
    setForm((f) => ({
      ...f,
      students: f.students.includes(id) ? f.students.filter((s) => s !== id) : [...f.students, id],
    }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    await onSave(form);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4 max-h-[70vh] overflow-y-auto pr-1">
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Batch Name</label>
        <input required value={form.name} onChange={(e) => set("name", e.target.value)}
          className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500" />
      </div>
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Course</label>
        <select required value={form.course} onChange={(e) => set("course", e.target.value)}
          className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500">
          <option value="">{courses.length ? "Select course" : "No courses available"}</option>
          {courses.map((c) => <option key={c._id} value={c._id}>{c.name}</option>)}
        </select>
      </div>
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Faculty</label>
        <select required value={form.faculty} onChange={(e) => set("faculty", e.target.value)}
          className="mt-1 w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500">
          <option value="">{faculties.length ? "Select faculty" : "No faculty available"}</option>
          {faculties.map((f) => <option key={f._id} value={f._id}>{f.name}{f.email ? ` (${f.email})` : ""}</option>)}
        </select>
      </div>
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Progress ({form.progress}%)</label>
        <input type="range" min={0} max={100} value={form.progress} onChange={(e) => set("progress", Number(e.target.value))}
          className="mt-1 w-full accent-blue-600" />
      </div>
      <div>
        <label className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-2 block">Add Students</label>
        <div className="border border-slate-200 rounded-xl max-h-40 overflow-y-auto divide-y divide-slate-50">
          {students.length === 0 && <p className="text-xs text-slate-400 p-3">No students found</p>}
          {students.map((s) => (
            <label key={s._id} className="flex items-center gap-3 px-4 py-2 hover:bg-slate-50 cursor-pointer">
              <input type="checkbox" checked={form.students.includes(s._id)} onChange={() => toggleStudent(s._id)} className="accent-blue-600" />
              <span className="text-sm text-slate-700">{s.name} <span className="text-slate-400 text-xs">({s.rollNo})</span></span>
            </label>
          ))}
        </div>
      </div>
      <div className="flex gap-3 pt-2">
        <button type="button" onClick={onClose} className="flex-1 py-2.5 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50">Cancel</button>
        <button type="submit" className="flex-1 py-2.5 bg-blue-900 text-white rounded-xl text-sm font-bold hover:bg-blue-800">Save</button>
      </div>
    </form>
  );
}

// ── Roster Modal ─────────────────────────────────────────
function RosterModal({ batch, onClose }) {
  const [students, setStudents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get(`${API}/courses/batches/${batch._id}/roster`)
      .then((r) => setStudents(r.data))
      .catch(() => toast.error("Failed to load roster"))
      .finally(() => setLoading(false));
  }, [batch._id]);

  return (
    <Modal title={`Roster — ${batch.name}`} onClose={onClose}>
      {loading ? (
        <p className="text-sm text-slate-400 text-center py-6">Loading...</p>
      ) : students.length === 0 ? (
        <p className="text-sm text-slate-400 text-center py-6">No students in this batch.</p>
      ) : (
        <div className="overflow-x-auto rounded-xl border border-slate-100">
          <table className="w-full text-sm">
            <thead className="bg-slate-50 text-xs font-black text-slate-500 uppercase tracking-widest">
              <tr>
                <th className="px-4 py-3 text-left">Name</th>
                <th className="px-4 py-3 text-left">Roll No</th>
                <th className="px-4 py-3 text-left">Email</th>
                <th className="px-4 py-3 text-left">Fees</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {students.map((s) => (
                <tr key={s._id} className="hover:bg-slate-50">
                  <td className="px-4 py-3 font-medium text-slate-800">{s.name}</td>
                  <td className="px-4 py-3 text-slate-500">{s.rollNo}</td>
                  <td className="px-4 py-3 text-slate-500">{s.email}</td>
                  <td className="px-4 py-3">
                    <span className={`px-2 py-0.5 rounded-full text-[10px] font-black uppercase ${s.feesStatus === "paid" ? "bg-emerald-100 text-emerald-700" : s.feesStatus === "partial" ? "bg-amber-100 text-amber-700" : "bg-red-100 text-red-600"}`}>
                      {s.feesStatus}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </Modal>
  );
}

// ── Main Page ────────────────────────────────────────────
const AdminCourses = () => {
  const navigate = useNavigate();
  const [courses, setCourses] = useState([]);
  const [batches, setBatches] = useState([]);
  const [faculties, setFaculties] = useState([]);
  const [allStudents, setAllStudents] = useState([]);
  const [loading, setLoading] = useState(true);

  const [courseModal, setCourseModal] = useState(null); // null | "create" | course obj
  const [batchModal, setBatchModal] = useState(null);   // null | "create" | batch obj
  const [rosterBatch, setRosterBatch] = useState(null);

  const fetchAll = async () => {
    const [coursesRes, batchesRes, facultiesRes, studentsRes] = await Promise.allSettled([
      axios.get(`${API}/courses`),
      axios.get(`${API}/courses/batches`),
      axios.get(`${API}/faculty`),
      axios.get(`${API}/courses/students/all`),
    ]);

    if (coursesRes.status === "fulfilled") {
      setCourses(coursesRes.value.data);
    } else {
      toast.error(coursesRes.reason.response?.data?.message || "Failed to load courses");
    }

    if (batchesRes.status === "fulfilled") {
      setBatches(batchesRes.value.data);
    } else {
      toast.error(batchesRes.reason.response?.data?.message || "Failed to load batches");
    }

    if (facultiesRes.status === "fulfilled") {
      setFaculties(facultiesRes.value.data);
    } else {
      toast.error(facultiesRes.reason.response?.data?.message || "Failed to load faculty");
    }

    if (studentsRes.status === "fulfilled") {
      setAllStudents(studentsRes.value.data);
    } else {
      toast.error(studentsRes.reason.response?.data?.message || "Failed to load students");
    }

    setLoading(false);
  };

  useEffect(() => { fetchAll(); }, []);

  const openCreateBatch = async () => {
    try {
      const [coursesRes, facultiesRes, studentsRes] = await Promise.all([
        axios.get(`${API}/courses`),
        axios.get(`${API}/faculty`),
        axios.get(`${API}/courses/students/all`),
      ]);

      setCourses(coursesRes.data);
      setFaculties(facultiesRes.data);
      setAllStudents(studentsRes.data);

      if (coursesRes.data.length === 0) {
        toast.error("Create a course before creating a batch");
        return;
      }

      if (facultiesRes.data.length === 0) {
        toast.error("Add a faculty profile before creating a batch");
        return;
      }

      setBatchModal("create");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to load batch form data");
    }
  };

  const openEditBatch = async (batch) => {
    try {
      const [coursesRes, facultiesRes, studentsRes] = await Promise.all([
        axios.get(`${API}/courses`),
        axios.get(`${API}/faculty`),
        axios.get(`${API}/courses/students/all`),
      ]);

      setCourses(coursesRes.data);
      setFaculties(facultiesRes.data);
      setAllStudents(studentsRes.data);
      setBatchModal(batch);
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to load batch form data");
    }
  };

  // Course CRUD
  const saveCourse = async (form) => {
    try {
      if (courseModal?._id) {
        const { data } = await axios.put(`${API}/courses/${courseModal._id}`, form);
        setCourses((prev) => prev.map((c) => c._id === data._id ? { ...c, ...data } : c));
        toast.success("Course updated");
      } else {
        const { data } = await axios.post(`${API}/courses`, form);
        setCourses((prev) => [data, ...prev]);
        toast.success("Course created");
      }
      setCourseModal(null);
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to save course");
    }
  };

  const deleteCourse = async (id) => {
    if (!confirm("Delete this course and all its batches?")) return;
    try {
      await axios.delete(`${API}/courses/${id}`);
      setCourses((prev) => prev.filter((c) => c._id !== id));
      setBatches((prev) => prev.filter((b) => (b.course?._id || b.course) !== id));
      toast.success("Course deleted");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to delete course");
    }
  };

  // Batch CRUD
  const saveBatch = async (form) => {
    if (!form.course) return toast.error("Please select a course");
    if (!form.faculty) return toast.error("Please select a faculty");

    try {
      if (batchModal?._id) {
        const { data } = await axios.put(`${API}/courses/batches/${batchModal._id}`, form);
        setBatches((prev) => prev.map((b) => b._id === data._id ? data : b));
        toast.success("Batch updated");
      } else {
        const { data } = await axios.post(`${API}/courses/batches`, form);
        setBatches((prev) => [data, ...prev]);
        toast.success("Batch created");
      }
      setBatchModal(null);
      fetchAll(); // refresh course counts
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to save batch");
    }
  };

  const deleteBatch = async (id) => {
    if (!confirm("Delete this batch?")) return;
    try {
      await axios.delete(`${API}/courses/batches/${id}`);
      setBatches((prev) => prev.filter((b) => b._id !== id));
      toast.success("Batch deleted");
      fetchAll();
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to delete batch");
    }
  };

  if (loading) return <div className="flex items-center justify-center h-64 text-slate-400 font-medium">Loading...</div>;

  return (
    <div className="space-y-10 animate-fade-in">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Courses & Batches</h1>
          <p className="text-slate-500 mt-1 font-medium">Define your academic structure and class groupings.</p>
        </div>
        <div className="flex gap-3">
          <button onClick={openCreateBatch}
            className="flex items-center gap-2 px-6 py-3 bg-white border border-slate-200 text-slate-800 font-bold rounded-2xl hover:bg-slate-50 transition shadow-sm">
            <Plus size={18} /> Create Batch
          </button>
          <button onClick={() => setCourseModal("create")}
            className="flex items-center gap-2 px-6 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20">
            <Plus size={18} /> New Course
          </button>
        </div>
      </header>

      {/* Course Cards */}
      {courses.length === 0 ? (
        <div className="text-center py-20 text-slate-400 font-medium">No courses yet. Create your first course!</div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {courses.map((course, i) => {
            const color = COLORS[i % COLORS.length];
            return (
              <div key={course._id} className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden group hover:shadow-xl hover:shadow-blue-900/5 transition-all duration-500 flex flex-col">
                <div className={`h-3 ${color}`} />
                <div className="p-8 flex-1">
                  <div className="flex justify-between items-start mb-6">
                    <div className={`w-12 h-12 rounded-2xl ${color} text-white flex items-center justify-center shadow-lg`}>
                      <GraduationCap size={24} />
                    </div>
                    <div className="flex items-center gap-2">
                      <span className="bg-slate-100 text-slate-500 text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full">
                        {course.type}
                      </span>
                      <button onClick={() => setCourseModal(course)} className="p-1.5 rounded-lg hover:bg-slate-100 text-slate-400 hover:text-blue-600 transition">
                        <Pencil size={14} />
                      </button>
                      <button onClick={() => deleteCourse(course._id)} className="p-1.5 rounded-lg hover:bg-red-50 text-slate-400 hover:text-red-500 transition">
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>
                  <h2 className="text-2xl font-black text-slate-800 mb-2">{course.name}</h2>
                  <p className="text-slate-400 text-sm font-medium mb-8">{course.description || "No description provided."}</p>
                  <div className="grid grid-cols-2 gap-4 pt-6 border-t border-slate-50">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400">
                        <BookOpen size={16} />
                      </div>
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase">Batches</p>
                        <p className="text-sm font-bold text-slate-700">{course.batchCount}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-lg bg-slate-50 flex items-center justify-center text-slate-400">
                        <Users size={16} />
                      </div>
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase">Students</p>
                        <p className="text-sm font-bold text-slate-700">{course.studentCount}</p>
                      </div>
                    </div>
                  </div>
                </div>
                <button onClick={() => navigate(`/admin/courses/${course._id}`)}
                  className="w-full py-5 bg-slate-50 text-slate-600 font-bold text-sm uppercase tracking-widest group-hover:bg-blue-900 group-hover:text-white transition-all flex items-center justify-center gap-2">
                  Manage Course <ChevronRight size={16} />
                </button>
              </div>
            );
          })}
        </div>
      )}

      {/* Live Batch Status */}
      <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
        <h3 className="text-xl font-bold text-slate-800 mb-6">Live Batches Status</h3>
        {batches.length === 0 ? (
          <p className="text-slate-400 text-sm text-center py-8">No batches created yet.</p>
        ) : (
          <div className="space-y-4">
            {batches.map((batch, i) => {
              const fill = COLORS[i % COLORS.length];
              return (
                <div key={batch._id} className="p-6 bg-slate-50/50 border border-slate-100 rounded-[1.5rem] flex flex-col md:flex-row md:items-center justify-between gap-6">
                  <div className="w-48 flex-shrink-0">
                    <p className="text-lg font-black text-slate-800">{batch.name}</p>
                    <p className="text-xs font-bold text-slate-400">{batch.faculty?.name || "—"}</p>
                    <p className="text-[10px] text-slate-400">{batch.course?.name || "—"}</p>
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-center mb-2">
                      <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">Syllabus Progress</p>
                      <p className="text-xs font-black text-slate-800">{batch.progress}%</p>
                    </div>
                    <div className="w-full h-2 bg-slate-200 rounded-full overflow-hidden">
                      <div className={`h-full ${fill} rounded-full transition-all duration-1000`} style={{ width: `${batch.progress}%` }} />
                    </div>
                  </div>
                  <div className="flex gap-2 flex-shrink-0">
                    <button onClick={() => setRosterBatch(batch)}
                      className="px-5 py-2.5 bg-white border border-slate-200 text-slate-700 font-bold rounded-xl text-xs hover:bg-slate-100 transition shadow-sm">
                      View Roster
                    </button>
                    <button onClick={() => openEditBatch(batch)}
                      className="p-2.5 bg-white border border-slate-200 text-slate-500 rounded-xl hover:bg-slate-100 transition shadow-sm">
                      <Pencil size={14} />
                    </button>
                    <button onClick={() => deleteBatch(batch._id)}
                      className="p-2.5 bg-white border border-red-100 text-red-400 rounded-xl hover:bg-red-50 transition shadow-sm">
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Modals */}
      {courseModal && (
        <Modal title={courseModal === "create" ? "New Course" : "Edit Course"} onClose={() => setCourseModal(null)}>
          <CourseForm initial={courseModal !== "create" ? courseModal : null} onSave={saveCourse} onClose={() => setCourseModal(null)} />
        </Modal>
      )}

      {batchModal && (
        <Modal title={batchModal === "create" ? "Create Batch" : "Edit Batch"} onClose={() => setBatchModal(null)}>
          <BatchForm
            courses={courses}
            faculties={faculties}
            students={allStudents}
            initial={batchModal !== "create" ? batchModal : null}
            onSave={saveBatch}
            onClose={() => setBatchModal(null)}
          />
        </Modal>
      )}

      {rosterBatch && <RosterModal batch={rosterBatch} onClose={() => setRosterBatch(null)} />}
    </div>
  );
};

export default AdminCourses;

