                <Tooltip />
                <Bar dataKey="rate" radius={[10, 10, 10, 10]} barSize={32}>
                  {(stats.attendanceByDay || []).map((entry, index) => <Cell key={`cell-${index}`} fill={entry.rate < 85 ? "#f59e0b" : "#1e3a8a"} />)}
