import { useState, useEffect } from "react";
import axios from "../../utils/axiosInstance";
import { UserPlus, Search, Clock } from "lucide-react";
import toast from "react-hot-toast";

// Sub-components
import FacultyTable from "../../components/admin/faculty/FacultyTable";
import FacultyFormModal from "../../components/admin/faculty/FacultyFormModal";
import RecruitmentHub from "../../components/admin/faculty/RecruitmentHub";

const AdminFaculty = () => {
  const [faculty, setFaculty] = useState([]);
  const [filteredFaculty, setFilteredFaculty] = useState([]);
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);

  const [searchTerm, setSearchTerm] = useState("");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFaculty, setEditingFaculty] = useState(null);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [facultyRes, appRes] = await Promise.all([
        axios.get("/faculty"),
        axios.get("/faculty/applications")
      ]);
      setFaculty(facultyRes.data);
      setFilteredFaculty(facultyRes.data);
      setApplications(appRes.data);
    } catch (error) {
      toast.error("Failed to fetch faculty data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  // Search logic
  useEffect(() => {
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      const filtered = faculty.filter(f => 
        f.name.toLowerCase().includes(term) || 
        f.subject.toLowerCase().includes(term)
      );
      setFilteredFaculty(filtered);
    } else {
      setFilteredFaculty(faculty);
    }
  }, [searchTerm, faculty]);

  const handleEdit = (member) => {
    setEditingFaculty(member);
    setIsModalOpen(true);
  };

  const handleAddNew = () => {
    setEditingFaculty(null);
    setIsModalOpen(true);
  };

  return (
    <div className="space-y-10 animate-fade-in pb-20">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Faculty Management</h1>
          <p className="text-slate-500 mt-1 font-medium">Manage educators, assignments, and recruitment.</p>
        </div>
        <div className="flex gap-4">
          <div className="relative hidden md:block">
            <Search size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by name or subject..." 
              className="pl-12 pr-6 py-3 border border-slate-200 rounded-2xl outline-none focus:border-indigo-600 transition-all font-medium text-sm w-64 bg-white shadow-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button 
            onClick={handleAddNew}
            className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 transition shadow-xl shadow-indigo-600/20"
          >
            <UserPlus size={20} /> Onboard New Faculty
          </button>
        </div>
      </header>

      {/* Mobile Search */}
      <div className="md:hidden relative">
        <Search size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
        <input 
          type="text" 
          placeholder="Search faculty..." 
          className="w-full pl-12 pr-6 py-4 border border-slate-200 rounded-2xl outline-none focus:border-indigo-600 transition-all font-medium bg-white shadow-sm"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-[2fr_1fr] gap-8">
        {/* Faculty List Section */}
        {loading ? (
          <div className="flex items-center justify-center py-20 bg-white rounded-[2.5rem] border border-slate-100 shadow-sm">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : (
          <div className="space-y-6">
            <FacultyTable 
              faculty={filteredFaculty} 
              onEdit={handleEdit} 
              onDeleteSuccess={fetchData} 
            />

            {/* Teaching Hours Summary Widget */}
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                <Clock size={20} className="text-amber-500" /> Monthly Teaching Summary
              </h3>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                <div className="p-4 bg-indigo-50 rounded-2xl border border-indigo-100">
                  <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-1">Total Lectures</p>
                  <p className="text-2xl font-black text-indigo-900">142</p>
                </div>
                <div className="p-4 bg-emerald-50 rounded-2xl border border-emerald-100">
                  <p className="text-[10px] font-black text-emerald-400 uppercase tracking-widest mb-1">Total Hours</p>
                  <p className="text-2xl font-black text-emerald-900">284.5</p>
                </div>
                <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100">
                  <p className="text-[10px] font-black text-amber-400 uppercase tracking-widest mb-1">Active Batches</p>
                  <p className="text-2xl font-black text-amber-900">12</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Recruitment Section */}
        <RecruitmentHub 
          applications={applications} 
          onActionSuccess={fetchData} 
        />
      </div>

      {/* Form Modal */}
      <FacultyFormModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        faculty={editingFaculty} 
        onSaveSuccess={fetchData} 
      />
    </div>
  );
};

export default AdminFaculty;

