import { useEffect, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Wallet, Search, History } from "lucide-react";

const API = "http://localhost:5001/api";

const currency = (amount) =>
  new Intl.NumberFormat("en-IN", { style: "currency", currency: "INR", maximumFractionDigits: 0 }).format(amount || 0);

const AdminFees = () => {
  const [payments, setPayments] = useState([]);
  const [summary, setSummary] = useState({ totalCollected: 0, totalPending: 0, totalPartial: 0 });
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get(`${API}/payments`)
      .then(({ data }) => {
        setPayments(data.payments || []);
        setSummary(data.summary || summary);
      })
      .catch((error) => toast.error(error.response?.data?.message || "Failed to load payments"))
      .finally(() => setLoading(false));
  }, []);

  const filtered = payments.filter((payment) =>
    (payment.student?.name || payment.studentName || "").toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-10 animate-fade-in">
      <header>
        <h1 className="text-3xl font-black text-slate-800 tracking-tight">Fees & Financials</h1>
        <p className="text-slate-500 mt-1 font-medium">Live payment records from MongoDB.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="bg-emerald-600 p-8 rounded-[2rem] shadow-xl text-white">
          <p className="text-xs font-black text-emerald-100 uppercase tracking-widest mb-2">Total Collected</p>
          <p className="text-3xl font-black">{currency(summary.totalCollected)}</p>
        </div>
        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm">
          <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Partial Payments</p>
          <p className="text-3xl font-black text-amber-500">{currency(summary.totalPartial)}</p>
        </div>
        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm">
          <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Pending Payments</p>
          <p className="text-3xl font-black text-red-500">{currency(summary.totalPending)}</p>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4 bg-slate-50/30">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center shadow-sm">
              <History size={20} />
            </div>
            <h2 className="text-xl font-bold text-slate-800">Transaction History</h2>
          </div>
          <div className="relative w-full md:w-64">
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              type="text"
              placeholder="Search student name..."
              className="w-full pl-12 pr-4 py-3 rounded-2xl border border-slate-200 outline-none focus:border-blue-900 font-medium text-sm"
            />
          </div>
        </div>

        {loading ? (
          <div className="text-center py-16 text-slate-400">Loading...</div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-16 text-slate-400">No payment records found.</div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-slate-50/50 border-b border-slate-100">
                <tr>
                  <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">Student</th>
                  <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">Amount</th>
                  <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">Date</th>
                  <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">Method</th>
                  <th className="px-6 py-4 text-xs font-black text-slate-400 uppercase tracking-widest">Status</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filtered.map((payment) => (
                  <tr key={payment._id} className="hover:bg-slate-50/50 transition">
                    <td className="px-6 py-4 font-bold text-slate-800">{payment.student?.name || payment.studentName || "Unknown"}</td>
                    <td className="px-6 py-4 font-black text-slate-700">{currency(payment.amount)}</td>
                    <td className="px-6 py-4 text-sm font-bold text-slate-400">{new Date(payment.date).toLocaleDateString("en-IN")}</td>
