import { useEffect, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Timer, Search, History, CheckCircle2, RefreshCw } from "lucide-react";

const API = "http://localhost:5001/api";

const fmt = (s) => {
  const h = Math.floor(s / 3600).toString().padStart(2, "0");
  const m = Math.floor((s % 3600) / 60).toString().padStart(2, "0");
  const sec = (s % 60).toString().padStart(2, "0");
  return `${h}:${m}:${sec}`;
};

const AdminHours = () => {
  const [logs, setLogs] = useState([]);
  const [summary, setSummary] = useState([]);
  const [totalSeconds, setTotalSeconds] = useState(0);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [logsRes, summaryRes] = await Promise.all([
        axios.get(`${API}/timetable/logs?limit=100`),
        axios.get(`${API}/timetable/faculty-summary`),
      ]);
      setLogs(logsRes.data.logs);
      setTotalSeconds(logsRes.data.totalSeconds);
      setSummary(summaryRes.data);
    } catch {
      toast.error("Failed to load teaching hours");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const verifyLog = async (id) => {
    try {
      const { data } = await axios.patch(`${API}/timetable/logs/${id}/verify`);
      setLogs((prev) => prev.map((l) => l._id === id ? { ...l, status: data.status } : l));
      toast.success("Log verified");
    } catch {
      toast.error("Failed to verify log");
    }
  };

  const filtered = logs.filter((l) =>
    (l.faculty?.name || "").toLowerCase().includes(search.toLowerCase()) ||
    (l.batch?.name || "").toLowerCase().includes(search.toLowerCase()) ||
    (l.subject || "").toLowerCase().includes(search.toLowerCase())
  );

  const totalHours = (totalSeconds / 3600).toFixed(1);

  return (
    <div className="space-y-10 animate-fade-in">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Teaching Hours Tracking</h1>
          <p className="text-slate-500 mt-1 font-medium">Monitor faculty lecture logs, durations, and session history.</p>
        </div>
        <div className="flex gap-3">
          <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-amber-50 text-amber-600 flex items-center justify-center">
              <Timer size={20} />
            </div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Logged</p>
              <p className="text-lg font-black text-slate-800">{loading ? "..." : `${totalHours} hrs`}</p>
            </div>
          </div>
          <button onClick={fetchData} disabled={loading} className="p-4 bg-white rounded-2xl border border-slate-100 shadow-sm hover:bg-slate-50 transition text-slate-500">
            <RefreshCw size={18} className={loading ? "animate-spin" : ""} />
          </button>
        </div>
      </header>

      {/* Faculty Summary Cards */}
      {summary.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {summary.slice(0, 4).map((s) => (
            <div key={s.faculty?._id} className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
              <div className="w-9 h-9 rounded-xl bg-blue-900 text-white flex items-center justify-center font-black text-sm mb-3">
                {s.faculty?.name?.charAt(0) || "?"}
              </div>
              <p className="font-bold text-slate-800 text-sm truncate">{s.faculty?.name || "Unknown"}</p>
              <p className="text-xs text-slate-400 mt-0.5">{s.faculty?.subject}</p>
              <p className="text-xl font-black text-blue-900 mt-2">{s.totalHours}h</p>
              <p className="text-[10px] text-slate-400">{s.sessionCount} sessions</p>
            </div>
          ))}
        </div>
      )}

      {/* Logs Table */}
      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6 bg-slate-50/30">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center shadow-sm">
              <History size={20} />
            </div>
            <h2 className="text-xl font-bold text-slate-800">Session History</h2>
          </div>
          <div className="relative w-full md:w-64">
            <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
            <input
              type="text"
              placeholder="Filter by faculty, batch, subject..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-12 pr-4 py-3 rounded-2xl border border-slate-200 outline-none focus:border-blue-900 transition-all font-medium text-sm"
            />
          </div>
        </div>

        {loading ? (
          <div className="flex items-center justify-center py-20">
            <div className="animate-spin w-8 h-8 border-4 border-blue-200 border-t-blue-600 rounded-full" />
          </div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-20 text-slate-400">
            <History size={32} className="mx-auto mb-3 opacity-30" />
            <p className="text-sm font-medium">No teaching logs yet.</p>
            <p className="text-xs mt-1">Faculty must start and end a session from their Teaching Hours page.</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 border-b border-slate-100">
                  {["Faculty", "Batch", "Subject", "Date", "Duration", "Status"].map((h) => (
                    <th key={h} className="px-8 py-5 text-xs font-black text-slate-400 uppercase tracking-widest">{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filtered.map((log) => (
                  <tr key={log._id} className="hover:bg-slate-50/50 transition">
                    <td className="px-8 py-5">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-lg bg-blue-900 text-white flex items-center justify-center font-bold text-xs flex-shrink-0">
                          {log.faculty?.name?.charAt(0) || "?"}
                        </div>
                        <p className="font-bold text-slate-800">{log.faculty?.name || "Unknown"}</p>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-sm font-bold text-blue-900">{log.batch?.name || "—"}</td>
                    <td className="px-8 py-5 text-sm font-bold text-slate-600">{log.subject}</td>
                    <td className="px-8 py-5 text-sm text-slate-400">
                      {new Date(log.date).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                    </td>
                    <td className="px-8 py-5">
                      <span className="font-mono text-sm font-black text-slate-700 bg-slate-100 px-3 py-1 rounded-lg">
                        {fmt(log.durationSeconds)}
                      </span>
                    </td>
                    <td className="px-8 py-5">
                      {log.status === "Verified" ? (
                        <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-emerald-50 text-emerald-600 border border-emerald-100">
                          Verified
                        </span>
                      ) : (
                        <button
                          onClick={() => verifyLog(log._id)}
                          className="px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest bg-amber-50 text-amber-600 border border-amber-100 hover:bg-amber-100 transition flex items-center gap-1"
                        >
                          <CheckCircle2 size={11} /> Verify
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminHours;

