import { useState, useEffect, useRef } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { 
  BookOpen, Upload, Trash2, Download, Search, 
  FileText, File, Image, Presentation, X, Plus,
  Filter, ChevronDown
} from "lucide-react";

// API base URL is handled by axiosInstance

const getFileIcon = (type) => {
  const t = (type || "").toLowerCase();
  if (["jpg","jpeg","png","gif","webp","svg"].includes(t)) return <Image size={20} className="text-pink-400" />;
  if (["ppt","pptx"].includes(t)) return <Presentation size={20} className="text-orange-400" />;
  if (["pdf"].includes(t)) return <FileText size={20} className="text-red-400" />;
  return <File size={20} className="text-blue-400" />;
};

const formatSize = (bytes) => {
  if (!bytes) return "—";
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
};

export default function AdminMaterials() {
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [search, setSearch] = useState("");
  const [filterSubject, setFilterSubject] = useState("");
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef();
  const [form, setForm] = useState({
    title: "", description: "", subject: "", course: "", batch: "", file: null,
  });



  const fetchMaterials = async () => {
    try {
      const params = {};
      if (search) params.search = search;
      if (filterSubject) params.subject = filterSubject;
      const { data } = await axios.get("/materials", { params });
      setMaterials(data);
    } catch {
      toast.error("Failed to load materials");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchMaterials(); }, [search, filterSubject]);

  const handleFileChange = (e) => setForm({ ...form, file: e.target.files[0] });

  const handleUpload = async (e) => {
    e.preventDefault();
    if (!form.title || !form.file) return toast.error("Title and file are required.");
    setUploading(true);
    try {
      const fd = new FormData();
      fd.append("title", form.title);
      fd.append("description", form.description);
      fd.append("subject", form.subject);
      fd.append("course", form.course);
      fd.append("batch", form.batch);
      fd.append("file", form.file);
      await axios.post("/materials", fd, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });
      toast.success("Material uploaded successfully!");
      setForm({ title: "", description: "", subject: "", course: "", batch: "", file: null });
      if (fileRef.current) fileRef.current.value = "";
      setShowForm(false);
      fetchMaterials();
    } catch (err) {
      toast.error(err.response?.data?.message || "Upload failed");
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this material?")) return;
    try {
      await axios.delete(`/materials/${id}`);
      toast.success("Material deleted");
      setMaterials((prev) => prev.filter((m) => m._id !== id));
    } catch {
      toast.error("Delete failed");
    }
  };

  const subjects = [...new Set(materials.map((m) => m.subject).filter(Boolean))];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-black text-slate-800 flex items-center gap-3">
            <span className="w-10 h-10 rounded-xl bg-blue-900 text-white flex items-center justify-center">
              <BookOpen size={20} />
            </span>
            Study Materials
          </h1>
          <p className="text-slate-500 text-sm mt-1">Upload and manage study resources for students</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="flex items-center gap-2 px-5 py-2.5 bg-blue-900 text-white rounded-xl font-bold text-sm hover:bg-blue-800 transition-all shadow-lg shadow-blue-900/20"
        >
          <Plus size={18} /> Upload Material
        </button>
      </div>

      {/* Upload Form */}
      {showForm && (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 animate-in fade-in duration-200">
          <div className="flex items-center justify-between mb-5">
            <h2 className="font-bold text-slate-800 text-lg">Upload New Material</h2>
            <button onClick={() => setShowForm(false)} className="text-slate-400 hover:text-slate-600">
              <X size={20} />
            </button>
          </div>
          <form onSubmit={handleUpload} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5">Title *</label>
              <input
                type="text"
                placeholder="e.g. Chapter 5 – Algebra Notes"
                value={form.title}
                onChange={(e) => setForm({ ...form, title: e.target.value })}
                className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900"
                required
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5">Subject</label>
              <input
                type="text"
                placeholder="e.g. Mathematics"
                value={form.subject}
                onChange={(e) => setForm({ ...form, subject: e.target.value })}
                className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5">Course</label>
              <input
                type="text"
                placeholder="e.g. JEE Mains"
                value={form.course}
                onChange={(e) => setForm({ ...form, course: e.target.value })}
                className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5">Batch (optional)</label>
              <input
                type="text"
                placeholder="e.g. Batch A"
                value={form.batch}
                onChange={(e) => setForm({ ...form, batch: e.target.value })}
                className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5">Description</label>
              <input
                type="text"
                placeholder="Short description..."
                value={form.description}
                onChange={(e) => setForm({ ...form, description: e.target.value })}
                className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900"
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-1.5">File *</label>
              <div className="border-2 border-dashed border-slate-200 rounded-xl p-4 hover:border-blue-900/40 transition-colors">
                <input
                  type="file"
                  ref={fileRef}
                  onChange={handleFileChange}
                  className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-bold file:bg-blue-50 file:text-blue-900 hover:file:bg-blue-100"
                  accept=".pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx,.jpg,.jpeg,.png,.zip"
                  required
                />
                {form.file && (
                  <p className="text-xs text-slate-500 mt-2">Selected: <span className="font-semibold text-slate-700">{form.file.name}</span> ({formatSize(form.file.size)})</p>
                )}
              </div>
            </div>
            <div className="md:col-span-2 flex gap-3 justify-end">
              <button type="button" onClick={() => setShowForm(false)} className="px-4 py-2 rounded-xl border border-slate-200 text-slate-500 font-semibold text-sm hover:bg-slate-50">Cancel</button>
              <button
                type="submit"
                disabled={uploading}
                className="flex items-center gap-2 px-6 py-2 bg-blue-900 text-white rounded-xl font-bold text-sm hover:bg-blue-800 disabled:opacity-60 transition-all"
              >
                <Upload size={16} />
                {uploading ? "Uploading..." : "Upload"}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-3">
        <div className="relative flex-1">
          <Search size={16} className="absolute left-3.5 top-3 text-slate-400" />
          <input
            type="text"
            placeholder="Search by title, subject or description..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900 bg-white"
          />
        </div>
        {subjects.length > 0 && (
          <div className="relative">
            <Filter size={14} className="absolute left-3.5 top-3.5 text-slate-400" />
            <select
              value={filterSubject}
              onChange={(e) => setFilterSubject(e.target.value)}
              className="pl-10 pr-8 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-blue-900/20 focus:border-blue-900 bg-white appearance-none"
            >
              <option value="">All Subjects</option>
              {subjects.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
            <ChevronDown size={14} className="absolute right-3 top-3.5 text-slate-400 pointer-events-none" />
          </div>
        )}
      </div>

      {/* Stats Bar */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: "Total Materials", value: materials.length, color: "bg-blue-50 text-blue-900" },
          { label: "Subjects", value: subjects.length, color: "bg-purple-50 text-purple-900" },
          { label: "PDFs", value: materials.filter(m => m.fileType === "pdf").length, color: "bg-red-50 text-red-900" },
          { label: "Other Files", value: materials.filter(m => m.fileType !== "pdf").length, color: "bg-amber-50 text-amber-900" },
        ].map((stat) => (
          <div key={stat.label} className={`${stat.color} rounded-2xl p-4`}>
            <p className="text-2xl font-black">{stat.value}</p>
            <p className="text-xs font-semibold mt-1 opacity-70">{stat.label}</p>
          </div>
        ))}
      </div>

      {/* Materials Grid */}
      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {[1,2,3,4,5,6].map(i => (
            <div key={i} className="bg-white rounded-2xl border border-slate-100 p-5 animate-pulse">
              <div className="flex gap-3 mb-3">
                <div className="w-10 h-10 bg-slate-100 rounded-xl" />
                <div className="flex-1">
                  <div className="h-4 bg-slate-100 rounded w-3/4 mb-2" />
                  <div className="h-3 bg-slate-100 rounded w-1/2" />
                </div>
              </div>
              <div className="h-3 bg-slate-100 rounded w-full mt-3" />
            </div>
          ))}
        </div>
      ) : materials.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border border-slate-100">
          <BookOpen size={48} className="mx-auto text-slate-300 mb-4" />
          <p className="text-slate-500 font-semibold">No materials found</p>
          <p className="text-slate-400 text-sm mt-1">Upload your first study material above</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {materials.map((mat) => (
            <div key={mat._id} className="bg-white rounded-2xl border border-slate-100 shadow-sm hover:shadow-md transition-all duration-200 p-5 flex flex-col gap-3">
              <div className="flex items-start gap-3">
                <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center flex-shrink-0">
                  {getFileIcon(mat.fileType)}
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="font-bold text-slate-800 text-sm leading-tight truncate">{mat.title}</h3>
                  {mat.subject && <span className="inline-block text-[10px] font-bold text-blue-700 bg-blue-50 px-2 py-0.5 rounded-full mt-1">{mat.subject}</span>}
                </div>
                <span className="text-[10px] font-bold uppercase px-2 py-1 rounded-lg bg-slate-100 text-slate-500 flex-shrink-0">{mat.fileType}</span>
              </div>

              {mat.description && <p className="text-xs text-slate-500 leading-relaxed line-clamp-2">{mat.description}</p>}

              <div className="flex flex-wrap gap-2 text-[10px] text-slate-400 font-semibold">
                {mat.course && <span className="bg-slate-50 px-2 py-0.5 rounded-full">📚 {mat.course}</span>}
                {mat.batch && <span className="bg-slate-50 px-2 py-0.5 rounded-full">👥 {mat.batch}</span>}
                <span className="bg-slate-50 px-2 py-0.5 rounded-full">{formatSize(mat.fileSize)}</span>
              </div>

              <div className="flex items-center justify-between pt-2 border-t border-slate-50">
                <div>
                  <p className="text-[10px] text-slate-400">By <span className="font-semibold text-slate-600">{mat.uploaderName}</span></p>
