import { useState, useEffect, useRef } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { 
  BookOpen, Upload, Trash2, Download, Search, 
  FileText, File, Image, Presentation, X, Plus,
  Filter, ChevronDown
} from "lucide-react";

// API base URL is handled by axiosInstance

const getFileIcon = (type) => {
  const t = (type || "").toLowerCase();
  if (["jpg","jpeg","png","gif","webp","svg"].includes(t)) return <Image size={20} className="text-pink-400" />;
  if (["ppt","pptx"].includes(t)) return <Presentation size={20} className="text-orange-400" />;
  if (["pdf"].includes(t)) return <FileText size={20} className="text-red-400" />;
  return <File size={20} className="text-blue-400" />;
};

const formatSize = (bytes) => {
  if (!bytes) return "—";
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
};

export default function AdminMaterials() {
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [search, setSearch] = useState("");
  const [filterSubject, setFilterSubject] = useState("");
  const [uploading, setUploading] = useState(false);
  const fileRef = useRef();
  const [form, setForm] = useState({
    title: "", description: "", subject: "", course: "", batch: "", file: null,
  });



  const fetchMaterials = async () => {
    try {
      const params = {};
      if (search) params.search = search;
      if (filterSubject) params.subject = filterSubject;
      const { data } = await axios.get("/materials", { params });
      setMaterials(data);
    } catch {
      toast.error("Failed to load materials");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchMaterials(); }, [search, filterSubject]);

  const handleFileChange = (e) => setForm({ ...form, file: e.target.files[0] });

  const handleUpload = async (e) => {
    e.preventDefault();
    if (!form.title || !form.file) return toast.error("Title and file are required.");
    setUploading(true);
    try {
      const fd = new FormData();
      fd.append("title", form.title);
      fd.append("description", form.description);
      fd.append("subject", form.subject);
      fd.append("course", form.course);
      fd.append("batch", form.batch);
      fd.append("file", form.file);
      await axios.post("/materials", fd, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });
      toast.success("Material uploaded successfully!");
      setForm({ title: "", description: "", subject: "", course: "", batch: "", file: null });
      if (fileRef.current) fileRef.current.value = "";
      setShowForm(false);
      fetchMaterials();
    } catch (err) {
      toast.error(err.response?.data?.message || "Upload failed");
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this material?")) return;
    try {
      await axios.delete(`/materials/${id}`);
      toast.success("Material deleted");
      setMaterials((prev) => prev.filter((m) => m._id !== id));
    } catch {
      toast.error("Delete failed");
    }
  };

  const subjects = [...new Set(materials.map((m) => m.subject).filter(Boolean))];

  return (
    <div className="space-y-8">
