                  onChange={handleFileChange}
                  className="w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-bold file:bg-blue-50 file:text-blue-900 hover:file:bg-blue-100"
                  accept=".pdf,.doc,.docx,.ppt,.pptx,.xls,.xlsx,.jpg,.jpeg,.png,.zip"
                  required
                />
                {form.file && (
                  <p className="text-xs text-slate-500 mt-2">Selected: <span className="font-semibold text-slate-700">{form.file.name}</span> ({formatSize(form.file.size)})</p>
