  const [loading, setLoading] = useState(true);
  const [publishing, setPublishing] = useState(false);
  const [form, setForm] = useState({
    audience: "all",
    priority: "normal",
    title: "",
    content: "",
  });

  const set = (key, value) => setForm((prev) => ({ ...prev, [key]: value }));

  const fetchNotices = async () => {
    try {
      const { data } = await axios.get(`${API}/notices`);
      setNotices(data);
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to load notices");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchNotices();
  }, []);

  const publishNotice = async (e) => {
    e.preventDefault();
    setPublishing(true);
    try {
      const { data } = await axios.post(`${API}/notices`, form);
      setNotices((prev) => [data, ...prev]);
      setForm({ audience: "all", priority: "normal", title: "", content: "" });
      toast.success("Notice published");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to publish notice");
    } finally {
      setPublishing(false);
    }
  };

  const deleteNotice = async (id) => {
    if (!confirm("Delete this notice?")) return;
    try {
      await axios.delete(`${API}/notices/${id}`);
      setNotices((prev) => prev.filter((notice) => notice._id !== id));
      toast.success("Notice deleted");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to delete notice");
    }
  };

  return (
    <div className="space-y-10 animate-fade-in">
      <header>
        <h1 className="text-3xl font-black text-slate-800 tracking-tight">Notice Management</h1>
        <p className="text-slate-500 mt-1 font-medium">Broadcast announcements to students, faculty, or everyone.</p>
      </header>

      <div className="grid lg:grid-cols-[1.1fr_1.2fr] gap-8">
        <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm h-max">
          <h2 className="text-xl font-bold text-slate-800 mb-6 flex items-center gap-3">
            <span className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center">
              <Megaphone size={20} />
            </span>
            Compose Announcement
          </h2>

          <form onSubmit={publishNotice} className="space-y-5">
            <div>
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Target Audience</label>
              <select
                value={form.audience}
                onChange={(e) => set("audience", e.target.value)}
                className="mt-2 w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900"
              >
                <option value="all">Students & Faculty</option>
                <option value="students">Students Only</option>
                <option value="faculty">Faculty Only</option>
              </select>
            </div>

            <div>
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Priority</label>
              <select
                value={form.priority}
                onChange={(e) => set("priority", e.target.value)}
                className="mt-2 w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900"
              >
                <option value="normal">Normal</option>
                <option value="high">High</option>
              </select>
            </div>

            <div>
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Notice Title</label>
              <input
                required
                value={form.title}
                onChange={(e) => set("title", e.target.value)}
                placeholder="e.g. Diwali Vacation Announcement"
                className="mt-2 w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900"
              />
            </div>

            <div>
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Message Content</label>
              <textarea
                required
                rows="5"
                value={form.content}
                onChange={(e) => set("content", e.target.value)}
                placeholder="Type your message here..."
                className="mt-2 w-full px-4 py-3 rounded-xl border border-slate-200 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 resize-none"
              />
            </div>

            <button
              type="submit"
              disabled={publishing}
              className="w-full py-4 bg-slate-900 text-white font-black rounded-xl hover:bg-slate-800 disabled:opacity-50 transition flex justify-center items-center gap-3 uppercase tracking-widest text-xs"
            >
              <Send size={18} /> {publishing ? "Publishing..." : "Publish Notice"}
            </button>
          </form>
        </div>

        <div className="space-y-5">
          <h2 className="text-xl font-bold text-slate-800 px-1">Published Notices</h2>

          {loading ? (
            <div className="text-center py-16 text-slate-400 bg-white rounded-2xl border border-slate-100">Loading...</div>
          ) : notices.length === 0 ? (
            <div className="text-center py-16 text-slate-400 bg-white rounded-2xl border border-slate-100">No notices published yet.</div>
          ) : (
            notices.map((notice) => (
              <div key={notice._id} className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm relative overflow-hidden group">
                {notice.priority === "high" && <div className="absolute top-0 left-0 w-1.5 h-full bg-red-500" />}
                <div className="flex justify-between gap-4">
                  <div>
                    <h3 className="text-lg font-bold text-slate-800">{notice.title}</h3>
                    <div className="flex flex-wrap items-center gap-2 mt-2">
                      <span className="text-[10px] font-black uppercase tracking-widest text-blue-600 bg-blue-50 px-2 py-0.5 rounded-md">
                        {audienceLabels[notice.audience] || notice.audience}
                      </span>
                      {notice.priority === "high" && (
                        <span className="text-[10px] font-black uppercase tracking-widest text-red-600 bg-red-50 px-2 py-0.5 rounded-md">High</span>
                      )}
                      <span className="text-xs font-bold text-slate-400">{formatDate(notice.createdAt)}</span>
                    </div>
                  </div>
                  <button onClick={() => deleteNotice(notice._id)} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition">
                    <Trash2 size={16} />
                  </button>
                </div>
                <p className="text-slate-500 text-sm font-medium leading-relaxed mt-4">{notice.content}</p>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default AdminNotices;

