import { useEffect, useState } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import axios from "../../utils/axiosInstance";
import { CheckCircle, XCircle, User, Loader2, ArrowLeft } from "lucide-react";
import toast from "react-hot-toast";

const AdminQRCheckin = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const studentId = searchParams.get("studentId");

  const [status, setStatus] = useState("loading"); // loading, success, error
  const [message, setMessage] = useState("Marking attendance...");
  const [studentInfo, setStudentInfo] = useState(null);

  useEffect(() => {
    if (!studentId) {
      setStatus("error");
      setMessage("Invalid QR Code. No student ID found.");
      return;
    }

    const performCheckin = async () => {
      try {
        const { data } = await axios.post("/attendance/qr-checkin", { studentId });
        if (data.success) {
          setStudentInfo(data.student);
          setStatus("success");
          setMessage("Attendance Marked Successfully!");
          toast.success(`Present: ${data.student.name}`);
        }
      } catch (error) {
        console.error("QR Checkin Error:", error);
        setStatus("error");
        setMessage(error.response?.data?.message || "Failed to mark attendance. Please try again.");
      }
    };

    performCheckin();
  }, [studentId]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 animate-fade-in">
      <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl shadow-blue-900/10 border border-slate-100 overflow-hidden text-center p-10">

        {/* State Icons */}
        <div className="mb-8 flex justify-center">
          {status === "loading" && (
            <div className="w-24 h-24 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center animate-pulse">
              <Loader2 size={48} className="animate-spin" />
            </div>
          )}
          {status === "success" && (
            <div className="w-24 h-24 bg-emerald-50 text-emerald-600 rounded-full flex items-center justify-center animate-bounce-short">
              <CheckCircle size={48} />
            </div>
          )}
          {status === "error" && (
            <div className="w-24 h-24 bg-red-50 text-red-600 rounded-full flex items-center justify-center">
              <XCircle size={48} />
            </div>
          )}
        </div>

        {/* Message */}
        <h1 className={`text-2xl font-black mb-2 ${
          status === "success" ? "text-emerald-700" : 
          status === "error" ? "text-red-700" : "text-slate-800"
        }`}>
          {message}
        </h1>

        {/* Student Card (on success) */}
        {studentInfo && status === "success" && (
          <div className="mt-8 p-6 bg-slate-50 rounded-3xl border border-slate-100 text-left">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 bg-blue-900 text-white rounded-2xl flex items-center justify-center text-2xl font-black">
                {studentInfo.name.charAt(0)}
              </div>
              <div>
                <p className="text-xl font-bold text-slate-800">{studentInfo.name}</p>
                <p className="text-sm font-bold text-blue-600 uppercase tracking-widest">{studentInfo.batch}</p>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Roll No: {studentInfo.rollNo}</p>
              </div>
            </div>
            <div className="mt-6 flex items-center gap-2 text-emerald-600 font-bold text-sm">
               <div className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></div>
               Status: Present for Today
            </div>
          </div>
        )}

        {/* Action Buttons */}
        <div className="mt-10 space-y-3">
          <button 
            onClick={() => window.location.href = '/admin/students'}
            className="w-full py-4 bg-slate-900 text-white font-bold rounded-2xl hover:bg-slate-800 transition flex items-center justify-center gap-2"
          >
            <User size={20} /> Back to Management
          </button>
          <button 
            onClick={() => navigate(-1)}
            className="w-full py-4 bg-white text-slate-500 font-bold rounded-2xl border border-slate-200 hover:bg-slate-50 transition flex items-center justify-center gap-2"
          >
            <ArrowLeft size={20} /> Go Back
          </button>
        </div>

      </div>

      <p className="mt-8 text-slate-400 text-sm font-bold tracking-widest uppercase">
        SRS Academy Digital Attendance
      </p>
    </div>
  );
};

export default AdminQRCheckin;

