import { useState, useEffect } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { 
  ClipboardList, Plus, Trash2, Edit, Play, Pause, 
  ChevronRight, BarChart2, Clock, BookOpen, X, CheckCircle2
} from "lucide-react";

export default function AdminQuizzes() {
  const [quizzes, setQuizzes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingQuiz, setEditingQuiz] = useState(null);
  const [resultsQuiz, setResultsQuiz] = useState(null);
  const [results, setResults] = useState([]);

  // Form State
  const [form, setForm] = useState({
    title: "", description: "", subject: "", duration: 30, batch: "", totalMarks: 0,
    status: "published",
    questions: [{ questionText: "", options: ["", "", "", ""], correctOption: 0, marks: 1 }]
  });

  const fetchQuizzes = async () => {
    try {
      const { data } = await axios.get("/quizzes");
      setQuizzes(data);
    } catch {
      toast.error("Failed to load quizzes");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchQuizzes(); }, []);

  const handleAddQuestion = () => {
    setForm({
      ...form,
      questions: [...form.questions, { questionText: "", options: ["", "", "", ""], correctOption: 0, marks: 1 }]
    });
  };

  const handleRemoveQuestion = (index) => {
    const newQuestions = [...form.questions];
    newQuestions.splice(index, 1);
    setForm({ ...form, questions: newQuestions });
  };

  const handleQuestionChange = (index, field, value) => {
    const newQuestions = [...form.questions];
    newQuestions[index][field] = value;
    setForm({ ...form, questions: newQuestions });
  };

  const handleOptionChange = (qIndex, oIndex, value) => {
    const newQuestions = [...form.questions];
    newQuestions[qIndex].options[oIndex] = value;
    setForm({ ...form, questions: newQuestions });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const totalMarks = form.questions.reduce((acc, q) => acc + Number(q.marks), 0);
    const finalForm = { ...form, totalMarks };

    try {
      if (editingQuiz) {
        await axios.put(`/quizzes/${editingQuiz._id}/status`, { status: form.status });
        toast.success("Quiz updated");
      } else {
        await axios.post("/quizzes", finalForm);
        toast.success("Quiz created successfully!");
      }
      setShowModal(false);
      setEditingQuiz(null);
      setForm({
        title: "", description: "", subject: "", duration: 30, batch: "", totalMarks: 0,
        status: "published",
        questions: [{ questionText: "", options: ["", "", "", ""], correctOption: 0, marks: 1 }]
      });
      fetchQuizzes();
    } catch (err) {
      toast.error("Save failed");
    }
  };

  const toggleStatus = async (quiz) => {
    const newStatus = quiz.status === "published" ? "closed" : "published";
    try {
      await axios.put(`/quizzes/${quiz._id}/status`, { status: newStatus });
      toast.success(`Quiz ${newStatus}`);
      fetchQuizzes();
    } catch {
      toast.error("Update failed");
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this quiz?")) return;
    try {
      await axios.delete(`/quizzes/${id}`);
      toast.success("Quiz deleted");
      fetchQuizzes();
    } catch {
      toast.error("Delete failed");
    }
  };

  const viewResults = async (quiz) => {
    setResultsQuiz(quiz);
    try {
      const { data } = await axios.get(`/quizzes/${quiz._id}/results`);
      setResults(data);
    } catch {
      toast.error("Failed to load results");
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <ClipboardList className="text-blue-900" size={32} />
            Quiz Management
          </h1>
          <p className="text-slate-500 mt-1 font-medium">Create and monitor online assessments for students.</p>
        </div>
        <button
          onClick={() => { setEditingQuiz(null); setShowModal(true); }}
          className="flex items-center gap-2 px-6 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20"
        >
          <Plus size={20} /> Create New Quiz
        </button>
      </header>

      {/* Quiz Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {loading ? (
          [1,2,3].map(i => <div key={i} className="h-48 bg-white rounded-[2rem] border border-slate-100 animate-pulse" />)
        ) : quizzes.map((quiz) => (
          <div key={quiz._id} className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden hover:shadow-md transition group">
            <div className="p-6">
              <div className="flex justify-between items-start mb-4">
                <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${
                  quiz.status === 'published' ? 'bg-emerald-50 text-emerald-600' : 
                  quiz.status === 'closed' ? 'bg-red-50 text-red-600' : 'bg-slate-50 text-slate-400'
                }`}>
                  {quiz.status}
                </span>
                <div className="flex gap-2">
                  <button onClick={() => toggleStatus(quiz)} className="p-2 hover:bg-slate-50 rounded-lg text-slate-400 hover:text-blue-600 transition">
                    {quiz.status === 'published' ? <Pause size={16} /> : <Play size={16} />}
                  </button>
                  <button onClick={() => handleDelete(quiz._id)} className="p-2 hover:bg-red-50 rounded-lg text-slate-400 hover:text-red-600 transition">
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
              <h3 className="text-lg font-bold text-slate-800 line-clamp-1">{quiz.title}</h3>
              <p className="text-xs text-slate-400 font-bold uppercase mt-1 tracking-widest">{quiz.subject}</p>

              <div className="grid grid-cols-2 gap-4 mt-6">
                <div className="flex items-center gap-2 text-slate-500">
                  <Clock size={14} /> <span className="text-xs font-bold">{quiz.duration} mins</span>
                </div>
                <div className="flex items-center gap-2 text-slate-500">
                  <BookOpen size={14} /> <span className="text-xs font-bold">{quiz.questions?.length} Questions</span>
                </div>
              </div>
            </div>
            <div className="px-6 py-4 bg-slate-50 flex items-center justify-between">
              <span className="text-xs font-bold text-slate-400">Target: {quiz.batch || 'All'}</span>
              <button 
                onClick={() => viewResults(quiz)}
                className="text-xs font-black text-blue-900 hover:underline flex items-center gap-1"
              >
                View Results <ChevronRight size={14} />
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Quiz Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-[2.5rem] w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
              <div>
                <h2 className="text-2xl font-black text-slate-800">Create Mock Test</h2>
                <p className="text-sm text-slate-500 font-medium">Design your MCQ exam with automated grading.</p>
              </div>
              <button onClick={() => setShowModal(false)} className="p-2 hover:bg-slate-100 rounded-full text-slate-400 transition">
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar">
              {/* Meta Info */}
              <div className="grid md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Quiz Title</label>
                  <input 
                    type="text" required
                    className="w-full px-5 py-4 rounded-2xl border-2 border-slate-50 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all"
                    placeholder="e.g. JEE Mains Mock Test 1"
