  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this quiz?")) return;
    try {
      await axios.delete(`/quizzes/${id}`);
      toast.success("Quiz deleted");
      fetchQuizzes();
    } catch {
      toast.error("Delete failed");
    }
  };

  const viewResults = async (quiz) => {
    setResultsQuiz(quiz);
    try {
