                <p className="text-sm text-blue-200">{stats.topper ? `${stats.topper.result.testName} - ${stats.topper.percentage}%` : "Publish results first"}</p>
              </div>
            </div>
          </div>
          <div className="text-white border-r border-white/10 pr-8">
            <p className="text-xs font-black text-blue-300 uppercase tracking-widest mb-2">Overall Average</p>
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 rounded-2xl bg-white/10 text-white flex items-center justify-center border border-white/20">
                <TrendingUp size={28} />
              </div>
              <div>
                <h3 className="text-xl font-bold">{stats.avg}%</h3>
                <p className="text-sm text-blue-200">Across published results</p>
              </div>
            </div>
          </div>
          <div className="text-white">
            <p className="text-xs font-black text-blue-300 uppercase tracking-widest mb-2">Tests Conducted</p>
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 rounded-2xl bg-white/10 text-white flex items-center justify-center border border-white/20">
                <BarChart3 size={28} />
              </div>
              <div>
                <h3 className="text-xl font-bold">{stats.testCount}</h3>
                <p className="text-sm text-blue-200">Result sheets</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50/30">
          <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2"><Trophy size={20} /> Recent Test Logs</h2>
        </div>
        {loading ? (
          <div className="text-center py-16 text-slate-400">Loading...</div>
        ) : results.length === 0 ? (
          <div className="text-center py-16 text-slate-400">No result records found.</div>
        ) : (
          <div className="divide-y divide-slate-50">
            {results.map((result) => {
              const percentages = result.records.map((record) => result.totalMarks ? Math.round((record.marks / result.totalMarks) * 100) : 0);
              const avg = percentages.length ? Math.round(percentages.reduce((sum, value) => sum + value, 0) / percentages.length) : 0;
              const high = percentages.length ? Math.max(...percentages) : 0;
              return (
                <div key={result._id} className="p-6 flex items-center justify-between hover:bg-slate-50/50 transition">
                  <div>
                    <h3 className="text-lg font-bold text-slate-800">{result.testName}</h3>
                    <div className="flex gap-4 mt-1">
                      <p className="text-xs font-bold text-slate-400">{result.batch?.name || "Unknown batch"}</p>
                      <p className="text-xs font-bold text-slate-400">{new Date(result.createdAt).toLocaleDateString("en-IN")}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-8">
                    <div className="text-center">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Avg Score</p>
                      <p className="text-sm font-black text-slate-700">{avg}%</p>
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Highest</p>
                      <p className="text-sm font-black text-emerald-600">{high}%</p>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminResults;

