import { useState, useEffect, useContext } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { Settings, Shield, Bell, Database, Globe, Save, Loader2, Download, User as UserIcon } from "lucide-react";
import { AuthContext } from "../../context/AuthContext";
import ChangePasswordForm from "../../components/common/ChangePasswordForm";

// API base URL is handled by axiosInstance

const AdminSettings = () => {
  const { user } = useContext(AuthContext);
  const [activeTab, setActiveTab] = useState("General Info");
  const [settings, setSettings] = useState({
    instituteName: "",
    contactEmail: "",
    timezone: "IST (GMT +5:30)",
    academicYear: "",
    notifications: {
      emailAlerts: true,
      attendanceAlerts: true,
      feeAlerts: false
    }
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const fetchSettings = async () => {
      try {
        const { data } = await axios.get("/admin/settings");
        setSettings(data);
      } catch (error) {
        console.error("Settings fetch error:", error);
        toast.error(error.response?.data?.message || error.message || "Failed to load settings");
      } finally {
        setLoading(false);
      }
    };
    if (user?.token) fetchSettings();
  }, [user]);

  const handleSave = async () => {
    setSaving(true);
    try {
      await axios.put("/admin/settings", settings);
      toast.success("Settings updated successfully");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to save settings");
    } finally {
      setSaving(false);
    }
  };

  const handleLogoUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append("logo", file);

    try {
      setSaving(true);
      const { data } = await axios.post("/admin/settings/logo", formData, {
        headers: { 
          "Content-Type": "multipart/form-data"
        }
      });
      setSettings({ ...settings, logoUrl: data.logoUrl });
      toast.success("Logo uploaded successfully");
    } catch (error) {
      toast.error("Logo upload failed");
    } finally {
      setSaving(false);
    }
  };

  const handleExport = async (type) => {
    try {
      const endpoint = type === 'students' ? 'export/students' : 'export/fees';
      const response = await axios.get(`/admin/${endpoint}`, {
        responseType: 'blob'
      });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `${type}_records.csv`);
      document.body.appendChild(link);
      link.click();
      toast.success(`${type} CSV downloaded`);
    } catch (error) {
      toast.error("Export failed");
    }
  };

  const tabs = [
    { name: "General Info", icon: <Globe size={20} /> },
    { name: "Security & Roles", icon: <Shield size={20} /> },
    { name: "Notifications", icon: <Bell size={20} /> },
    { name: "Backup & Data", icon: <Database size={20} /> },
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <Loader2 className="animate-spin text-blue-900" size={40} />
      </div>
    );
  }

  return (
    <div className="space-y-10 animate-fade-in">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">System Settings</h1>
          <p className="text-slate-500 mt-1 font-medium">Configure institute details, roles, and global system preferences.</p>
        </div>
        <button 
          onClick={handleSave}
          disabled={saving}
          className="flex items-center gap-2 px-8 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20 disabled:opacity-50"
        >
          {saving ? <Loader2 className="animate-spin" size={20} /> : <Save size={20} />}
          Save Global Config
        </button>
      </header>

      <div className="grid lg:grid-cols-[1fr_2.5fr] gap-8">
        {/* Navigation */}
        <div className="space-y-2">
          {tabs.map((item, i) => (
            <button 
              key={i} 
              onClick={() => setActiveTab(item.name)}
              className={`flex items-center gap-3 w-full px-6 py-4 rounded-2xl font-bold text-sm transition-all ${activeTab === item.name ? 'bg-white text-blue-900 shadow-sm border border-slate-100' : 'text-slate-400 hover:bg-white/50'}`}
            >
              {item.icon} {item.name}
            </button>
          ))}
        </div>

        {/* Content */}
        <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm min-h-[500px]">
          {activeTab === "General Info" && (
            <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div>
                <h2 className="text-xl font-bold text-slate-800 mb-8 border-b border-slate-50 pb-4">Institute Information</h2>
                <div className="grid md:grid-cols-2 gap-8">
                  <div className="space-y-2">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Institute Name</label>
                    <input 
                      type="text" 
                      value={settings.instituteName} 
                      onChange={(e) => setSettings({...settings, instituteName: e.target.value})}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-50 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all" 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Contact Email</label>
                    <input 
                      type="email" 
                      value={settings.contactEmail} 
                      onChange={(e) => setSettings({...settings, contactEmail: e.target.value})}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-50 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all" 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">System Timezone</label>
                    <select 
                      value={settings.timezone}
                      onChange={(e) => setSettings({...settings, timezone: e.target.value})}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-50 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all"
                    >
                      <option>IST (GMT +5:30)</option>
                      <option>UTC</option>
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Academic Year</label>
                    <input 
                      type="text" 
                      value={settings.academicYear} 
                      onChange={(e) => setSettings({...settings, academicYear: e.target.value})}
                      className="w-full px-5 py-4 rounded-2xl border-2 border-slate-50 bg-slate-50 font-bold text-slate-700 outline-none focus:border-blue-900 transition-all" 
                    />
                  </div>
                </div>
              </div>

              <div className="pt-8 border-t border-slate-100">
                <h2 className="text-xl font-bold text-slate-800 mb-6">Logo & Branding</h2>
                <div className="flex items-center gap-8 p-8 bg-slate-50 rounded-[2rem] border border-dashed border-slate-200">
                  {settings.logoUrl ? (
                    <img src={`http://localhost:5001${settings.logoUrl}`} alt="Logo" className="w-20 h-20 rounded-2xl object-cover" />
                  ) : (
                    <div className="w-20 h-20 rounded-2xl bg-blue-900 text-white flex items-center justify-center font-black text-3xl">
                      {settings.instituteName?.charAt(0) || "S"}
                    </div>
                  )}
                  <div>
                    <input type="file" id="logoInput" className="hidden" onChange={handleLogoUpload} accept="image/*" />
                    <label htmlFor="logoInput" className="px-6 py-2.5 bg-white border border-slate-200 text-slate-800 font-bold rounded-xl text-xs hover:bg-slate-100 transition shadow-sm mb-2 block cursor-pointer">
                      Upload New Logo
                    </label>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Recommended size: 512x512px (PNG/SVG)</p>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === "Security & Roles" && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <h2 className="text-xl font-bold text-slate-800 border-b border-slate-50 pb-4 px-2">Security & Identity</h2>
              <div className="space-y-8">
                <ChangePasswordForm />

                <div className="flex items-center justify-between p-8 bg-amber-50 rounded-[2rem] border border-amber-100">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-amber-600 shadow-sm border border-amber-100">
                      <Shield size={24} />
                    </div>
                    <div>
                      <h3 className="font-bold text-amber-900 text-lg">Two-Factor Authentication</h3>
                      <p className="text-sm text-amber-700">Add an extra layer of security to your admin account.</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => setSettings({...settings, twoFactorAuth: !settings.twoFactorAuth})}
                    className={`w-12 h-6 rounded-full relative transition-colors duration-200 focus:outline-none ${settings.twoFactorAuth ? 'bg-amber-600' : 'bg-slate-300'}`}
                  >
                    <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-transform duration-200 ${settings.twoFactorAuth ? 'translate-x-7' : 'translate-x-1'}`}></div>
                  </button>
                </div>
              </div>
            </div>
          )}

          {activeTab === "Notifications" && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <h2 className="text-xl font-bold text-slate-800 border-b border-slate-50 pb-4">Notification Preferences</h2>
              <div className="divide-y divide-slate-100">
                {[
                  { key: "emailAlerts", title: "Email Notifications", desc: "Receive daily reports and urgent alerts via email." },
                  { key: "attendanceAlerts", title: "Attendance Alerts", desc: "Notify parents automatically when a student is absent." },
                  { key: "feeAlerts", title: "Fee Reminders", desc: "Send automated reminders for upcoming fee deadlines." },
                ].map((item) => (
                  <div key={item.key} className="py-6 flex items-center justify-between">
                    <div>
                      <h3 className="font-bold text-slate-800">{item.title}</h3>
                      <p className="text-sm text-slate-500">{item.desc}</p>
                    </div>
                    <button 
                      onClick={() => setSettings({
                        ...settings, 
                        notifications: { ...settings.notifications, [item.key]: !settings.notifications[item.key] }
                      })}
                      className={`w-14 h-7 rounded-full relative transition-colors duration-200 focus:outline-none ${settings.notifications[item.key] ? 'bg-emerald-500' : 'bg-slate-200'}`}
                    >
                      <div className={`absolute top-1 w-5 h-5 bg-white rounded-full transition-transform duration-200 ${settings.notifications[item.key] ? 'translate-x-8' : 'translate-x-1'}`}></div>
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === "Backup & Data" && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 text-center py-10">
              <div className="w-20 h-20 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6">
                <Database size={40} />
              </div>
              <h2 className="text-2xl font-black text-slate-800">Database & Backups</h2>
              <p className="text-slate-500 max-w-sm mx-auto">Export your entire institute data in CSV format for offline storage.</p>
              <div className="flex flex-col gap-3 max-w-xs mx-auto pt-6">
                <button onClick={() => handleExport('students')} className="w-full py-4 bg-white border-2 border-slate-100 text-slate-800 font-bold rounded-2xl hover:border-blue-900 transition flex items-center justify-center gap-2">
                  <Download size={18} /> Download Student CSV
                </button>
                <button onClick={() => handleExport('fees')} className="w-full py-4 bg-white border-2 border-slate-100 text-slate-800 font-bold rounded-2xl hover:border-blue-900 transition flex items-center justify-center gap-2">
                  <Download size={18} /> Download Fee Records
                </button>
                <button onClick={() => toast.success("System backup initiated")} className="w-full py-4 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-lg shadow-blue-900/20">Generate Full System Backup</button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};


export default AdminSettings;

