import { useState, useEffect } from "react";
import axios from "../../utils/axiosInstance";
import { Plus, FileText } from "lucide-react";
import toast from "react-hot-toast";
import { useRef } from "react";
import jsPDF from "jspdf";
import html2canvas from "html2canvas";
import ReportTemplate from "../../components/common/ReportTemplate";
import IDCardTemplate from "../../components/admin/students/IDCardTemplate";
import { IdCard } from "lucide-react";

// Sub-components
import SearchBar from "../../components/admin/students/SearchBar";
import FilterDropdown from "../../components/admin/students/FilterDropdown";
import CSVUploadButton from "../../components/admin/students/CSVUploadButton";
import StudentTable from "../../components/admin/students/StudentTable";
import StudentFormModal from "../../components/admin/students/StudentFormModal";

const AdminStudents = () => {
  const [students, setStudents] = useState([]);
  const [filteredStudents, setFilteredStudents] = useState([]);
  const [loading, setLoading] = useState(true);

  // States for search and filter
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedBatch, setSelectedBatch] = useState("");
  const [batches, setBatches] = useState([]);

  // States for Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingStudent, setEditingStudent] = useState(null);

  // States for Report Generation
  const [reportData, setReportData] = useState(null);
  const [activeStudent, setActiveStudent] = useState(null);
  const [downloading, setDownloading] = useState(false);
  const reportRef = useRef();
  // States for ID Card Generation
  const [activeIDStudent, setActiveIDStudent] = useState(null);
  const idCardRef = useRef();

  const fetchStudents = async () => {
    try {
      setLoading(true);
      const { data } = await axios.get("/students");
      setStudents(data);
      setFilteredStudents(data);

      // Extract unique batches for the filter
      const uniqueBatches = [...new Set(data.map(s => s.batch))];
      setBatches(uniqueBatches);
    } catch (error) {
      toast.error("Failed to fetch students");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStudents();
  }, []);

  // Handle Search and Filter logic
  useEffect(() => {
    let result = students;

    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      result = result.filter(s => 
        s.name.toLowerCase().includes(term) || 
        s.rollNo.toLowerCase().includes(term) || 
        s.batch.toLowerCase().includes(term)
      );
    }

    if (selectedBatch) {
      result = result.filter(s => s.batch === selectedBatch);
    }

    setFilteredStudents(result);
  }, [searchTerm, selectedBatch, students]);

  const handleEdit = (student) => {
    setEditingStudent(student);
    setIsModalOpen(true);
  };

  const handleAddNew = () => {
    setEditingStudent(null);
    setIsModalOpen(true);
  };

  const handleDownloadReport = async (student) => {
    setActiveStudent(student);
    setDownloading(true);
    const toastId = toast.loading(`Preparing report for ${student.name}...`);

    try {
      // 1. Fetch Performance Data
      const { data: perfData } = await axios.get(`/attendance/student?studentEmail=${encodeURIComponent(student.email)}`);
      setReportData(perfData);

      // 2. Wait for state update and template render
      setTimeout(async () => {
        if (!reportRef.current) return;

        const element = reportRef.current;
        const canvas = await html2canvas(element, {
          scale: 2,
          useCORS: true,
          logging: false,
        });
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF('p', 'mm', 'a4');
        const imgWidth = 210;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        pdf.addImage(imgData, 'PNG', 0, 0, imgWidth, imgHeight);
        pdf.save(`${student.name}_Progress_Report.pdf`);
        toast.success("Report downloaded successfully!", { id: toastId });
        setDownloading(false);
      }, 500);

    } catch (error) {
      console.error("Report Generation Failed:", error);
      toast.error("Failed to generate report", { id: toastId });
    }
  };

  const handleGenerateID = async (student) => {
    setActiveIDStudent(student);
    const toastId = toast.loading(`Designing ID card for ${student.name}...`);

    try {
      setTimeout(async () => {
        if (!idCardRef.current) return;

        const element = idCardRef.current;
        const canvas = await html2canvas(element, {
          scale: 3,
          useCORS: true,
          backgroundColor: null,
        });

        const link = document.createElement('a');
        link.download = `${student.name}_ID_Card.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

        toast.success("ID Card generated successfully!", { id: toastId });
      }, 500);

    } catch (error) {
      console.error("ID Generation Failed:", error);
      toast.error("Failed to generate ID Card", { id: toastId });
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Student Management</h1>
          <p className="text-slate-500 mt-1 font-medium">Add, manage, and monitor all enrolled students.</p>
        </div>
        <div className="flex flex-wrap gap-3">
          <CSVUploadButton onUploadSuccess={fetchStudents} />
          <button 
            onClick={handleAddNew}
            className="flex items-center gap-2 px-6 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20"
          >
            <Plus size={20} /> Add New Student
          </button>
        </div>
      </header>

      {/* Control Bar */}
      <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <SearchBar searchTerm={searchTerm} setSearchTerm={setSearchTerm} />

        <div className="flex items-center gap-6 w-full md:w-auto">
          <FilterDropdown 
            batches={batches} 
            selectedBatch={selectedBatch} 
            setSelectedBatch={setSelectedBatch} 
          />
          <div className="h-10 w-px bg-slate-100 hidden md:block"></div>
          <p className="text-sm font-bold text-slate-400">
            {loading ? "Loading..." : `Showing ${filteredStudents.length} Students`}
          </p>
        </div>
      </div>

      {/* Main Table Content */}
      {loading ? (
        <div className="flex items-center justify-center py-20">
          <div className="w-12 h-12 border-4 border-blue-900 border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : (
        <StudentTable 
          students={filteredStudents} 
          onEdit={handleEdit} 
          onDeleteSuccess={fetchStudents} 
          onDownloadReport={handleDownloadReport}
          onGenerateID={handleGenerateID}
        />
      )}

      {/* Hidden Templates */}
      <ReportTemplate 
        ref={reportRef} 
        student={activeStudent} 
        data={reportData} 
      />

      <IDCardTemplate 
        ref={idCardRef} 
        student={activeIDStudent} 
      />

      {/* Form Modal */}
      <StudentFormModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        student={editingStudent} 
        onSaveSuccess={fetchStudents} 
      />
    </div>
  );
};

export default AdminStudents;

