        const link = document.createElement('a');
        link.download = `${student.name}_ID_Card.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();

        toast.success("ID Card generated successfully!", { id: toastId });
      }, 500);

    } catch (error) {
      console.error("ID Generation Failed:", error);
      toast.error("Failed to generate ID Card", { id: toastId });
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header */}
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Student Management</h1>
          <p className="text-slate-500 mt-1 font-medium">Add, manage, and monitor all enrolled students.</p>
        </div>
        <div className="flex flex-wrap gap-3">
          <CSVUploadButton onUploadSuccess={fetchStudents} />
          <button 
            onClick={handleAddNew}
            className="flex items-center gap-2 px-6 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20"
          >
            <Plus size={20} /> Add New Student
          </button>
        </div>
      </header>

      {/* Control Bar */}
      <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-6">
        <SearchBar searchTerm={searchTerm} setSearchTerm={setSearchTerm} />

        <div className="flex items-center gap-6 w-full md:w-auto">
          <FilterDropdown 
            batches={batches} 
            selectedBatch={selectedBatch} 
            setSelectedBatch={setSelectedBatch} 
          />
          <div className="h-10 w-px bg-slate-100 hidden md:block"></div>
          <p className="text-sm font-bold text-slate-400">
            {loading ? "Loading..." : `Showing ${filteredStudents.length} Students`}
          </p>
        </div>
      </div>

      {/* Main Table Content */}
      {loading ? (
        <div className="flex items-center justify-center py-20">
          <div className="w-12 h-12 border-4 border-blue-900 border-t-transparent rounded-full animate-spin"></div>
        </div>
      ) : (
        <StudentTable 
          students={filteredStudents} 
          onEdit={handleEdit} 
          onDeleteSuccess={fetchStudents} 
          onDownloadReport={handleDownloadReport}
          onGenerateID={handleGenerateID}
        />
      )}

      {/* Hidden Templates */}
      <ReportTemplate 
        ref={reportRef} 
        student={activeStudent} 
        data={reportData} 
      />

      <IDCardTemplate 
        ref={idCardRef} 
        student={activeIDStudent} 
      />

      {/* Form Modal */}
      <StudentFormModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        student={editingStudent} 
        onSaveSuccess={fetchStudents} 
      />
    </div>
  );
};

export default AdminStudents;

