const AdminTimetable = () => {
  const [activeDay, setActiveDay] = useState("Monday");
  const [weekSlots, setWeekSlots] = useState({});
  const [faculties, setFaculties] = useState([]);
  const [batches, setBatches] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // null | {} | slot obj

  const fetchAll = async () => {
    try {
      const [slotsRes, facRes, batRes] = await Promise.all([
        axios.get(`${API}/timetable/week`),
        axios.get(`${API}/faculty`),
        axios.get(`${API}/courses/batches`),
      ]);
      setWeekSlots(slotsRes.data);
      setFaculties(facRes.data);
      setBatches(batRes.data);
    } catch {
      toast.error("Failed to load timetable data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  const saveSlot = async (form) => {
    try {
      if (modal?._id) {
        const { data } = await axios.put(`${API}/timetable/${modal._id}`, form);
        setWeekSlots((prev) => {
          const updated = { ...prev };
          // Remove from old day if day changed
          for (const d of DAYS) updated[d] = (updated[d] || []).filter((s) => s._id !== data._id);
          updated[data.day] = [...(updated[data.day] || []), data].sort((a, b) => a.startTime.localeCompare(b.startTime));
          return updated;
        });
        toast.success("Slot updated");
      } else {
        const { data } = await axios.post(`${API}/timetable`, form);
        setWeekSlots((prev) => ({
          ...prev,
          [data.day]: [...(prev[data.day] || []), data].sort((a, b) => a.startTime.localeCompare(b.startTime)),
        }));
        toast.success("Slot created");
      }
      setModal(null);
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to save slot");
    }
  };

  const deleteSlot = async (slot) => {
    if (!confirm(`Delete "${slot.subject}" on ${slot.day}?`)) return;
    try {
      await axios.delete(`${API}/timetable/${slot._id}`);
      setWeekSlots((prev) => ({
        ...prev,
        [slot.day]: prev[slot.day].filter((s) => s._id !== slot._id),
      }));
      toast.success("Slot deleted");
    } catch {
      toast.error("Failed to delete slot");
    }
  };

  const daySlots = weekSlots[activeDay] || [];

  // Room utilization from today's active day
  const roomUsage = {};
  for (const slot of daySlots) {
    roomUsage[slot.room] = (roomUsage[slot.room] || 0) + 1;
  }

  if (loading) return <div className="flex items-center justify-center h-64"><div className="animate-spin w-8 h-8 border-4 border-blue-200 border-t-blue-600 rounded-full" /></div>;

  return (
    <div className="space-y-10 animate-fade-in">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Timetable Management</h1>
          <p className="text-slate-500 mt-1 font-medium">Schedule lectures, assign halls, and manage faculty slots.</p>
        </div>
        <button onClick={() => setModal({})} className="flex items-center gap-2 px-6 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20">
          <Plus size={20} /> Create New Slot
        </button>
      </header>

      {/* Day tabs */}
      <div className="flex gap-1.5 p-1.5 bg-white border border-slate-100 rounded-2xl w-max shadow-sm flex-wrap">
        {DAYS.map((day) => (
          <button key={day} onClick={() => setActiveDay(day)}
            className={`px-5 py-2.5 rounded-xl font-bold text-sm transition-all ${activeDay === day ? "bg-blue-900 text-white shadow-lg shadow-blue-900/20" : "text-slate-500 hover:bg-slate-50"}`}>
            {day.slice(0, 3)}
            {(weekSlots[day] || []).length > 0 && (
              <span className={`ml-1.5 text-[10px] px-1.5 py-0.5 rounded-full ${activeDay === day ? "bg-white/20" : "bg-slate-100"}`}>
                {(weekSlots[day] || []).length}
              </span>
            )}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-[1.5fr_1fr] gap-8">
        {/* Schedule list */}
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/30">
            <h2 className="text-xl font-bold text-slate-800">{activeDay} Schedule</h2>
            <span className="text-xs text-slate-400 font-medium">{daySlots.length} slot(s)</span>
          </div>
          {daySlots.length === 0 ? (
            <div className="text-center py-20 text-slate-400">
              <CalendarRange size={32} className="mx-auto mb-3 opacity-30" />
              <p className="text-sm font-medium">No slots for {activeDay}.</p>
              <button onClick={() => setModal({ day: activeDay })} className="mt-3 text-blue-600 text-sm font-bold hover:underline">+ Add a slot</button>
            </div>
          ) : (
            <div className="divide-y divide-slate-50">
              {daySlots.map((slot) => (
                <div key={slot._id} className="p-6 flex flex-col md:flex-row md:items-center justify-between gap-4 hover:bg-slate-50/50 transition border-l-4 border-transparent hover:border-blue-900 group">
                  <div className="flex items-start gap-5">
                    <div className="bg-blue-50 text-blue-900 px-4 py-2.5 rounded-2xl font-black text-xs whitespace-nowrap border border-blue-100 flex items-center gap-1.5">
                      <Clock size={13} /> {slot.startTime} – {slot.endTime}
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-slate-800">{slot.subject}</h3>
                      <div className="flex flex-wrap gap-3 mt-1.5">
                        <span className="text-xs font-bold text-slate-500">{slot.faculty?.name || "—"}</span>
                        <span className="text-slate-300">•</span>
                        <span className="text-xs font-bold text-emerald-600">{slot.batch?.name || "—"}</span>
                        {slot.batch?.course && <span className="text-xs text-slate-400">({slot.batch.course.name})</span>}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <div className="flex items-center gap-2 bg-white border border-slate-100 px-4 py-2 rounded-xl shadow-sm text-sm font-bold text-slate-600">
                      <MapPin size={14} className="text-slate-400" /> {slot.room}
                    </div>
                    <button onClick={() => setModal(slot)} className="p-2 rounded-xl hover:bg-slate-100 text-slate-400 hover:text-blue-600 transition opacity-0 group-hover:opacity-100">
                      <Pencil size={15} />
                    </button>
                    <button onClick={() => deleteSlot(slot)} className="p-2 rounded-xl hover:bg-red-50 text-slate-400 hover:text-red-500 transition opacity-0 group-hover:opacity-100">
                      <Trash2 size={15} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Room utilization */}
        <div className="space-y-6">
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
            <h2 className="text-xl font-bold text-slate-800 mb-6">Room Utilization — {activeDay}</h2>
            {ROOMS.map((room) => {
              const count = roomUsage[room] || 0;
              const util = Math.min(Math.round((count / Math.max(daySlots.length, 1)) * 100), 100);
              return (
                <div key={room} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 mb-3">
                  <div className="flex justify-between items-center mb-2">
                    <p className="font-bold text-slate-800 text-sm">{room}</p>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${count > 0 ? "text-red-500" : "text-emerald-500"}`}>
                      {count > 0 ? `${count} slot(s)` : "Free"}
                    </span>
                  </div>
                  <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${count > 0 ? "bg-blue-900" : "bg-emerald-500"}`} style={{ width: `${util || 5}%` }} />
                  </div>
                </div>
              );
            })}
          </div>

          <div className="p-8 bg-blue-900 rounded-[2.5rem] shadow-xl text-white">
            <h3 className="font-bold mb-2">Weekly Overview</h3>
            <div className="space-y-2 mt-4">
              {DAYS.map((d) => (
                <div key={d} className="flex justify-between items-center text-sm">
                  <span className="text-blue-200 font-medium">{d.slice(0, 3)}</span>
                  <span className="font-black text-white">{(weekSlots[d] || []).length} slots</span>
                </div>
              ))}
            </div>
            <div className="mt-6 pt-4 border-t border-white/20 flex justify-between">
              <span className="text-blue-200 text-sm">Total Slots</span>
              <span className="font-black text-white">{Object.values(weekSlots).flat().length}</span>
            </div>
          </div>
        </div>
      </div>

      {modal !== null && (
        <SlotModal
          slot={modal}
          faculties={faculties}
          batches={batches}
          onSave={saveSlot}
          onClose={() => setModal(null)}
        />
      )}
    </div>
  );
};

export default AdminTimetable;

