          return updated;
        });
        toast.success("Slot updated");
      } else {
        const { data } = await axios.post(`${API}/timetable`, form);
        setWeekSlots((prev) => ({
          ...prev,
          [data.day]: [...(prev[data.day] || []), data].sort((a, b) => a.startTime.localeCompare(b.startTime)),
        }));
        toast.success("Slot created");
      }
      setModal(null);
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to save slot");
    }
  };

  const deleteSlot = async (slot) => {
    if (!confirm(`Delete "${slot.subject}" on ${slot.day}?`)) return;
    try {
      await axios.delete(`${API}/timetable/${slot._id}`);
      setWeekSlots((prev) => ({
        ...prev,
        [slot.day]: prev[slot.day].filter((s) => s._id !== slot._id),
      }));
      toast.success("Slot deleted");
    } catch {
      toast.error("Failed to delete slot");
    }
  };

  const daySlots = weekSlots[activeDay] || [];

  // Room utilization from today's active day
  const roomUsage = {};
  for (const slot of daySlots) {
    roomUsage[slot.room] = (roomUsage[slot.room] || 0) + 1;
  }

  if (loading) return <div className="flex items-center justify-center h-64"><div className="animate-spin w-8 h-8 border-4 border-blue-200 border-t-blue-600 rounded-full" /></div>;

  return (
    <div className="space-y-10 animate-fade-in">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">Timetable Management</h1>
          <p className="text-slate-500 mt-1 font-medium">Schedule lectures, assign halls, and manage faculty slots.</p>
        </div>
        <button onClick={() => setModal({})} className="flex items-center gap-2 px-6 py-3 bg-blue-900 text-white font-bold rounded-2xl hover:bg-blue-800 transition shadow-xl shadow-blue-900/20">
          <Plus size={20} /> Create New Slot
        </button>
      </header>

      {/* Day tabs */}
      <div className="flex gap-1.5 p-1.5 bg-white border border-slate-100 rounded-2xl w-max shadow-sm flex-wrap">
        {DAYS.map((day) => (
          <button key={day} onClick={() => setActiveDay(day)}
            className={`px-5 py-2.5 rounded-xl font-bold text-sm transition-all ${activeDay === day ? "bg-blue-900 text-white shadow-lg shadow-blue-900/20" : "text-slate-500 hover:bg-slate-50"}`}>
            {day.slice(0, 3)}
            {(weekSlots[day] || []).length > 0 && (
              <span className={`ml-1.5 text-[10px] px-1.5 py-0.5 rounded-full ${activeDay === day ? "bg-white/20" : "bg-slate-100"}`}>
                {(weekSlots[day] || []).length}
              </span>
            )}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-[1.5fr_1fr] gap-8">
        {/* Schedule list */}
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/30">
            <h2 className="text-xl font-bold text-slate-800">{activeDay} Schedule</h2>
            <span className="text-xs text-slate-400 font-medium">{daySlots.length} slot(s)</span>
          </div>
          {daySlots.length === 0 ? (
            <div className="text-center py-20 text-slate-400">
              <CalendarRange size={32} className="mx-auto mb-3 opacity-30" />
              <p className="text-sm font-medium">No slots for {activeDay}.</p>
              <button onClick={() => setModal({ day: activeDay })} className="mt-3 text-blue-600 text-sm font-bold hover:underline">+ Add a slot</button>
            </div>
          ) : (
            <div className="divide-y divide-slate-50">
              {daySlots.map((slot) => (
                <div key={slot._id} className="p-6 flex flex-col md:flex-row md:items-center justify-between gap-4 hover:bg-slate-50/50 transition border-l-4 border-transparent hover:border-blue-900 group">
                  <div className="flex items-start gap-5">
