            {ROOMS.map((room) => {
              const count = roomUsage[room] || 0;
              const util = Math.min(Math.round((count / Math.max(daySlots.length, 1)) * 100), 100);
              return (
                <div key={room} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 mb-3">
                  <div className="flex justify-between items-center mb-2">
                    <p className="font-bold text-slate-800 text-sm">{room}</p>
