import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { ArrowLeft, Users, BookOpen, ChevronDown, ChevronUp } from "lucide-react";

// API base URL is handled by axiosInstance

const ManageCourse = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [course, setCourse] = useState(null);
  const [batches, setBatches] = useState([]);
  const [expanded, setExpanded] = useState({});
  const [rosters, setRosters] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [courses, batchRes] = await Promise.all([
          axios.get("/courses"),
          axios.get(`/courses/batches?course=${id}`),
        ]);
        const found = courses.data.find((c) => c._id === id);
        setCourse(found || null);
        setBatches(batchRes.data);
      } catch (error) {
        toast.error(error.response?.data?.message || "Failed to load course data");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [id]);

  const toggleBatch = async (batchId) => {
    setExpanded((prev) => ({ ...prev, [batchId]: !prev[batchId] }));
    if (!rosters[batchId]) {
      try {
        const { data } = await axios.get(`/courses/batches/${batchId}/roster`);
        setRosters((prev) => ({ ...prev, [batchId]: data }));
      } catch (error) {
        toast.error(error.response?.data?.message || "Failed to load roster");
      }
    }
  };

  if (loading) return <div className="flex items-center justify-center h-64 text-slate-400 font-medium">Loading...</div>;
  if (!course) return <div className="text-center py-20 text-slate-400">Course not found.</div>;

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Header */}
      <div className="flex items-center gap-4">
        <button onClick={() => navigate("/admin/courses")}
          className="p-2.5 rounded-xl border border-slate-200 hover:bg-slate-50 text-slate-500 transition">
          <ArrowLeft size={18} />
        </button>
        <div>
          <h1 className="text-3xl font-black text-slate-800 tracking-tight">{course.name}</h1>
          <p className="text-slate-500 mt-0.5 font-medium">{course.type} · {course.description || "No description"}</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 gap-4 max-w-sm">
        <div className="bg-white rounded-2xl border border-slate-100 p-5 flex items-center gap-3 shadow-sm">
          <div className="w-10 h-10 rounded-xl bg-blue-50 flex items-center justify-center text-blue-600">
            <BookOpen size={18} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase">Batches</p>
            <p className="text-xl font-black text-slate-800">{course.batchCount}</p>
          </div>
        </div>
        <div className="bg-white rounded-2xl border border-slate-100 p-5 flex items-center gap-3 shadow-sm">
          <div className="w-10 h-10 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-600">
            <Users size={18} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase">Students</p>
            <p className="text-xl font-black text-slate-800">{course.studentCount}</p>
          </div>
        </div>
      </div>

      {/* Batches */}
      <div className="space-y-4">
        <h2 className="text-lg font-black text-slate-700">All Batches</h2>
        {batches.length === 0 ? (
          <div className="text-center py-16 text-slate-400 bg-white rounded-3xl border border-slate-100">No batches for this course yet.</div>
        ) : (
          batches.map((batch) => (
            <div key={batch._id} className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
              {/* Batch Header */}
              <button onClick={() => toggleBatch(batch._id)}
                className="w-full flex items-center justify-between px-8 py-6 hover:bg-slate-50 transition text-left">
                <div className="flex items-center gap-6">
                  <div>
                    <p className="text-lg font-black text-slate-800">{batch.name}</p>
                    <p className="text-xs text-slate-400 font-medium mt-0.5">
                      Faculty: <span className="text-slate-600 font-bold">{batch.faculty?.name || "—"}</span>
                      <span className="mx-2">·</span>
                      {batch.students?.length || 0} students
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-6">
                  <div className="text-right hidden md:block">
                    <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Progress</p>
                    <div className="flex items-center gap-3">
                      <div className="w-32 h-2 bg-slate-200 rounded-full overflow-hidden">
                        <div className="h-full bg-blue-600 rounded-full" style={{ width: `${batch.progress}%` }} />
                      </div>
                      <span className="text-xs font-black text-slate-700">{batch.progress}%</span>
                    </div>
                  </div>
                  {expanded[batch._id] ? <ChevronUp size={18} className="text-slate-400" /> : <ChevronDown size={18} className="text-slate-400" />}
                </div>
              </button>

              {/* Student Roster */}
              {expanded[batch._id] && (
                <div className="border-t border-slate-100 px-8 py-6">
                  <p className="text-xs font-black text-slate-500 uppercase tracking-widest mb-4">Student Roster</p>
                  {!rosters[batch._id] ? (
                    <p className="text-sm text-slate-400">Loading...</p>
                  ) : rosters[batch._id].length === 0 ? (
                    <p className="text-sm text-slate-400">No students assigned to this batch.</p>
                  ) : (
                    <div className="overflow-x-auto rounded-xl border border-slate-100">
                      <table className="w-full text-sm">
                        <thead className="bg-slate-50 text-xs font-black text-slate-500 uppercase tracking-widest">
                          <tr>
                            <th className="px-4 py-3 text-left">#</th>
                            <th className="px-4 py-3 text-left">Name</th>
                            <th className="px-4 py-3 text-left">Roll No</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Phone</th>
                            <th className="px-4 py-3 text-left">Fees</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                          {rosters[batch._id].map((s, idx) => (
                            <tr key={s._id} className="hover:bg-slate-50">
                              <td className="px-4 py-3 text-slate-400 text-xs">{idx + 1}</td>
                              <td className="px-4 py-3 font-semibold text-slate-800">{s.name}</td>
                              <td className="px-4 py-3 text-slate-500">{s.rollNo}</td>
                              <td className="px-4 py-3 text-slate-500">{s.email}</td>
                              <td className="px-4 py-3 text-slate-500">{s.phone || "—"}</td>
                              <td className="px-4 py-3">
                                <span className={`px-2 py-0.5 rounded-full text-[10px] font-black uppercase ${s.feesStatus === "paid" ? "bg-emerald-100 text-emerald-700" : s.feesStatus === "partial" ? "bg-amber-100 text-amber-700" : "bg-red-100 text-red-600"}`}>
                                  {s.feesStatus}
                                </span>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default ManageCourse;

