import { useEffect, useState, useContext } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Check, X, CheckCircle2, Search, BarChart2 } from "lucide-react";
import { AuthContext } from "../../context/AuthContext";

const API = "http://localhost:5001/api";

const FacultyAttendance = () => {
  const { user } = useContext(AuthContext);

  const [batches, setBatches] = useState([]);
  const [facultyId, setFacultyId] = useState(null);
  const [warning, setWarning] = useState(null);
  const [batchesLoading, setBatchesLoading] = useState(true);

  const [selectedBatch, setSelectedBatch] = useState("");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);
  const [students, setStudents] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [alreadySubmitted, setAlreadySubmitted] = useState(false);

  const [tab, setTab] = useState("mark");
  const [summary, setSummary] = useState([]);
  const [summaryLoading, setSummaryLoading] = useState(false);

  // ── Load faculty's assigned batches ──────────────────────
  useEffect(() => {
    if (!user?.email) return;
    setBatchesLoading(true);
    axios
      .get(`${API}/attendance/batches?facultyEmail=${encodeURIComponent(user.email)}`)
      .then(({ data }) => {
        setBatches(data.batches || []);
        setFacultyId(data.facultyId || null);
        setWarning(data.warning || null);
      })
      .catch((err) => {
        setWarning(err.response?.data?.message || "Failed to load batches. Check server connection.");
      })
      .finally(() => setBatchesLoading(false));
  }, [user]);

  // ── Load students for selected batch + date ───────────────
  const loadStudents = async () => {
    if (!selectedBatch) return toast.error("Please select a batch");
    setLoading(true);
    setAlreadySubmitted(false);
    setStudents([]);

    try {
      const batch = batches.find((b) => b._id === selectedBatch);
      // Base list from batch roster
      const baseStudents = (batch?.students || []).map((s) => ({
        _id: s._id.toString(),
        name: s.name,
        rollNo: s.rollNo,
        status: null,
      }));

      if (baseStudents.length === 0) {
        toast.error("This batch has no students. Add students via Admin → Courses & Batches.");
        setLoading(false);
        return;
      }

      // Check if attendance already exists for this date
      const { data: existing } = await axios.get(
        `${API}/attendance?batch=${selectedBatch}&date=${date}`
      );

      if (existing?.records?.length > 0) {
        setAlreadySubmitted(true);
        // Merge existing statuses — compare as strings to avoid ObjectId vs string mismatch
        const merged = baseStudents.map((s) => {
          const rec = existing.records.find(
            (r) => (r.student?._id?.toString() || r.student?.toString()) === s._id
          );
          return { ...s, status: rec?.status ?? null };
        });
        setStudents(merged);
      } else {
        setStudents(baseStudents);
      }
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to load students");
    } finally {
      setLoading(false);
    }
  };

  // ── Load summary ──────────────────────────────────────────
  const loadSummary = async () => {
    if (!selectedBatch) return toast.error("Please select a batch");
    setSummaryLoading(true);
    try {
      const { data } = await axios.get(`${API}/attendance/summary?batch=${selectedBatch}`);
      setSummary(data);
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to load summary");
    } finally {
      setSummaryLoading(false);
    }
  };

  // Auto-reload summary when switching to summary tab
  useEffect(() => {
    if (tab === "summary" && selectedBatch) loadSummary();
  }, [tab]);

  const toggleStatus = (id, status) =>
    setStudents((prev) => prev.map((s) => (s._id === id ? { ...s, status } : s)));

  const markAll = (status) =>
    setStudents((prev) => prev.map((s) => ({ ...s, status })));

  // ── Submit attendance ─────────────────────────────────────
  const handleSubmit = async () => {
    if (!selectedBatch) return toast.error("No batch selected");
    if (!facultyId) return toast.error("Faculty profile not linked. Contact admin.");

    const unmarked = students.filter((s) => s.status === null);
    if (unmarked.length > 0)
      return toast.error(`Mark all students first. ${unmarked.length} unmarked.`);

    setSubmitting(true);
    try {
      await axios.post(`${API}/attendance`, {
        batch: selectedBatch,
        date,
        markedBy: facultyId,
        records: students.map((s) => ({ student: s._id, status: s.status })),
      });
      toast.success(alreadySubmitted ? "Attendance updated!" : "Attendance submitted!");
      setAlreadySubmitted(true);
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to submit attendance");
    } finally {
      setSubmitting(false);
    }
  };

  const filtered = students.filter(
    (s) =>
      s.name.toLowerCase().includes(search.toLowerCase()) ||
      s.rollNo.toLowerCase().includes(search.toLowerCase())
  );

  const presentCount = students.filter((s) => s.status === "present").length;
  const absentCount = students.filter((s) => s.status === "absent").length;
  const unmarkedCount = students.filter((s) => s.status === null).length;
  const selectedBatchObj = batches.find((b) => b._id === selectedBatch);

  return (
    <div className="space-y-6">
      <header className="mb-2">
        <h1 className="text-3xl font-bold text-slate-800">Mark Attendance</h1>
        <p className="text-slate-500 mt-1">Record attendance for your assigned batches.</p>
      </header>

      {/* Tabs */}
      <div className="flex gap-2">
        {["mark", "summary"].map((t) => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className={`px-5 py-2 rounded-xl text-sm font-bold transition ${
              tab === t
                ? "bg-slate-900 text-white shadow"
                : "bg-white border border-slate-200 text-slate-600 hover:bg-slate-50"
            }`}
          >
            {t === "mark" ? "Mark Attendance" : (
              <span className="flex items-center gap-1.5"><BarChart2 size={14} /> Summary</span>
            )}
          </button>
        ))}
      </div>

      {/* Warning / diagnostic banner */}
      {warning && (
        <div className="bg-amber-50 border border-amber-200 rounded-2xl p-5 flex items-start gap-3">
          <span className="text-amber-500 text-lg mt-0.5">⚠️</span>
          <div>
            <p className="font-bold text-amber-900 text-sm">Setup Required</p>
            <p className="text-amber-700 text-sm mt-1">{warning}</p>
            <p className="text-amber-600 text-xs mt-2">
              Your login email: <span className="font-bold">{user?.email}</span>
            </p>
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col md:flex-row gap-4 items-end">
        <div className="w-full md:w-1/3">
          <label className="block text-sm font-medium text-slate-700 mb-1">Select Batch</label>
          {batchesLoading ? (
            <div className="w-full px-4 py-2.5 rounded-xl border border-slate-200 bg-slate-50 text-slate-400 text-sm">
              Loading batches...
            </div>
          ) : (
            <select
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-amber-500 bg-slate-50"
              value={selectedBatch}
              onChange={(e) => {
                setSelectedBatch(e.target.value);
                setStudents([]);
                setSummary([]);
                setAlreadySubmitted(false);
              }}
            >
              <option value="">-- Choose Batch --</option>
              {batches.map((b) => (
                <option key={b._id} value={b._id}>
                  {b.name}{b.course ? ` (${b.course.name})` : ""}
                </option>
              ))}
            </select>
          )}
        </div>

        {tab === "mark" && (
          <div className="w-full md:w-1/3">
            <label className="block text-sm font-medium text-slate-700 mb-1">Date</label>
            <input
              type="date"
              value={date}
              max={new Date().toISOString().split("T")[0]}
              onChange={(e) => { setDate(e.target.value); setStudents([]); setAlreadySubmitted(false); }}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-amber-500 bg-slate-50"
            />
          </div>
        )}

        <button
          onClick={tab === "mark" ? loadStudents : loadSummary}
          disabled={!selectedBatch || loading || summaryLoading}
          className="w-full md:w-auto px-8 py-2.5 bg-slate-900 hover:bg-slate-800 disabled:opacity-50 text-white font-semibold rounded-xl transition shadow-lg shadow-slate-900/20"
        >
          {loading || summaryLoading ? "Loading..." : tab === "mark" ? "Load Students" : "Load Summary"}
        </button>
      </div>

      {/* ── MARK TAB ── */}
      {tab === "mark" && (
        <>
          {students.length === 0 && !loading && selectedBatch && (
            <div className="text-center py-10 text-slate-400 text-sm bg-white rounded-2xl border border-slate-100">
              Click "Load Students" to fetch the student list for this batch and date.
            </div>
          )}

          {students.length > 0 && (
            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
              {/* Stats + actions bar */}
              <div className="px-6 py-4 border-b border-slate-100 bg-slate-50 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div className="flex flex-wrap gap-2">
                  <span className="text-sm font-semibold text-slate-600 bg-white px-3 py-1.5 rounded-lg border border-slate-200">
                    Total: {students.length}
                  </span>
                  <span className="text-sm font-semibold text-emerald-700 bg-emerald-50 px-3 py-1.5 rounded-lg border border-emerald-100">
                    Present: {presentCount}
                  </span>
                  <span className="text-sm font-semibold text-red-700 bg-red-50 px-3 py-1.5 rounded-lg border border-red-100">
                    Absent: {absentCount}
                  </span>
                  {unmarkedCount > 0 && (
                    <span className="text-sm font-semibold text-amber-700 bg-amber-50 px-3 py-1.5 rounded-lg border border-amber-100">
                      Unmarked: {unmarkedCount}
                    </span>
                  )}
                  {alreadySubmitted && (
                    <span className="text-sm font-semibold text-blue-700 bg-blue-50 px-3 py-1.5 rounded-lg border border-blue-100">
                      ✓ Already submitted
                    </span>
                  )}
                </div>

                <div className="flex gap-2 w-full sm:w-auto">
                  <div className="relative flex-1 sm:w-44">
                    <Search size={15} className="absolute left-3 top-2.5 text-slate-400" />
                    <input
                      type="text"
                      placeholder="Search..."
                      value={search}
                      onChange={(e) => setSearch(e.target.value)}
                      className="w-full pl-9 pr-3 py-2 text-sm border border-slate-200 rounded-lg outline-none focus:border-amber-400"
                    />
                  </div>
                  <button
                    onClick={() => markAll("present")}
                    className="px-3 py-2 bg-emerald-100 hover:bg-emerald-200 text-emerald-700 text-xs font-bold rounded-lg transition flex items-center gap-1 whitespace-nowrap"
                  >
                    <CheckCircle2 size={14} /> All Present
                  </button>
                  <button
                    onClick={() => markAll("absent")}
                    className="px-3 py-2 bg-red-100 hover:bg-red-200 text-red-700 text-xs font-bold rounded-lg transition flex items-center gap-1 whitespace-nowrap"
                  >
                    <X size={14} /> All Absent
                  </button>
                </div>
              </div>

              {/* Student cards */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 p-6 gap-3">
                {filtered.map((student) => (
                  <div
                    key={student._id}
                    className={`p-4 border rounded-xl flex items-center justify-between transition ${
                      student.status === "present"
                        ? "border-emerald-200 bg-emerald-50/50"
                        : student.status === "absent"
                        ? "border-red-200 bg-red-50/50"
                        : "border-slate-100 bg-slate-50/50 hover:border-slate-300"
                    }`}
                  >
                    <div>
                      <p className="font-bold text-slate-800 text-sm">{student.name}</p>
                      <p className="text-xs text-slate-500 mt-0.5">{student.rollNo}</p>
                    </div>
                    <div className="flex gap-2">
                      <button
                        onClick={() => toggleStatus(student._id, "present")}
                        className={`w-9 h-9 rounded-lg flex items-center justify-center transition-all ${
                          student.status === "present"
                            ? "bg-emerald-500 text-white shadow-md shadow-emerald-500/30"
                            : "bg-slate-200 text-slate-500 hover:bg-emerald-100 hover:text-emerald-600"
                        }`}
                      >
                        <Check size={18} />
                      </button>
                      <button
                        onClick={() => toggleStatus(student._id, "absent")}
                        className={`w-9 h-9 rounded-lg flex items-center justify-center transition-all ${
                          student.status === "absent"
                            ? "bg-red-500 text-white shadow-md shadow-red-500/30"
                            : "bg-slate-200 text-slate-500 hover:bg-red-100 hover:text-red-600"
                        }`}
                      >
                        <X size={18} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>

              {/* Submit */}
              <div className="px-6 py-4 border-t border-slate-100 bg-slate-50 flex items-center justify-between">
                <p className="text-xs text-slate-400">
                  {unmarkedCount > 0
                    ? `${unmarkedCount} student(s) not yet marked`
                    : "All students marked ✓"}
