        <div className="text-center py-16 text-slate-400 bg-white rounded-2xl border border-slate-100">Loading...</div>
      ) : batches.length === 0 ? (
        <div className="text-center py-16 text-slate-400 bg-white rounded-2xl border border-slate-100">No batches assigned yet.</div>
      ) : (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {batches.map((batch) => (
            <div key={batch._id} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden hover:shadow-md transition group">
              <div className="h-2 bg-indigo-500 w-full group-hover:bg-amber-500 transition-colors" />
              <div className="p-6">
                <div className="flex justify-between items-start mb-4">
                  <h2 className="text-xl font-bold text-slate-800">{batch.name}</h2>
                  <span className="bg-slate-100 text-slate-600 text-xs font-bold px-2.5 py-1 rounded-md">{batch.progress || 0}%</span>
