import { useContext, useEffect, useMemo, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { AuthContext } from "../../context/AuthContext";
import { Users, BookOpen, Clock, FileCheck, FileSpreadsheet, CheckCircle2 } from "lucide-react";
import { Link } from "react-router-dom";

const API = "http://localhost:5001/api";

const todayName = new Date().toLocaleString("en", { weekday: "long" });

const FacultyDashboard = () => {
  const { user } = useContext(AuthContext);
  const [batches, setBatches] = useState([]);
  const [weekSlots, setWeekSlots] = useState({});
  const [logs, setLogs] = useState([]);
  const [totalSeconds, setTotalSeconds] = useState(0);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user?.email) return;
    const load = async () => {
      try {
        const batchRes = await axios.get(`${API}/attendance/batches?facultyEmail=${encodeURIComponent(user.email)}`);
        const assignedBatches = batchRes.data.batches || [];
        setBatches(assignedBatches);

        const facultyId = batchRes.data.facultyId;
        const [slotsRes, logsRes] = await Promise.all([
          facultyId ? axios.get(`${API}/timetable/week?faculty=${facultyId}`) : Promise.resolve({ data: {} }),
          facultyId ? axios.get(`${API}/timetable/logs?faculty=${facultyId}&limit=20`) : Promise.resolve({ data: { logs: [], totalSeconds: 0 } }),
        ]);
        setWeekSlots(slotsRes.data || {});
        setLogs(logsRes.data.logs || []);
        setTotalSeconds(logsRes.data.totalSeconds || 0);
      } catch (error) {
        toast.error(error.response?.data?.message || "Failed to load dashboard");
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [user]);

  const totalStudents = useMemo(() => {
    const ids = new Set();
    batches.forEach((batch) => (batch.students || []).forEach((student) => ids.add(student._id)));
    return ids.size;
  }, [batches]);

  const todaySlots = weekSlots[todayName] || [];
  const weekStart = new Date();
  weekStart.setDate(weekStart.getDate() - weekStart.getDay());
  weekStart.setHours(0, 0, 0, 0);
  const weekSeconds = logs
    .filter((log) => new Date(log.date) >= weekStart)
    .reduce((sum, log) => sum + log.durationSeconds, 0);

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Dashboard Overview</h1>
        <p className="text-slate-500 mt-1">Welcome back, {user?.name || "Professor"}. Your data is loaded from live records.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="w-14 h-14 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center shrink-0"><BookOpen size={28} /></div>
          <div><p className="text-slate-500 text-sm font-medium mb-1">Today's Classes</p><p className="text-3xl font-bold text-slate-800">{loading ? "..." : todaySlots.length}</p></div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="w-14 h-14 rounded-xl bg-emerald-50 text-emerald-600 flex items-center justify-center shrink-0"><Users size={28} /></div>
          <div><p className="text-slate-500 text-sm font-medium mb-1">Total Students</p><p className="text-3xl font-bold text-slate-800">{loading ? "..." : totalStudents}</p></div>
        </div>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="w-14 h-14 rounded-xl bg-amber-50 text-amber-600 flex items-center justify-center shrink-0"><Clock size={28} /></div>
          <div><p className="text-slate-500 text-sm font-medium mb-1">Hours Taught (Week)</p><p className="text-3xl font-bold text-slate-800">{(weekSeconds / 3600).toFixed(1)}</p></div>
        </div>
        <div className="bg-slate-900 p-6 rounded-2xl shadow-sm text-white">
          <h3 className="text-slate-300 font-medium mb-3">Pending Tasks</h3>
          <div className="flex items-center gap-2 mb-2"><span className="w-2 h-2 rounded-full bg-amber-400" /><p className="text-sm">{batches.length ? "Review assigned batch attendance" : "No assigned batches"}</p></div>
          <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-emerald-400" /><p className="text-sm">{logs.length ? "Teaching logs available" : "No teaching logs yet"}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-8">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-bold text-slate-800">Today's Schedule</h2>
            <Link to="/faculty/timetable" className="text-sm font-semibold text-indigo-600 hover:text-indigo-800">View All</Link>
          </div>
          <div className="space-y-4">
            {todaySlots.length === 0 ? (
              <div className="text-center py-10 text-slate-400">No classes scheduled for today.</div>
            ) : (
              todaySlots.map((slot) => (
                <div key={slot._id} className="p-4 rounded-xl border flex items-center justify-between bg-white border-slate-100 hover:bg-slate-50">
                  <div className="flex items-center gap-4">
                    <div className="text-sm font-bold text-slate-500 w-28">{slot.startTime} - {slot.endTime}</div>
                    <div><h3 className="font-bold text-slate-800">{slot.subject}</h3><p className="text-xs font-medium text-slate-500">{slot.batch?.name || "Batch"}</p></div>
                  </div>
                  <CheckCircle2 className="text-emerald-500" size={20} />
                </div>
              ))
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h2 className="text-lg font-bold text-slate-800 mb-6">Quick Actions</h2>
          <div className="grid grid-cols-2 gap-4">
            <Link to="/faculty/attendance" className="p-6 border border-slate-100 rounded-xl hover:border-emerald-300 hover:bg-emerald-50 transition group flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mb-3"><FileCheck size={24} /></div>
              <h3 className="font-bold text-slate-800">Mark Attendance</h3>
              <p className="text-xs text-slate-500 mt-1">Record daily presence</p>
            </Link>
            <Link to="/faculty/results" className="p-6 border border-slate-100 rounded-xl hover:border-blue-300 hover:bg-blue-50 transition group flex flex-col items-center text-center">
              <div className="w-14 h-14 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mb-3"><FileSpreadsheet size={24} /></div>
              <h3 className="font-bold text-slate-800">Upload Results</h3>
              <p className="text-xs text-slate-500 mt-1">Enter marks for tests</p>
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FacultyDashboard;

