import { useEffect, useState, useContext } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Play, Square, Clock } from "lucide-react";
import { AuthContext } from "../../context/AuthContext";

const API = "http://localhost:5001/api";

const fmt = (s) => {
  const h = Math.floor(s / 3600).toString().padStart(2, "0");
  const m = Math.floor((s % 3600) / 60).toString().padStart(2, "0");
  const sec = (s % 60).toString().padStart(2, "0");
  return `${h}:${m}:${sec}`;
};

const FacultyHours = () => {
  const { user } = useContext(AuthContext);

  const [faculty, setFaculty] = useState(null);
  const [batches, setBatches] = useState([]);
  const [logs, setLogs] = useState([]);
  const [totalSeconds, setTotalSeconds] = useState(0);
  const [loading, setLoading] = useState(true);

  const [isActive, setIsActive] = useState(false);
  const [seconds, setSeconds] = useState(0);
  const [selectedBatch, setSelectedBatch] = useState("");
  const [selectedSubject, setSelectedSubject] = useState("");
  const [saving, setSaving] = useState(false);

  // Load faculty profile + assigned batches + logs
  useEffect(() => {
    if (!user?.email) return;
    const load = async () => {
      try {
        const facRes = await axios.get(`${API}/faculty`);
        const fac = facRes.data.find((f) => f.email.toLowerCase() === user.email.toLowerCase());
        if (!fac) { toast.error("Faculty profile not found."); setLoading(false); return; }
        setFaculty(fac);

        const [batchRes, logsRes] = await Promise.all([
          axios.get(`${API}/attendance/batches?facultyEmail=${encodeURIComponent(user.email)}`),
          axios.get(`${API}/timetable/logs?faculty=${fac._id}&limit=50`),
        ]);
        setBatches(batchRes.data.batches || []);
        setLogs(logsRes.data.logs || []);
        setTotalSeconds(logsRes.data.totalSeconds || 0);
      } catch {
        toast.error("Failed to load data");
      } finally {
        setLoading(false);
      }
    };
    load();
  }, [user]);

  // Stopwatch
  useEffect(() => {
    let interval = null;
    if (isActive) interval = setInterval(() => setSeconds((s) => s + 1), 1000);
    return () => clearInterval(interval);
  }, [isActive]);

  const handleStart = () => {
    if (!selectedBatch || !selectedSubject.trim()) {
      return toast.error("Select a batch and enter a subject first");
    }
    setIsActive(true);
  };

  const handleStop = async () => {
    setIsActive(false);
    if (seconds < 10) { setSeconds(0); return; } // ignore accidental stops
    setSaving(true);
    try {
      const { data } = await axios.post(`${API}/timetable/logs`, {
        faculty: faculty._id,
        batch: selectedBatch,
        subject: selectedSubject,
        durationSeconds: seconds,
      });
      setLogs((prev) => [data, ...prev]);
      setTotalSeconds((prev) => prev + seconds);
      toast.success("Session saved!");
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to save session");
    } finally {
      setSaving(false);
      setSeconds(0);
      setSelectedBatch("");
      setSelectedSubject("");
    }
  };

  const thisWeekSeconds = logs
    .filter((l) => {
      const d = new Date(l.date);
      const now = new Date();
      const weekStart = new Date(now.setDate(now.getDate() - now.getDay()));
      return d >= weekStart;
    })
    .reduce((sum, l) => sum + l.durationSeconds, 0);

  if (loading)
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin w-8 h-8 border-4 border-indigo-200 border-t-indigo-600 rounded-full" />
      </div>
    );

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Teaching Hours Tracking</h1>
        <p className="text-slate-500 mt-1">Record your live lecture durations for administrative payroll.</p>
      </header>

      {!faculty && (
        <div className="bg-amber-50 border border-amber-200 rounded-2xl p-5 text-sm text-amber-700 font-medium">
          ⚠️ Faculty profile not found for <strong>{user?.email}</strong>. Ask admin to add your profile.
        </div>
      )}

      <div className="grid lg:grid-cols-2 gap-8">
        {/* Stopwatch */}
        <div className="bg-slate-900 rounded-3xl shadow-xl overflow-hidden text-center relative p-10 flex flex-col items-center">
          {isActive && <div className="absolute inset-0 bg-indigo-500/10 animate-pulse pointer-events-none" />}
          <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center text-white/50 mb-8">
            <Clock size={32} />
          </div>
          <h2 className="text-white text-lg font-medium mb-2">Live Lecture Tracker</h2>
          <div className="text-6xl sm:text-7xl font-bold text-white mb-10 tracking-widest tabular-nums font-mono">
            {fmt(seconds)}
          </div>

          {!isActive ? (
            <div className="w-full space-y-4 max-w-sm">
              <select
                value={selectedBatch}
                onChange={(e) => setSelectedBatch(e.target.value)}
                className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white focus:outline-none focus:ring-2 focus:ring-emerald-400"
              >
                <option value="" className="text-slate-800">Select Batch</option>
                {batches.map((b) => (
                  <option key={b._id} value={b._id} className="text-slate-800">
                    {b.name}{b.course ? ` (${b.course.name})` : ""}
                  </option>
                ))}
              </select>
              <input
                type="text"
                placeholder="Subject / Topic"
                value={selectedSubject}
                onChange={(e) => setSelectedSubject(e.target.value)}
                className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder:text-white/40 focus:outline-none focus:ring-2 focus:ring-emerald-400"
              />
              <button
                onClick={handleStart}
                disabled={!faculty}
                className="w-full py-4 mt-2 bg-emerald-500 hover:bg-emerald-400 disabled:opacity-50 text-slate-900 font-bold rounded-xl transition flex items-center justify-center gap-2 text-lg shadow-[0_0_20px_rgba(16,185,129,0.3)]"
              >
                <Play fill="currentColor" size={20} /> Start Class
              </button>
            </div>
          ) : (
            <div className="w-full max-w-sm">
              <div className="mb-6 bg-white/10 p-4 rounded-xl border border-white/10 text-left">
                <p className="text-indigo-300 text-xs font-bold uppercase tracking-wider mb-1">Ongoing Lecture</p>
                <p className="text-white font-medium">
                  {batches.find((b) => b._id === selectedBatch)?.name || selectedBatch} · {selectedSubject}
                </p>
              </div>
              <button
                onClick={handleStop}
                disabled={saving}
                className="w-full py-4 bg-red-500 hover:bg-red-400 disabled:opacity-50 text-white font-bold rounded-xl transition flex items-center justify-center gap-2 text-lg shadow-[0_0_20px_rgba(239,68,68,0.3)]"
              >
                <Square fill="currentColor" size={20} /> {saving ? "Saving..." : "End Class"}
              </button>
            </div>
          )}
        </div>

        {/* Logs */}
        <div className="bg-white rounded-3xl shadow-sm border border-slate-100 flex flex-col overflow-hidden">
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
            <h2 className="text-lg font-bold text-slate-800">Session Logs</h2>
            <div className="flex gap-2">
              <span className="text-xs font-bold bg-indigo-100 text-indigo-700 px-3 py-1 rounded-full">
                This week: {fmt(thisWeekSeconds)}
              </span>
              <span className="text-xs font-bold bg-slate-100 text-slate-600 px-3 py-1 rounded-full">
                Total: {(totalSeconds / 3600).toFixed(1)}h
              </span>
            </div>
          </div>
          <div className="divide-y divide-slate-100 overflow-y-auto max-h-[420px]">
            {logs.length === 0 ? (
              <div className="text-center py-16 text-slate-400 text-sm">No sessions logged yet. Start a class above!</div>
            ) : (
              logs.map((log) => (
                <div key={log._id} className="p-5 flex items-center justify-between hover:bg-slate-50 transition">
                  <div>
                    <p className="font-bold text-slate-800">{log.batch?.name || "—"}</p>
                    <div className="flex gap-2 text-sm text-slate-500 mt-0.5">
                      <span className="font-medium text-indigo-600">{log.subject}</span>
                      <span>·</span>
                      <span>{new Date(log.date).toLocaleDateString("en-US", { month: "short", day: "numeric" })}</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="bg-slate-100 px-3 py-1.5 rounded-lg font-mono font-bold text-slate-700 text-sm">
                      {fmt(log.durationSeconds)}
