  const [selectedBatch, setSelectedBatch] = useState("");
  const [students, setStudents] = useState([]);
  const [testName, setTestName] = useState("");
  const [subject, setSubject] = useState("");
  const [totalMarks, setTotalMarks] = useState("");
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!user?.email) return;
    axios
      .get(`${API}/attendance/batches?facultyEmail=${encodeURIComponent(user.email)}`)
      .then(({ data }) => {
        setBatches(data.batches || []);
        setFacultyId(data.facultyId || "");
      })
      .catch((error) => toast.error(error.response?.data?.message || "Failed to load batches"));
  }, [user]);

  const loadRoster = () => {
    const batch = batches.find((item) => item._id === selectedBatch);
    if (!batch) return toast.error("Please select a batch");
    setStudents((batch.students || []).map((student) => ({ ...student, marks: "" })));
  };

  const handleMarkChange = (id, value) => {
    setStudents((prev) => prev.map((student) => (student._id === id ? { ...student, marks: value } : student)));
  };

  const publishResults = async () => {
    if (!selectedBatch) return toast.error("Please select a batch");
    if (!testName.trim()) return toast.error("Enter test name");
    if (!totalMarks || Number(totalMarks) <= 0) return toast.error("Enter valid total marks");
    if (students.length === 0) return toast.error("Load roster before publishing");

    setSaving(true);
    try {
      await axios.post(`${API}/results`, {
        testName,
        subject,
        batch: selectedBatch,
        faculty: facultyId || undefined,
        totalMarks: Number(totalMarks),
        records: students.map((student) => ({ student: student._id, marks: Number(student.marks) || 0 })),
      });
      toast.success("Results published");
      setTestName("");
      setSubject("");
      setTotalMarks("");
      setStudents([]);
      setSelectedBatch("");
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to publish results");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Upload Results</h1>
        <p className="text-slate-500 mt-1">Enter test scores for students in your assigned batches.</p>
      </header>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 grid md:grid-cols-5 gap-4 items-end">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Batch</label>
          <select className="w-full px-4 py-2.5 rounded-xl border border-slate-200 bg-slate-50" value={selectedBatch} onChange={(e) => { setSelectedBatch(e.target.value); setStudents([]); }}>
            <option value="">-- Select --</option>
            {batches.map((batch) => <option key={batch._id} value={batch._id}>{batch.name}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Test Name</label>
          <input value={testName} onChange={(e) => setTestName(e.target.value)} type="text" placeholder="Unit Test" className="w-full px-4 py-2.5 rounded-xl border border-slate-200 bg-slate-50" />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Subject</label>
          <input value={subject} onChange={(e) => setSubject(e.target.value)} type="text" placeholder="Subject" className="w-full px-4 py-2.5 rounded-xl border border-slate-200 bg-slate-50" />
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Total Marks</label>
          <input value={totalMarks} onChange={(e) => setTotalMarks(e.target.value)} type="number" placeholder="100" className="w-full px-4 py-2.5 rounded-xl border border-slate-200 bg-slate-50" />
        </div>
        <button onClick={loadRoster} className="w-full px-4 py-2.5 bg-slate-900 hover:bg-slate-800 text-white font-semibold rounded-xl transition flex justify-center items-center gap-2">
          <Upload size={18} /> Load Roster
        </button>
      </div>

      {students.length > 0 && (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden animate-fade-in">
          <div className="px-6 py-4 border-b border-slate-100 bg-amber-50/30 flex justify-between items-center">
            <h2 className="font-bold text-slate-800">Enter Student Marks</h2>
            <span className="text-sm font-medium text-slate-500">Students: {students.length}</span>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100 text-sm text-slate-500">
                  <th className="px-6 py-4 font-medium">Roll No</th>
                  <th className="px-6 py-4 font-medium">Student Name</th>
                  <th className="px-6 py-4 font-medium w-48">Marks Obtained</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {students.map((student) => (
                  <tr key={student._id} className="hover:bg-slate-50/50 transition">
                    <td className="px-6 py-4 font-medium text-slate-600">{student.rollNo}</td>
                    <td className="px-6 py-4 font-bold text-slate-800">{student.name}</td>
                    <td className="px-6 py-4">
                      <input type="number" value={student.marks} onChange={(e) => handleMarkChange(student._id, e.target.value)} className="w-full px-3 py-2 border rounded-lg outline-none transition border-slate-200 focus:border-amber-400" />
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="px-6 py-5 border-t border-slate-100 bg-slate-50 flex justify-end">
            <button onClick={publishResults} disabled={saving} className="px-8 py-3 bg-emerald-600 hover:bg-emerald-700 disabled:opacity-50 text-white font-bold rounded-xl transition flex items-center gap-2">
              <Save size={18} /> {saving ? "Publishing..." : "Publish Results"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default FacultyResults;

