import { AuthContext } from "../../context/AuthContext";

const API = "http://localhost:5001/api";
const DAYS = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];

const FacultyTimetable = () => {
  const { user } = useContext(AuthContext);
  const [weekSlots, setWeekSlots] = useState({});
  const [loading, setLoading] = useState(true);
  const [facultyId, setFacultyId] = useState(null);

  useEffect(() => {
    if (!user?.email) return;

    const load = async () => {
      try {
        // Get faculty profile to get _id
        const facRes = await axios.get(`${API}/faculty`);
        const faculty = facRes.data.find(
          (f) => f.email.toLowerCase() === user.email.toLowerCase()
        );

        if (!faculty) {
          toast.error("Faculty profile not found. Ask admin to add your profile.");
          setLoading(false);
          return;
        }

        setFacultyId(faculty._id);

        const { data } = await axios.get(`${API}/timetable/week?faculty=${faculty._id}`);
        setWeekSlots(data);
      } catch {
        toast.error("Failed to load timetable");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [user]);

  const totalSlots = Object.values(weekSlots).flat().length;

  if (loading)
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin w-8 h-8 border-4 border-amber-200 border-t-amber-500 rounded-full" />
      </div>
    );

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Teaching Timetable</h1>
        <p className="text-slate-500 mt-1">Your assigned lectures and sessions this week.</p>
      </header>

      {totalSlots === 0 ? (
        <div className="bg-amber-50 border border-amber-200 rounded-2xl p-6 text-center">
          <p className="font-bold text-amber-900">No timetable slots assigned yet.</p>
          <p className="text-sm text-amber-700 mt-1">Ask admin to create timetable slots and assign them to you.</p>
        </div>
      ) : (
        <div className="space-y-6">
          {DAYS.map((day) => {
            const slots = weekSlots[day] || [];
            if (slots.length === 0) return null;
            return (
              <div key={day} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="bg-amber-50/50 px-6 py-4 border-b border-amber-100 flex items-center justify-between">
                  <h2 className="text-lg font-bold text-amber-900">{day}</h2>
                  <span className="text-xs text-amber-600 font-bold">{slots.length} slot(s)</span>
                </div>
                <div className="divide-y divide-slate-100">
                  {slots.map((slot) => (
                    <div key={slot._id} className="p-6 flex flex-col md:flex-row md:items-center justify-between gap-4 hover:bg-slate-50 transition border-l-4 border-transparent hover:border-amber-400">
                      <div className="flex items-start gap-4">
                        <div className="bg-slate-100 text-slate-700 px-4 py-2 rounded-xl flex items-center gap-2 font-semibold text-sm whitespace-nowrap">
                          <Clock size={15} /> {slot.startTime} – {slot.endTime}
                        </div>
                        <div>
                          <h3 className="text-lg font-bold text-slate-800">{slot.subject}</h3>
                          <p className="text-indigo-600 font-semibold text-sm mt-1">
                            {slot.batch?.name || "—"}
                            {slot.batch?.course ? ` · ${slot.batch.course.name}` : ""}
                          </p>
                        </div>
                      </div>
                      <div className="flex items-center gap-2 text-slate-600 text-sm font-medium bg-white border border-slate-200 px-4 py-2 rounded-lg w-max shadow-sm">
                        <MapPin size={15} className="text-slate-400" /> {slot.room}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default FacultyTimetable;

