import { useState, useEffect, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { 
  Clock, ChevronLeft, ChevronRight, Send, 
  AlertTriangle, Flag, CheckCircle2, HelpCircle
} from "lucide-react";

export default function QuizPortal() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [quiz, setQuiz] = useState(null);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [answers, setAnswers] = useState({}); // { questionId: selectedOptionIndex }
  const [timeLeft, setTimeLeft] = useState(0);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  useEffect(() => {
    const fetchQuiz = async () => {
      try {
        const { data } = await axios.get(`/quizzes/${id}`);
        setQuiz(data);
        setTimeLeft(data.duration * 60);
      } catch {
        toast.error("Failed to load quiz");
        navigate("/student/quizzes");
      } finally {
        setLoading(false);
      }
    };
    fetchQuiz();
  }, [id, navigate]);

  const handleSubmit = useCallback(async () => {
    if (submitting) return;
    setSubmitting(true);

    try {
      const submission = {
        quizId: id,
        answers: Object.entries(answers).map(([qId, opt]) => ({
          questionId: qId,
          selectedOption: opt
        }))
      };

      await axios.post("/quizzes/submit", submission);
      toast.success("Quiz submitted successfully!");
      navigate("/student/quizzes");
    } catch {
      toast.error("Submission failed. Please contact admin.");
    } finally {
      setSubmitting(false);
    }
  }, [id, answers, navigate, submitting]);

  // Timer Logic
  useEffect(() => {
    if (timeLeft <= 0 && !loading && quiz) {
      toast.error("Time is up! Submitting your answers...");
      handleSubmit();
      return;
    }

    const timer = setInterval(() => {
      setTimeLeft(prev => prev - 1);
    }, 1000);

    return () => clearInterval(timer);
  }, [timeLeft, loading, quiz, handleSubmit]);

  const formatTime = (seconds) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s < 10 ? '0' : ''}${s}`;
  };

  const handleOptionSelect = (qId, optIndex) => {
    setAnswers(prev => ({ ...prev, [qId]: optIndex }));
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center text-white">
      <div className="animate-spin rounded-full h-12 w-12 border-4 border-indigo-500 border-t-transparent" />
    </div>
  );

  const question = quiz.questions[currentQuestion];
  const isLastQuestion = currentQuestion === quiz.questions.length - 1;

  return (
    <div className="min-h-screen bg-slate-50 font-sans flex flex-col">
      {/* Quiz Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-30">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 rounded-xl bg-indigo-900 flex items-center justify-center text-white font-black">S</div>
          <div>
            <h1 className="text-lg font-black text-slate-800 tracking-tight leading-none">{quiz.title}</h1>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mt-1">{quiz.subject}</p>
          </div>
        </div>

        <div className={`flex items-center gap-3 px-6 py-2.5 rounded-2xl border-2 transition-colors ${timeLeft < 60 ? 'bg-red-50 border-red-200 text-red-600 animate-pulse' : 'bg-slate-50 border-slate-100 text-slate-700'}`}>
          <Clock size={20} />
          <span className="text-xl font-black tabular-nums">{formatTime(timeLeft)}</span>
        </div>

        <button 
          onClick={() => setShowConfirm(true)}
          className="px-8 py-2.5 bg-indigo-600 text-white font-black rounded-2xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-600/20"
        >
          Finish Test
        </button>
      </header>

      <div className="flex-1 grid lg:grid-cols-[1fr_350px]">
        {/* Question Area */}
        <div className="p-8 lg:p-20 overflow-y-auto">
          <div className="max-w-3xl mx-auto space-y-12">
            <div className="flex items-start gap-6">
              <span className="w-12 h-12 rounded-2xl bg-indigo-900 text-white flex items-center justify-center font-black text-xl shrink-0">
                {currentQuestion + 1}
              </span>
              <div className="space-y-8 flex-1">
                <h2 className="text-2xl font-bold text-slate-800 leading-relaxed">
                  {question.questionText}
                </h2>

                <div className="grid gap-4">
                  {question.options.map((opt, i) => (
                    <button
                      key={i}
                      onClick={() => handleOptionSelect(question._id, i)}
                      className={`group flex items-center gap-4 p-6 rounded-3xl border-2 text-left transition-all duration-200 ${
                        answers[question._id] === i 
                        ? 'border-indigo-600 bg-indigo-50/50 shadow-md translate-x-2' 
                        : 'border-slate-100 bg-white hover:border-indigo-200 hover:bg-slate-50'
                      }`}
                    >
                      <span className={`w-8 h-8 rounded-full flex items-center justify-center font-black text-sm transition-colors ${
