                  Submit Final <Send size={18} />
                </button>
              ) : (
                <button
                  onClick={() => setCurrentQuestion(prev => prev + 1)}
                  className="flex items-center gap-2 px-8 py-3 bg-slate-800 text-white font-bold rounded-2xl hover:bg-slate-900 transition shadow-lg"
