              {quiz.questions.map((q, i) => (
                <button
                  key={i}
                  onClick={() => setCurrentQuestion(i)}
                  className={`aspect-square rounded-xl flex items-center justify-center font-black text-sm transition-all ${
                    currentQuestion === i ? 'ring-2 ring-indigo-600 ring-offset-2' : ''
                  } ${
                    answers[q._id] !== undefined ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/30' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'
