import { useEffect, useState, useContext } from "react";
import axios from "../../utils/axiosInstance";
import { AuthContext } from "../../context/AuthContext";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid,
  Tooltip, ResponsiveContainer, Cell,
} from "recharts";
import AttendanceHeatmap from "../../components/student/AttendanceHeatmap";

const API = "http://localhost:5001/api";

const StudentAttendance = () => {
  const { user } = useContext(AuthContext);
  const [data, setData] = useState(null);
  const [heatmapData, setHeatmapData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (!user?.email) return;
    setLoading(true);
    setError(null);
    Promise.all([
      axios.get(`/attendance/student?studentEmail=${encodeURIComponent(user.email)}`),
      axios.get(`/attendance/heatmap?studentEmail=${encodeURIComponent(user.email)}`)
    ])
    .then(([{ data: mainData }, { data: heatData }]) => {
      setData(mainData);
      setHeatmapData(heatData);
    })
    .catch((err) => {
      const msg = err.response?.data?.message || "Failed to load attendance";
      setError(msg);
      setData({ percentage: 0, totalPresent: 0, totalAbsent: 0, logs: [], monthlyData: [] });
    })
    .finally(() => setLoading(false));
  }, [user]);

  if (loading)
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin w-8 h-8 border-4 border-blue-200 border-t-blue-600 rounded-full" />
      </div>
    );

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Attendance & Discipline</h1>
        <p className="text-slate-500 mt-1">Track your presence across all enrolled batches.</p>
      </header>

      {/* Error banner */}
      {error && (
        <div className="bg-red-50 border border-red-200 rounded-2xl p-4 text-sm text-red-700 font-medium">
          ⚠️ {error}
        </div>
      )}

      {/* No data yet */}
      {!error && data?.logs?.length === 0 && (
        <div className="bg-amber-50 border border-amber-200 rounded-2xl p-4 text-sm text-amber-700 font-medium">
          No attendance records found yet. Your faculty hasn't marked attendance for your batch, or you haven't been added to a batch.
        </div>
      )}

      <div className="grid lg:grid-cols-3 gap-6">
        {/* Overall circle */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-center items-center text-center">
          <div className="w-32 h-32 relative mb-4">
            <svg className="w-full h-full transform -rotate-90" viewBox="0 0 36 36">
              <path
                className="text-slate-100"
                strokeWidth="3" stroke="currentColor" fill="none"
                d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
              />
              <path
                className={
                  (data?.percentage ?? 0) >= 75
                    ? "text-green-500"
                    : (data?.percentage ?? 0) >= 50
                    ? "text-amber-500"
                    : "text-red-500"
                }
                strokeDasharray={`${data?.percentage ?? 0}, 100`}
                strokeWidth="3" stroke="currentColor" fill="none" strokeLinecap="round"
                d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"
              />
            </svg>
            <div className="absolute inset-0 flex items-center justify-center">
              <span className="text-3xl font-bold text-slate-800">{data?.percentage ?? 0}%</span>
            </div>
          </div>
          <h2 className="font-bold text-slate-800 text-lg">Overall Attendance</h2>
          <p className="text-sm text-slate-500 mt-1">
            {data?.totalPresent ?? 0} Present &bull; {data?.totalAbsent ?? 0} Absent
          </p>
          <div className={`mt-3 px-3 py-1 rounded-full text-xs font-bold ${
            (data?.percentage ?? 0) >= 75
              ? "bg-green-100 text-green-700"
              : (data?.percentage ?? 0) >= 50
              ? "bg-amber-100 text-amber-700"
              : "bg-red-100 text-red-700"
          }`}>
            {(data?.percentage ?? 0) >= 75 ? "Good Standing" : (data?.percentage ?? 0) >= 50 ? "Needs Improvement" : "Critical — Below 50%"}
          </div>
        </div>

        {/* Monthly bar chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h2 className="text-lg font-bold text-slate-800 mb-6">Monthly Breakdown</h2>
          {!data?.monthlyData?.length ? (
            <div className="flex items-center justify-center h-48 text-slate-400 text-sm">
              No monthly data yet.
            </div>
          ) : (
            <div className="h-56">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data.monthlyData} barCategoryGap="30%">
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: "#64748b", fontSize: 12 }} />
                  <YAxis axisLine={false} tickLine={false} tick={{ fill: "#64748b", fontSize: 12 }} domain={[0, 100]} tickFormatter={(v) => `${v}%`} />
                  <Tooltip
                    cursor={{ fill: "#f8fafc" }}
                    formatter={(v) => [`${v}%`, "Attendance"]}
                    contentStyle={{ borderRadius: "12px", border: "none", boxShadow: "0 4px 6px -1px rgb(0 0 0 / 0.1)" }}
                  />
                  <Bar dataKey="percentage" radius={[6, 6, 0, 0]}>
                    {data.monthlyData.map((entry, i) => (
                      <Cell
                        key={i}
                        fill={entry.percentage >= 75 ? "#10b981" : entry.percentage >= 50 ? "#f59e0b" : "#ef4444"}
                      />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          )}
        </div>
      </div>

      {/* Heatmap Section */}
      <AttendanceHeatmap data={heatmapData} />

      {/* Recent logs */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="px-6 py-5 border-b border-slate-100 flex items-center justify-between">
          <h2 className="text-lg font-bold text-slate-800">Recent Logs</h2>
          <span className="text-xs text-slate-400 font-medium">{data?.logs?.length ?? 0} records</span>
        </div>
        {!data?.logs?.length ? (
          <div className="text-center py-16 text-slate-400 text-sm">No attendance logs yet.</div>
        ) : (
          <div className="divide-y divide-slate-100">
            {data.logs.map((log, i) => (
              <div key={i} className="flex items-center justify-between px-6 py-4 hover:bg-slate-50 transition">
                <div className="flex items-center gap-4">
                  <div className={`w-2.5 h-2.5 rounded-full flex-shrink-0 ${log.status === "present" ? "bg-green-500" : "bg-red-500"}`} />
                  <div>
                    <p className="font-semibold text-slate-800 text-sm">
                      {new Date(log.date).toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" })}
                    </p>
                    <p className="text-xs text-slate-500 mt-0.5">{log.batch}</p>
                  </div>
                </div>
                <span className={`px-3 py-1 rounded-full text-xs font-bold capitalize ${
                  log.status === "present" ? "bg-green-100 text-green-700" : "bg-red-100 text-red-700"
                }`}>
                  {log.status}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default StudentAttendance;

