import { useContext, useEffect, useState } from "react";
import { AuthContext } from "../../context/AuthContext";
import { Users, CheckCircle, AlertCircle, FileText, Clock } from "lucide-react";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import axios from "../../utils/axiosInstance";
import AttendanceHeatmap from "../../components/student/AttendanceHeatmap";
import ReportTemplate from "../../components/common/ReportTemplate";
import { useRef } from "react";
import jsPDF from "jspdf";
import html2canvas from "html2canvas";
import toast from "react-hot-toast";

const API_URL = "http://localhost:5001/api";

const StudentDashboard = () => {
  const { user, loading: authLoading } = useContext(AuthContext);
  const [data, setData] = useState(null);
  const [heatmapData, setHeatmapData] = useState([]);
  const [dataLoading, setDataLoading] = useState(true);
  const [downloading, setDownloading] = useState(false);
  const reportRef = useRef();

  useEffect(() => {
    const fetchDashboard = async () => {
      if (!user?.token) return;

      try {
        const [{ data: resData }, { data: heatData }] = await Promise.all([
          axios.get("/students/panel/dashboard"),
          axios.get(`/attendance/heatmap?studentEmail=${encodeURIComponent(user.email)}`)
        ]);
        setData(resData);
        setHeatmapData(heatData);
      } catch (error) {
        console.error("Failed to fetch dashboard data:", error);
        toast.error(error.response?.data?.message || "Failed to load dashboard data");
      } finally {
        setDataLoading(false);
      }
    };

    if (!authLoading) {
      if (user) {
        fetchDashboard();
      } else {
        setDataLoading(false);
      }
    }
  }, [user, authLoading]);

  const handleDownloadReport = async () => {
    if (!reportRef.current) return;
    setDownloading(true);
    const toastId = toast.loading("Generating professional report...");

    try {
      const element = reportRef.current;
      const canvas = await html2canvas(element, {
        scale: 2,
        useCORS: true,
        logging: false,
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const imgWidth = 210;
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      pdf.addImage(imgData, 'PNG', 0, 0, imgWidth, imgHeight);
      pdf.save(`${user?.name || 'Student'}_Progress_Report.pdf`);
      toast.success("Report downloaded successfully!", { id: toastId });
    } catch (error) {
      console.error("PDF Error:", error);
      toast.error("Failed to generate report", { id: toastId });
    } finally {
      setDownloading(false);
    }
  };


  if (authLoading || dataLoading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="h-10 w-10 animate-spin rounded-full border-4 border-blue-900 border-t-transparent"></div>
      </div>
    );
  }

  if (!data) {
    return (
      <div className="text-center py-20 bg-white rounded-2xl border border-slate-100">
        <p className="text-slate-500">Could not load dashboard data. Please make sure your student profile is linked.</p>
      </div>
    );
  }

  const { summary, notices, chartData } = data;

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Overview</h1>
          <p className="text-slate-500 mt-1">Welcome back, {user?.name || "Student"}! Here is your academic summary.</p>
        </div>
        <button
          onClick={handleDownloadReport}
          disabled={downloading}
          className="flex items-center gap-2 px-6 py-3 bg-white text-indigo-900 border-2 border-indigo-100 font-bold rounded-2xl hover:bg-indigo-50 transition shadow-sm disabled:opacity-50"
        >
          <FileText size={20} /> {downloading ? 'Preparing...' : 'Download Progress Report'}
        </button>
      </header>

      {/* Hidden Report Template */}
      <ReportTemplate 
        ref={reportRef} 
        student={user} 
        data={data} 
        heatmapData={heatmapData} 
      />

      {/* KPI Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition">
          <div className="flex justify-between items-start mb-4">
            <div className="w-12 h-12 rounded-xl bg-green-50 text-green-600 flex items-center justify-center">
              <CheckCircle size={24} />
            </div>
            <span className={`text-xs font-semibold px-2 py-1 rounded-full ${summary.attendancePercentage >= 75 ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
              {summary.attendancePercentage >= 75 ? 'Good' : 'Low'}
            </span>
          </div>
          <div>
            <h3 className="text-slate-500 text-sm font-medium mb-1">Overall Attendance</h3>
            <p className="text-3xl font-bold text-slate-800">{summary.attendancePercentage}%</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition">
          <div className="flex justify-between items-start mb-4">
            <div className="w-12 h-12 rounded-xl bg-orange-50 text-orange-600 flex items-center justify-center">
              <AlertCircle size={24} />
            </div>
            <span className="text-xs font-semibold px-2 py-1 bg-orange-100 text-orange-700 rounded-full">
              {summary.feesDue > 0 ? 'Pending' : 'Clear'}
            </span>
          </div>
          <div>
            <h3 className="text-slate-500 text-sm font-medium mb-1">Fees Status</h3>
            <p className="text-3xl font-bold text-slate-800">₹{summary.feesDue.toLocaleString()}</p>
            <p className="text-xs text-slate-400 mt-1">{summary.feesDue > 0 ? 'Balance amount' : 'No dues'}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition">
          <div className="flex justify-between items-start mb-4">
            <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center">
              <FileText size={24} />
            </div>
          </div>
          <div>
            <h3 className="text-slate-500 text-sm font-medium mb-1">Latest Test Score</h3>
            {summary.latestScore ? (
              <>
                <p className="text-3xl font-bold text-slate-800">
                  {summary.latestScore.marks}<span className="text-lg text-slate-400">/{summary.latestScore.totalMarks}</span>
                </p>
                <p className="text-xs text-blue-600 font-medium mt-1 truncate">{summary.latestScore.testName}</p>
              </>
            ) : (
              <p className="text-xl font-bold text-slate-400 mt-2">No tests yet</p>
            )}
          </div>
        </div>

        <div className="bg-gradient-to-br from-indigo-600 to-blue-700 p-6 rounded-2xl shadow-sm text-white flex flex-col justify-between relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl transform translate-x-1/2 -translate-y-1/2"></div>
          <div className="relative z-10">
            <h3 className="text-indigo-100 font-medium mb-4 flex items-center gap-2">
              <Clock size={16} /> Next Class
            </h3>
            {summary.nextClass ? (
              <>
                <p className="text-2xl font-bold mb-1 truncate">{summary.nextClass.startTime}</p>
                <p className="text-sm font-medium text-indigo-200 mb-4">{summary.nextClass.subject} • {summary.nextClass.room}</p>
              </>
            ) : (
              <p className="text-xl font-bold mb-5">No classes today</p>
            )}
            <button 
              onClick={() => window.location.href = '/student/timetable'}
              className="w-full py-2 bg-white/20 hover:bg-white/30 transition rounded-lg text-sm font-semibold backdrop-blur-sm border border-white/10"
            >
              View Timetable
            </button>
          </div>
        </div>
      </div>

      {/* Attendance Heatmap */}
      <AttendanceHeatmap data={heatmapData} />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mt-8">
        {/* Chart Section */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-bold text-slate-800">Recent Attendance Activity</h2>
          </div>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8'}} domain={[0, 100]} ticks={[0, 50, 100]} />
                <Tooltip 
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                  formatter={(value) => [value === 100 ? 'Present' : 'Absent', 'Status']}
                />
                <Line type="monotone" dataKey="present" stroke="#4f46e5" strokeWidth={4} dot={{r: 6, fill: '#4f46e5', strokeWidth: 2, stroke: '#fff'}} activeDot={{r: 8}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Notices Section */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h2 className="text-lg font-bold text-slate-800 mb-6">Recent Notices</h2>
          <div className="space-y-4">
            {notices.length === 0 ? (
              <p className="text-sm text-slate-400 text-center py-10">No recent notices</p>
            ) : (
              notices.map((notice) => (
                <div key={notice._id} className={`p-4 rounded-xl border relative overflow-hidden group ${notice.priority === 'high' ? 'border-red-100 bg-red-50/50' : 'border-blue-100 bg-blue-50/50'}`}>
                  <div className={`absolute left-0 top-0 bottom-0 w-1 ${notice.priority === 'high' ? 'bg-red-500' : 'bg-blue-500'}`}></div>
                  <h3 className="font-semibold text-slate-800 text-sm mb-1 truncate">{notice.title}</h3>
                  <p className="text-xs text-slate-500 mb-2 line-clamp-2">{notice.content}</p>
                  <span className={`text-[10px] font-medium px-2 py-0.5 rounded-md ${notice.priority === 'high' ? 'text-red-600 bg-red-100' : 'text-blue-600 bg-blue-100'}`}>
                    {notice.postedBy}
                  </span>
                </div>
              ))
            )}
          </div>
          {notices.length > 0 && (
            <button 
              onClick={() => window.location.href = '/student/notices'}
              className="w-full mt-4 py-2 text-sm text-indigo-600 font-semibold hover:bg-indigo-50 rounded-lg transition"
            >
              View All Notices
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default StudentDashboard;

