import { useState, useEffect } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { 
  BookOpen, Download, Search, FileText, File, Image, 
  Filter, ChevronDown, BookMarked
} from "lucide-react";

// API base URL is handled by axiosInstance

const getFileIcon = (type) => {
  const t = (type || "").toLowerCase();
  if (["jpg","jpeg","png","gif","webp","svg"].includes(t)) return <Image size={22} className="text-pink-400" />;
  if (["ppt","pptx"].includes(t)) return <File size={22} className="text-orange-400" />;
  if (["pdf"].includes(t)) return <FileText size={22} className="text-red-400" />;
  return <File size={22} className="text-indigo-400" />;
};

const formatSize = (bytes) => {
  if (!bytes) return "—";
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
};

export default function StudentMaterials() {
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filterSubject, setFilterSubject] = useState("");



  const fetchMaterials = async () => {
    try {
      const params = {};
      if (search) params.search = search;
      if (filterSubject) params.subject = filterSubject;
      const { data } = await axios.get("/materials", { params });
      setMaterials(data);
    } catch {
      toast.error("Failed to load materials");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchMaterials(); }, [search, filterSubject]);

  const subjects = [...new Set(materials.map((m) => m.subject).filter(Boolean))];

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="bg-gradient-to-r from-indigo-900 to-indigo-700 rounded-2xl p-6 text-white">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 rounded-2xl bg-white/10 backdrop-blur flex items-center justify-center">
            <BookMarked size={28} />
          </div>
          <div>
            <h1 className="text-2xl font-black">Study Materials</h1>
            <p className="text-indigo-200 text-sm mt-0.5">Browse and download resources shared by your faculty</p>
          </div>
        </div>
        <div className="grid grid-cols-3 gap-4 mt-6">
          <div className="bg-white/10 rounded-xl p-3 text-center">
            <p className="text-2xl font-black">{materials.length}</p>
            <p className="text-indigo-200 text-xs font-semibold mt-0.5">Total Files</p>
          </div>
          <div className="bg-white/10 rounded-xl p-3 text-center">
            <p className="text-2xl font-black">{subjects.length}</p>
            <p className="text-indigo-200 text-xs font-semibold mt-0.5">Subjects</p>
          </div>
          <div className="bg-white/10 rounded-xl p-3 text-center">
            <p className="text-2xl font-black">{materials.filter(m => m.fileType === "pdf").length}</p>
            <p className="text-indigo-200 text-xs font-semibold mt-0.5">PDFs</p>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-3">
        <div className="relative flex-1">
          <Search size={16} className="absolute left-3.5 top-3 text-slate-400" />
          <input
            type="text"
            placeholder="Search by title, subject, or description..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600/20 focus:border-indigo-600 bg-white"
          />
        </div>
        {subjects.length > 0 && (
          <div className="relative">
            <Filter size={14} className="absolute left-3.5 top-3.5 text-slate-400" />
            <select
              value={filterSubject}
              onChange={(e) => setFilterSubject(e.target.value)}
              className="pl-10 pr-8 py-2.5 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-600/20 focus:border-indigo-600 bg-white appearance-none"
            >
              <option value="">All Subjects</option>
              {subjects.map((s) => <option key={s} value={s}>{s}</option>)}
            </select>
            <ChevronDown size={14} className="absolute right-3 top-3.5 text-slate-400 pointer-events-none" />
          </div>
        )}
      </div>

      {/* Materials */}
      {loading ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {[1,2,3,4,5,6].map(i => (
            <div key={i} className="bg-white rounded-2xl border border-slate-100 p-5 animate-pulse">
              <div className="flex gap-3 mb-3">
                <div className="w-12 h-12 bg-slate-100 rounded-xl" />
                <div className="flex-1"><div className="h-4 bg-slate-100 rounded w-3/4 mb-2" /><div className="h-3 bg-slate-100 rounded w-1/2" /></div>
              </div>
              <div className="h-3 bg-slate-100 rounded w-full mt-3" />
              <div className="h-8 bg-slate-100 rounded-lg mt-4" />
            </div>
          ))}
        </div>
      ) : materials.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border border-slate-100">
          <BookOpen size={56} className="mx-auto text-slate-200 mb-4" />
          <p className="text-slate-500 font-bold text-lg">No materials yet</p>
          <p className="text-slate-400 text-sm mt-1">Your faculty hasn't uploaded any study materials yet</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {materials.map((mat) => (
            <div
              key={mat._id}
              className="bg-white rounded-2xl border border-slate-100 shadow-sm hover:shadow-lg hover:-translate-y-0.5 transition-all duration-200 p-5 flex flex-col gap-3"
            >
              {/* File Icon & Title */}
              <div className="flex items-start gap-3">
                <div className="w-12 h-12 rounded-xl bg-indigo-50 flex items-center justify-center flex-shrink-0">
                  {getFileIcon(mat.fileType)}
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="font-bold text-slate-800 text-sm leading-snug line-clamp-2">{mat.title}</h3>
                  {mat.subject && (
                    <span className="inline-block text-[10px] font-bold text-indigo-700 bg-indigo-50 px-2 py-0.5 rounded-full mt-1">
                      {mat.subject}
                    </span>
                  )}
                </div>
                <span className="text-[10px] font-black uppercase px-2 py-1 rounded-lg bg-slate-100 text-slate-500 flex-shrink-0">
                  {mat.fileType}
                </span>
              </div>

              {/* Description */}
              {mat.description && (
                <p className="text-xs text-slate-500 leading-relaxed line-clamp-2">{mat.description}</p>
              )}

              {/* Meta Tags */}
              <div className="flex flex-wrap gap-1.5 text-[10px] text-slate-500 font-semibold">
                {mat.course && <span className="bg-slate-50 border border-slate-100 px-2 py-0.5 rounded-full">📚 {mat.course}</span>}
                {mat.batch && <span className="bg-slate-50 border border-slate-100 px-2 py-0.5 rounded-full">👥 {mat.batch}</span>}
                <span className="bg-slate-50 border border-slate-100 px-2 py-0.5 rounded-full">{formatSize(mat.fileSize)}</span>
              </div>

              {/* Footer */}
              <div className="pt-3 border-t border-slate-50 flex items-center justify-between gap-3 mt-auto">
                <div>
                  <p className="text-[10px] text-slate-400 leading-none">Uploaded by</p>
                  <p className="text-xs font-bold text-slate-600 mt-0.5">{mat.uploaderName}</p>
                  <p className="text-[10px] text-slate-400">{new Date(mat.createdAt).toLocaleDateString("en-IN", { day:"numeric", month:"short", year:"numeric" })}</p>
                </div>
                <a
                  href={`http://localhost:5001${mat.fileUrl}`}
                  download={mat.fileName}
                  target="_blank"
                  rel="noreferrer"
                  className="flex items-center gap-2 px-4 py-2 rounded-xl bg-indigo-600 text-white text-xs font-bold hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-600/20 flex-shrink-0"
                >
                  <Download size={14} />
                  Download
                </a>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

