              {/* Meta Tags */}
              <div className="flex flex-wrap gap-1.5 text-[10px] text-slate-500 font-semibold">
                {mat.course && <span className="bg-slate-50 border border-slate-100 px-2 py-0.5 rounded-full">📚 {mat.course}</span>}
                {mat.batch && <span className="bg-slate-50 border border-slate-100 px-2 py-0.5 rounded-full">👥 {mat.batch}</span>}
                <span className="bg-slate-50 border border-slate-100 px-2 py-0.5 rounded-full">{formatSize(mat.fileSize)}</span>
              </div>

              {/* Footer */}
              <div className="pt-3 border-t border-slate-50 flex items-center justify-between gap-3 mt-auto">
                <div>
                  <p className="text-[10px] text-slate-400 leading-none">Uploaded by</p>
                  <p className="text-xs font-bold text-slate-600 mt-0.5">{mat.uploaderName}</p>
