import { useEffect, useState } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Bell, Megaphone } from "lucide-react";

const API = "http://localhost:5001/api";

const formatDate = (value) =>
  new Date(value).toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });

const StudentNotices = () => {
  const [notices, setNotices] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get(`${API}/notices?audience=students`)
      .then(({ data }) => setNotices(data))
      .catch((error) => toast.error(error.response?.data?.message || "Failed to load notices"))
      .finally(() => setLoading(false));
  }, []);

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Notices & Announcements</h1>
        <p className="text-slate-500 mt-1">Stay updated with the latest from the institute.</p>
      </header>

      <div className="space-y-4 max-w-4xl">
        {loading ? (
          <div className="text-center py-16 text-slate-400 bg-white rounded-2xl border border-slate-100">Loading...</div>
        ) : notices.length === 0 ? (
          <div className="text-center py-16 text-slate-400 bg-white rounded-2xl border border-slate-100">No notices for students yet.</div>
        ) : (
          notices.map((notice) => (
            <div key={notice._id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden">
              <div className={`absolute top-0 left-0 w-1.5 h-full ${notice.priority === "high" ? "bg-red-500" : "bg-blue-500"}`} />
              <div className="flex gap-4">
                <div className="w-12 h-12 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center shrink-0">
                  {notice.priority === "high" ? <Bell size={24} /> : <Megaphone size={24} />}
                </div>
                <div>
                  <div className="flex flex-wrap items-center gap-3 mb-1">
                    <h3 className="text-lg font-bold text-slate-800">{notice.title}</h3>
                    <span className="text-[10px] font-bold tracking-wider uppercase text-blue-600 bg-blue-100 px-2 py-0.5 rounded-full">
                      Admin Notice
                    </span>
                    {notice.priority === "high" && (
                      <span className="text-[10px] font-bold tracking-wider uppercase text-red-600 bg-red-100 px-2 py-0.5 rounded-full">High</span>
                    )}
                  </div>
                  <p className="text-sm text-slate-400 mb-3">Posted on {formatDate(notice.createdAt)}</p>
                  <p className="text-slate-600 leading-relaxed">{notice.content}</p>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default StudentNotices;

