import { useState, useEffect } from "react";
import axios from "../../utils/axiosInstance";
import toast from "react-hot-toast";
import { 
  ClipboardList, Play, CheckCircle2, Clock, BookOpen, 
  ChevronRight, Award, AlertCircle
} from "lucide-react";
import { useNavigate } from "react-router-dom";

export default function StudentQuizzes() {
  const [quizzes, setQuizzes] = useState([]);
  const [attempts, setAttempts] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [quizRes, attemptRes] = await Promise.all([
          axios.get("/quizzes"),
          axios.get("/quizzes/my/attempts")
        ]);
        setQuizzes(quizRes.data);
        setAttempts(attemptRes.data);
      } catch {
        toast.error("Failed to load assessments");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  const hasAttempted = (quizId) => attempts.some(a => a.quiz?._id === quizId || a.quiz === quizId);
  const getAttempt = (quizId) => attempts.find(a => a.quiz?._id === quizId || a.quiz === quizId);

  return (
    <div className="space-y-10 animate-fade-in pb-20">
      <header>
        <h1 className="text-4xl font-black text-slate-800 tracking-tight">Assessments</h1>
        <p className="text-slate-500 mt-2 font-medium text-lg">Test your knowledge with mock exams and quizzes.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-[1fr_350px] gap-10">
        <div className="space-y-6">
          <h2 className="text-xl font-bold text-slate-700 flex items-center gap-2">
            <Play size={20} className="text-indigo-600" /> Active Assessments
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {loading ? (
              [1,2].map(i => <div key={i} className="h-48 bg-white rounded-3xl animate-pulse border border-slate-100" />)
            ) : quizzes.filter(q => q.status === 'published').length === 0 ? (
              <div className="md:col-span-2 py-16 bg-white rounded-3xl border border-slate-100 text-center">
                <ClipboardList size={48} className="mx-auto text-slate-200 mb-4" />
                <p className="text-slate-400 font-bold">No active quizzes at the moment.</p>
              </div>
            ) : quizzes.filter(q => q.status === 'published').map((quiz) => {
              const attempted = hasAttempted(quiz._id);
              const attempt = getAttempt(quiz._id);

              return (
                <div key={quiz._id} className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 group">
                  <div className="flex justify-between items-start mb-6">
                    <div className="w-14 h-14 rounded-2xl bg-indigo-50 text-indigo-600 flex items-center justify-center">
                      <BookOpen size={28} />
                    </div>
                    {attempted && (
                      <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-1">
                        <CheckCircle2 size={12} /> Completed
                      </span>
                    )}
                  </div>

                  <h3 className="text-xl font-black text-slate-800 line-clamp-1">{quiz.title}</h3>
                  <p className="text-sm font-bold text-indigo-600 uppercase tracking-widest mt-1">{quiz.subject}</p>

                  <div className="flex items-center gap-6 mt-8 py-4 border-y border-slate-50">
                    <div className="space-y-1">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Duration</p>
                      <p className="text-sm font-bold text-slate-700 flex items-center gap-1.5"><Clock size={14} className="text-slate-400" /> {quiz.duration}m</p>
                    </div>
                    <div className="space-y-1">
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Questions</p>
                      <p className="text-sm font-bold text-slate-700 flex items-center gap-1.5"><ClipboardList size={14} className="text-slate-400" /> {quiz.questions?.length}</p>
                    </div>
                  </div>

                  <div className="mt-8 flex items-center justify-between">
                    {attempted ? (
                      <div className="text-left">
                        <p className="text-[10px] font-black text-slate-400 uppercase">Score</p>
                        <p className="text-lg font-black text-indigo-600">{attempt.score} <span className="text-sm text-slate-400">/ {quiz.totalMarks}</span></p>
                      </div>
                    ) : (
                      <div className="text-left">
                        <p className="text-[10px] font-black text-slate-400 uppercase">Total Marks</p>
                        <p className="text-lg font-black text-slate-800">{quiz.totalMarks}</p>
                      </div>
                    )}

                    {attempted ? (
                      <button 
                        onClick={() => toast.success("Review feature coming soon!")}
                        className="p-3 rounded-2xl bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 transition"
                      >
                        <Award size={20} />
                      </button>
                    ) : (
                      <button 
                        onClick={() => navigate(`/student/quizzes/${quiz._id}`)}
                        className="flex items-center gap-2 px-6 py-3 bg-indigo-600 text-white font-bold rounded-2xl hover:bg-indigo-700 transition shadow-lg shadow-indigo-600/20"
                      >
                        Start Test <ChevronRight size={18} />
                      </button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Sidebar stats/past */}
        <div className="space-y-8">
          <div className="bg-indigo-900 rounded-[2.5rem] p-8 text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl transform translate-x-1/2 -translate-y-1/2" />
            <h3 className="text-xl font-bold mb-6">Performance</h3>
            <div className="space-y-6">
              <div>
                <p className="text-xs font-bold text-indigo-300 uppercase tracking-widest mb-2">Quizzes Attempted</p>
                <p className="text-4xl font-black">{attempts.length}</p>
              </div>
              <div className="flex gap-4">
                <div className="flex-1 p-4 bg-white/10 rounded-2xl border border-white/5">
                  <p className="text-[10px] font-bold text-indigo-200 uppercase">Avg Score</p>
                  <p className="text-lg font-black">
                    {attempts.length ? Math.round(attempts.reduce((a,b) => a + (b.score/ (b.quiz?.totalMarks || 1)), 0) / attempts.length * 100) : 0}%
                  </p>
                </div>
                <div className="flex-1 p-4 bg-white/10 rounded-2xl border border-white/5">
                  <p className="text-[10px] font-bold text-indigo-200 uppercase">Accuracy</p>
                  <p className="text-lg font-black">
                    {attempts.length ? Math.round(attempts.reduce((a,b) => a + (b.totalCorrect / (b.totalCorrect + b.totalWrong || 1)), 0) / attempts.length * 100) : 0}%
                  </p>
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-[2.5rem] p-8 border border-slate-100 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-6">Recent Attempts</h3>
            <div className="space-y-4">
              {attempts.slice(0, 5).map((att) => (
                <div key={att._id} className="flex items-center gap-4 group">
                  <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition">
                    <CheckCircle2 size={18} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-slate-800 truncate">{att.quiz?.title || "Deleted Quiz"}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{new Date(att.completedAt).toLocaleDateString()}</p>
                  </div>
                  <p className="text-sm font-black text-indigo-600">{att.score}</p>
                </div>
              ))}
              {attempts.length === 0 && <p className="text-sm text-slate-400 text-center py-4 italic">No attempts yet.</p>}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

