import { useContext, useEffect, useState } from "react";
import { AuthContext } from "../../context/AuthContext";
import axios from "axios";
import toast from "react-hot-toast";
import { Trophy, Download, Target, TrendingUp } from "lucide-react";
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, PolarRadiusAxis, ResponsiveContainer } from 'recharts';

const API_URL = "http://localhost:5001/api";

const StudentResults = () => {
  const { user, loading: authLoading } = useContext(AuthContext);
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchResults = async () => {
      if (!user?.token) {
        setLoading(false);
        return;
      }
      try {
        const { data } = await axios.get(`${API_URL}/students/panel/results`, {
          headers: { Authorization: `Bearer ${user.token}` }
        });
        setResults(data);
      } catch (error) {
        console.error("Failed to fetch results:", error);
        toast.error("Failed to load your results");
      } finally {
        setLoading(false);
      }
    };

    if (!authLoading) {
      if (user) fetchResults();
      else setLoading(false);
    }
  }, [user, authLoading]);


  // Calculate mastery for Radar Chart
  const masteryData = results.reduce((acc, curr) => {
    const subject = curr.subject || "Other";
    const existing = acc.find(s => s.subject === subject);
    if (existing) {
      existing.score = (existing.score + curr.percentage) / 2;
    } else {
      acc.push({ subject, score: curr.percentage, max: 100 });
    }
    return acc;
  }, []).slice(0, 5);

  const avgScore = results.length > 0 
    ? Math.round(results.reduce((sum, r) => sum + r.percentage, 0) / results.length) 
    : 0;

  const latestResult = results[0];

  if (loading || authLoading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="h-10 w-10 animate-spin rounded-full border-4 border-blue-900 border-t-transparent"></div>
      </div>
    );
