      </header>

      {results.length === 0 ? (
        <div className="text-center py-20 bg-white rounded-2xl border border-slate-100">
          <Trophy size={48} className="mx-auto text-slate-200 mb-4" />
          <p className="text-slate-500 font-medium">No test results published yet.</p>
        </div>
      ) : (
        <>
          <div className="grid lg:grid-cols-3 gap-6">
            {/* Radar Chart */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col items-center">
              <h2 className="text-lg font-bold text-slate-800 mb-2">Subject Mastery</h2>
              <div className="w-full h-64">
                {masteryData.length >= 3 ? (
                  <ResponsiveContainer width="100%" height="100%">
                    <RadarChart cx="50%" cy="50%" outerRadius="70%" data={masteryData}>
                      <PolarGrid stroke="#e2e8f0" />
                      <PolarAngleAxis dataKey="subject" tick={{fill: '#64748b', fontSize: 12}} />
                      <PolarRadiusAxis angle={30} domain={[0, 100]} tick={false} axisLine={false} />
                      <Radar name="Student" dataKey="score" stroke="#4f46e5" fill="#4f46e5" fillOpacity={0.4} />
                    </RadarChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="h-full flex items-center justify-center text-slate-400 text-sm text-center px-10">
                    Need results from at least 3 subjects to show mastery chart.
                  </div>
