                <Trophy className="absolute right-[-10px] bottom-[-10px] text-white/20 w-32 h-32" />
                <h3 className="text-orange-100 font-medium mb-2 relative z-10">Tests Attempted</h3>
                <p className="text-5xl font-bold relative z-10">{results.length}</p>
