                <div>
                  <p className="text-sm font-semibold text-blue-600 mb-1 uppercase tracking-wider">Latest Test</p>
                  <h3 className="text-xl font-bold text-slate-800">{latestResult.testName} ({latestResult.subject || "Mixed"})</h3>
