                    <th className="px-6 py-4 font-medium">Percentage</th>
                    <th className="px-6 py-4 font-medium">Faculty</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-sm">
                  {results.map((test) => (
                    <tr key={test._id} className="hover:bg-slate-50 transition">
                      <td className="px-6 py-4 font-bold text-slate-800">{test.testName}</td>
                      <td className="px-6 py-4 text-slate-600">{new Date(test.date).toLocaleDateString()}</td>
                      <td className="px-6 py-4 text-slate-600">{test.subject || "—"}</td>
