                      <td className="px-6 py-4">
                        <div className="flex items-center gap-2">
                          <div className="w-16 h-1.5 bg-slate-100 rounded-full overflow-hidden">
                            <div className="h-full bg-indigo-600" style={{ width: `${test.percentage}%` }}></div>
                          </div>
                          <span className="font-bold text-slate-800">{test.percentage}%</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-slate-600">{test.faculty}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default StudentResults;

