import { useEffect, useState, useContext } from "react";
import axios from "axios";
import toast from "react-hot-toast";
import { Clock, MapPin } from "lucide-react";
import { AuthContext } from "../../context/AuthContext";

const API = "http://localhost:5001/api";
const DAYS = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];

const StudentTimetable = () => {
  const { user } = useContext(AuthContext);
  const [weekSlots, setWeekSlots] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user?.email) return;

    const load = async () => {
      try {
        // Find student's batch via attendance batches endpoint (reuse existing)
        // We fetch all batches the student belongs to, then get timetable for those batches
        const Student = await axios.get(`${API}/courses/students/all`);
        const student = Student.data.find(
          (s) => s.email?.toLowerCase() === user.email.toLowerCase()
        );

        if (!student) {
          toast.error("Student profile not found.");
          setLoading(false);
          return;
        }

        // Get all batches that contain this student
        const batchRes = await axios.get(`${API}/courses/batches`);
        const myBatches = batchRes.data.filter((b) =>
          b.students?.some((s) => (s._id || s).toString() === student._id.toString())
        );

        if (myBatches.length === 0) {
          setLoading(false);
          return;
        }

        // Fetch timetable for each batch and merge
        const allSlots = [];
        for (const batch of myBatches) {
          const { data } = await axios.get(`${API}/timetable/week?batch=${batch._id}`);
          for (const day of DAYS) {
            if (data[day]) allSlots.push(...data[day]);
          }
        }

        // Group by day, deduplicate by _id
        const grouped = {};
        for (const day of DAYS) grouped[day] = [];
        const seen = new Set();
        for (const slot of allSlots) {
          if (!seen.has(slot._id)) {
            seen.add(slot._id);
            grouped[slot.day].push(slot);
          }
        }
        // Sort each day by startTime
        for (const day of DAYS) {
          grouped[day].sort((a, b) => a.startTime.localeCompare(b.startTime));
        }

        setWeekSlots(grouped);
      } catch {
        toast.error("Failed to load timetable");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [user]);

  const totalSlots = Object.values(weekSlots).flat().length;

  if (loading)
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin w-8 h-8 border-4 border-indigo-200 border-t-indigo-600 rounded-full" />
      </div>
    );

  return (
    <div className="space-y-6">
      <header className="mb-8">
        <h1 className="text-3xl font-bold text-slate-800">Timetable</h1>
        <p className="text-slate-500 mt-1">Your weekly lecture and session schedule.</p>
      </header>

      {totalSlots === 0 ? (
        <div className="bg-indigo-50 border border-indigo-200 rounded-2xl p-6 text-center">
          <p className="font-bold text-indigo-900">No timetable available yet.</p>
          <p className="text-sm text-indigo-700 mt-1">
            You haven't been added to a batch, or admin hasn't created timetable slots yet.
          </p>
        </div>
      ) : (
        <div className="space-y-6">
          {DAYS.map((day) => {
            const slots = weekSlots[day] || [];
            if (slots.length === 0) return null;
            return (
              <div key={day} className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
                <div className="bg-indigo-50/50 px-6 py-4 border-b border-indigo-100 flex items-center justify-between">
                  <h2 className="text-lg font-bold text-indigo-900">{day}</h2>
                  <span className="text-xs text-indigo-500 font-bold">{slots.length} class(es)</span>
                </div>
                <div className="divide-y divide-slate-100">
                  {slots.map((slot) => (
