const { Parser } = require("json2csv");
const Student = require("../models/Student");
const Faculty = require("../models/Faculty");
const Payment = require("../models/Payment");
const Attendance = require("../models/Attendance");
const Batch = require("../models/Batch");
const Setting = require("../models/Setting");

const getAdminStats = async (req, res) => {
  try {
    const [totalStudents, totalFaculty, payments, batches] = await Promise.all([
      Student.countDocuments(),
      Faculty.countDocuments(),
      Payment.find({ status: "Paid" }),
      Batch.find().sort({ createdAt: -1 }).limit(5).populate("course", "name"),
    ]);

    const totalFeesCollected = payments.reduce((acc, curr) => acc + curr.amount, 0);

    // Real avg attendance from last 30 days
    const since = new Date();
    since.setDate(since.getDate() - 30);
    const recentSessions = await Attendance.find({ date: { $gte: since } });

    let totalPresent = 0, totalRecords = 0;
    for (const session of recentSessions) {
      totalRecords += session.records.length;
      totalPresent += session.records.filter((r) => r.status === "present").length;
    }
    const avgAttendance = totalRecords > 0 ? Math.round((totalPresent / totalRecords) * 100) : 0;

    const monthlyGrowth = [];
    const now = new Date();
    for (let i = 5; i >= 0; i--) {
      const start = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const end = new Date(now.getFullYear(), now.getMonth() - i + 1, 0, 23, 59, 59, 999);
      const [students, feePayments] = await Promise.all([
        Student.countDocuments({ createdAt: { $lte: end } }),
        Payment.find({ status: "Paid", date: { $gte: start, $lte: end } }),
      ]);
      monthlyGrowth.push({
        month: start.toLocaleString("en", { month: "short" }),
        students,
        fees: feePayments.reduce((sum, payment) => sum + payment.amount, 0),
      });
    }

    const attendanceByDay = [];
    for (let i = 5; i >= 0; i--) {
      const day = new Date();
      day.setDate(day.getDate() - i);
      const start = new Date(day); start.setHours(0, 0, 0, 0);
      const end = new Date(day); end.setHours(23, 59, 59, 999);
      const sessions = await Attendance.find({ date: { $gte: start, $lte: end } });
      const total = sessions.reduce((sum, session) => sum + session.records.length, 0);
      const present = sessions.reduce((sum, session) => sum + session.records.filter((r) => r.status === "present").length, 0);
      attendanceByDay.push({
        day: start.toLocaleString("en", { weekday: "short" }),
        rate: total ? Math.round((present / total) * 100) : 0,
      });
    }

    const recentActivities = [
      ...batches.map((batch) => ({
        user: "Batch",
        action: `${batch.name}${batch.course?.name ? ` assigned to ${batch.course.name}` : " created"}`,
        time: new Date(batch.createdAt).toLocaleDateString("en-IN"),
        type: "info",
      })),
      ...recentSessions.slice(0, 5).map((session) => ({
        user: "Attendance",
        action: `Attendance marked for ${session.records.length} student(s)`,
        time: new Date(session.date).toLocaleDateString("en-IN"),
        type: "success",
      })),
    ].slice(0, 6);

    res.json({ totalStudents, totalFaculty, totalFeesCollected, avgAttendance, recentActivities, monthlyGrowth, attendanceByDay });
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

const getSettings = async (req, res) => {
  try {
    let settings = await Setting.findOne();
    if (!settings) {
      settings = await Setting.create({});
    }
    res.json(settings);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

const updateSettings = async (req, res) => {
  try {
    let settings = await Setting.findOne();
    if (!settings) {
      settings = new Setting(req.body);
    } else {
      Object.assign(settings, req.body);
    }
    await settings.save();
    res.json(settings);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

const downloadStudentsCSV = async (req, res) => {
  try {
    const students = await Student.find().lean();
    const fields = ["rollNo", "name", "email", "phone", "course", "batch", "gender"];
    const parser = new Parser({ fields });
    const csv = parser.parse(students);
    res.header("Content-Type", "text/csv");
    res.attachment("students.csv");
    res.send(csv);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

const downloadFeesCSV = async (req, res) => {
  try {
    const payments = await Payment.find().populate("student", "name rollNo").lean();
    const data = payments.map(p => ({
      Date: new Date(p.date).toLocaleDateString(),
      Student: p.student?.name,
      RollNo: p.student?.rollNo,
      Amount: p.amount,
      Method: p.method,
      Status: p.status
    }));
    const parser = new Parser();
    const csv = parser.parse(data);
    res.header("Content-Type", "text/csv");
    res.attachment("fee_records.csv");
    res.send(csv);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

const uploadLogo = async (req, res) => {
  try {
    if (!req.files || Object.keys(req.files).length === 0) {
      return res.status(400).json({ message: "No files were uploaded." });
    }
    const logo = req.files.logo;
    const uploadPath = `./uploads/logo_${Date.now()}_${logo.name}`;
    await logo.mv(uploadPath);

    let settings = await Setting.findOne();
    if (!settings) settings = new Setting();
    settings.logoUrl = uploadPath.replace("./", "/");
    await settings.save();

    res.json({ message: "Logo uploaded", logoUrl: settings.logoUrl });
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

module.exports = { getAdminStats, getSettings, updateSettings, downloadStudentsCSV, downloadFeesCSV, uploadLogo };

