const submitAttendance = async (req, res) => {
  try {
    const { batch, date, records, markedBy } = req.body;

    if (!batch || !date || !markedBy) {
      return res.status(400).json({ message: "batch, date, and markedBy are required" });
    }

    if (!Array.isArray(records) || records.length === 0) {
      return res.status(400).json({ message: "At least one attendance record is required" });
    }

    const [batchExists, facultyExists] = await Promise.all([
      Batch.findById(batch),
      Faculty.findById(markedBy),
    ]);

    if (!batchExists) return res.status(404).json({ message: "Selected batch was not found" });
    if (!facultyExists) return res.status(404).json({ message: "Selected faculty was not found" });

    const allowedStatuses = new Set(["present", "absent"]);
    const cleanedRecords = records.map((record) => ({
      student: record.student,
      status: record.status,
    }));

    if (cleanedRecords.some((record) => !record.student || !allowedStatuses.has(record.status))) {
      return res.status(400).json({ message: "Every student must be marked present or absent" });
    }

    const { start, end } = getDateRange(date);

    const existing = await Attendance.findOne({ batch, date: { $gte: start, $lte: end } });
    if (existing) {
      existing.records = cleanedRecords;
      existing.markedBy = markedBy;
      await existing.save();
      const populated = await existing.populate([
        { path: "batch", select: "name" },
        { path: "markedBy", select: "name" },
        { path: "records.student", select: "name rollNo email" },
      ]);
      return res.json(populated);
    }

    const attendance = await Attendance.create({ batch, date: start, records: cleanedRecords, markedBy });
    const populated = await attendance.populate([
      { path: "batch", select: "name course" }, // Added course for subject info
      { path: "markedBy", select: "name" },
      { path: "records.student", select: "name rollNo email parentPhone" }, // Added parentPhone
    ]);

    // TRIGGER SMS NOTIFICATIONS FOR ABSENTEES
    const absentees = populated.records.filter(r => r.status === 'absent');
    const subject = populated.batch?.course?.name || "Regular Lecture";

    absentees.forEach(async (record) => {
      if (record.student && record.student.parentPhone) {
        // Send SMS
        await sendSMSNotification(
          record.student.name,
          record.student.parentPhone,
          subject,
          populated.date
        );
      }
    });

    res.status(201).json(populated);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
};

