    if (!batch) return res.status(400).json({ message: "batch required" });

    const records = await Attendance.find({ batch }).populate("records.student", "name rollNo");

    const summary = {};
    for (const session of records) {
      for (const r of session.records) {
        if (!r.student) continue;
        const id = r.student._id.toString();
        if (!summary[id]) summary[id] = { student: r.student, present: 0, total: 0 };
        summary[id].total += 1;
        if (r.status === "present") summary[id].present += 1;
      }
    }

    const result = Object.values(summary).map((s) => ({
      ...s,
      percentage: s.total ? Math.round((s.present / s.total) * 100) : 0,
    }));

    res.json(result);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// GET /api/attendance/student?studentEmail=
const getStudentAttendance = async (req, res) => {
  try {
    const { studentEmail } = req.query;
    if (!studentEmail) return res.status(400).json({ message: "studentEmail required" });

    let student = await Student.findOne({ email: studentEmail });
    if (!student) {
      student = await Student.findOne({ email: new RegExp(`^${escapeRegex(studentEmail)}$`, "i") });
    }
    if (!student) return res.status(404).json({ message: "Student not found" });

    const studentId = student._id.toString();

    // Find all batches this student belongs to
    const batches = await Batch.find({ students: student._id });
    const batchIds = batches.map((b) => b._id);

    // All attendance sessions for this student. Include batch membership as a fallback
    // so older records still appear even if batch rosters were edited later.
    const sessions = await Attendance.find({
      $or: [
        { "records.student": student._id },
        { batch: { $in: batchIds } },
      ],
    })
      .populate("batch", "name")
      .sort({ date: -1 });

    let totalPresent = 0;
    let totalAbsent = 0;
    const logs = [];

    for (const session of sessions) {
      const rec = session.records.find((r) => r.student.toString() === studentId);
      if (rec) {
        if (rec.status === "present") totalPresent++;
        else totalAbsent++;
        logs.push({
          date: session.date,
          status: rec.status,
          batch: session.batch?.name || "Unknown",
        });
      }
    }

    const total = totalPresent + totalAbsent;
    const percentage = total ? Math.round((totalPresent / total) * 100) : 0;

    // Monthly breakdown — last 6 months
    const monthlyData = [];
    const now = new Date();
    for (let i = 5; i >= 0; i--) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const start = new Date(d.getFullYear(), d.getMonth(), 1);
      const end = new Date(d.getFullYear(), d.getMonth() + 1, 0, 23, 59, 59);

      const monthSessions = await Attendance.find({
        date: { $gte: start, $lte: end },
        $or: [
          { "records.student": student._id },
          { batch: { $in: batchIds } },
        ],
      });
      let mPresent = 0, mTotal = 0;
      for (const session of monthSessions) {
        const rec = session.records.find((r) => r.student.toString() === studentId);
        if (rec) { mTotal++; if (rec.status === "present") mPresent++; }
      }

      monthlyData.push({
        name: d.toLocaleString("en", { month: "short" }),
        percentage: mTotal ? Math.round((mPresent / mTotal) * 100) : 0,
      });
    }

    res.json({ percentage, totalPresent, totalAbsent, logs: logs.slice(0, 30), monthlyData });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// GET /api/attendance/admin/overview?date=&batch=
const getAdminOverview = async (req, res) => {
  try {
    const { date, batch } = req.query;
    const filter = {};

    if (date) {
      const { start, end } = getDateRange(date);
      filter.date = { $gte: start, $lte: end };
    }
    if (batch) filter.batch = batch;

    const records = await Attendance.find(filter)
      .populate("batch", "name")
      .populate("markedBy", "name")
      .sort({ date: -1 });

    const logs = records.map((r) => {
      const present = r.records.filter((rec) => rec.status === "present").length;
      const total = r.records.length;
      return {
        _id: r._id,
        batch: r.batch?.name || "Unknown",
        batchId: r.batch?._id,
        date: r.date,
        teacher: r.markedBy?.name || "Unknown",
        present,
        total,
      };
    });

    // Today's stats
    const today = new Date(); today.setHours(0, 0, 0, 0);
    const todayEnd = new Date(); todayEnd.setHours(23, 59, 59, 999);
    const todayRecords = await Attendance.find({ date: { $gte: today, $lte: todayEnd } });

    let todayPresent = 0, todayTotal = 0;
    for (const r of todayRecords) {
      todayTotal += r.records.length;
      todayPresent += r.records.filter((rec) => rec.status === "present").length;
    }

    res.json({
      logs,
      todayPercentage: todayTotal ? Math.round((todayPresent / todayTotal) * 100) : 0,
      todayAbsent: todayTotal - todayPresent,
    });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// GET /api/attendance/admin/low
const getLowAttendance = async (req, res) => {
  try {
    const batches = await Batch.find().populate("students", "name rollNo");
    const lowStudents = [];

    for (const batch of batches) {
      const sessions = await Attendance.find({ batch: batch._id });
      for (const student of batch.students) {
        let present = 0, total = 0;
        for (const session of sessions) {
          const rec = session.records.find((r) => r.student.toString() === student._id.toString());
          if (rec) { total++; if (rec.status === "present") present++; }
        }
        if (total > 0) {
          const percentage = Math.round((present / total) * 100);
          if (percentage < 75) {
            lowStudents.push({ name: student.name, rollNo: student.rollNo, batch: batch.name, percentage });
          }
        }
      }
    }

    res.json(lowStudents.sort((a, b) => a.percentage - b.percentage));
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// GET /api/attendance/admin/batches — all batches for admin dropdown
const getStudentHeatmapData = async (req, res) => {
  try {
    const { studentEmail } = req.query;
    if (!studentEmail) return res.status(400).json({ message: "studentEmail required" });

    const student = await Student.findOne({ email: new RegExp(`^${escapeRegex(studentEmail)}$`, "i") });
    if (!student) return res.status(404).json({ message: "Student not found" });

    const studentId = student._id.toString();

    // Fetch all attendance records where this student is present/absent
    const sessions = await Attendance.find({
      "records.student": student._id
    }).select("date records.student records.status");

    const heatmapData = sessions.map(session => {
      const record = session.records.find(r => r.student.toString() === studentId);
      return {
        date: session.date.toISOString().split('T')[0],
        status: record ? record.status : 'no_class'
      };
    });

    res.json(heatmapData);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

const getAllBatches = async (req, res) => {
  try {
    const batches = await Batch.find().populate("course", "name").select("name course");
    res.json(batches);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

const qrCheckin = async (req, res) => {
  try {
    const { studentId } = req.body;
    if (!studentId) return res.status(400).json({ message: "studentId required" });

    // 1. Find the student
    const student = await Student.findById(studentId);
    if (!student) return res.status(404).json({ message: "Student not found" });

    // 2. Find their batch
    const batch = await Batch.findOne({ name: student.batch });
    if (!batch) return res.status(404).json({ message: "Batch not found" });

    // 3. Find today's attendance for this batch
    const start = new Date();
    start.setHours(0, 0, 0, 0);
    const end = new Date();
    end.setHours(23, 59, 59, 999);

    let attendance = await Attendance.findOne({
      batch: batch._id,
      date: { $gte: start, $lte: end }
    });

    if (!attendance) {
      // Create new attendance for today if it doesn't exist
      // Initially everyone is absent, we'll mark this one as present
      const allStudents = await Student.find({ batch: student.batch });
      const records = allStudents.map(s => ({
        student: s._id,
        status: s._id.toString() === studentId ? 'present' : 'absent'
      }));

      attendance = await Attendance.create({
        batch: batch._id,
        date: new Date(),
        records,
        markedBy: req.user.id
      });
    } else {
      // Update existing attendance
      const recordIndex = attendance.records.findIndex(r => r.student.toString() === studentId);
      if (recordIndex !== -1) {
        attendance.records[recordIndex].status = 'present';
      } else {
        // Student was not in the original list (maybe added later to batch)
        attendance.records.push({ student: studentId, status: 'present' });
      }
      await attendance.save();
    }

    res.json({ 
      success: true, 
      message: "Attendance marked!", 
      student: { name: student.name, rollNo: student.rollNo, batch: student.batch }
    });
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

module.exports = {
  getFacultyBatches,
  getAttendance,
  submitAttendance,
  getAttendanceSummary,
  getStudentAttendance,
  getStudentHeatmapData,
  getAdminOverview,
  getLowAttendance,
  getAllBatches,
  qrCheckin,
};

