  return jwt.sign({ id }, process.env.JWT_SECRET || "super_secret_jwt_key_srs_academy_2026", {
    expiresIn: "30d",
  });
};

const sendError = (error, res, next) => {
  if (typeof next === "function") {
    return next(error);
  }

  return res.status(error.statusCode || 500).json({
    message: error.message || "Server Error",
  });
};

const registerUser = async (req, res, next) => {
  try {
    const { name, email, password, role } = req.body;

    const userExists = await User.findOne({ email });

    if (userExists) {
      const error = new Error("User already exists");
      error.statusCode = 400;
      throw error;
    }

    const user = await User.create({
      name,
      email,
      password,
      role: role || "student",
    });

    if (user) {
      res.status(201).json({
        _id: user._id,
        name: user.name,
        email: user.email,
        role: user.role,
        token: generateToken(user._id),
      });
    } else {
      const error = new Error("Invalid user data");
      error.statusCode = 400;
      throw error;
    }
  } catch (error) {
    return sendError(error, res, next);
  }
};

const loginUser = async (req, res, next) => {
  try {
    const { email, password } = req.body;

    const user = await User.findOne({ email });

    if (user && (await user.matchPassword(password))) {
      res.json({
        _id: user._id,
        name: user.name,
        email: user.email,
        role: user.role,
        token: generateToken(user._id),
      });
    } else {
      const error = new Error("Invalid email or password");
      error.statusCode = 401;
      throw error;
    }
  } catch (error) {
    return sendError(error, res, next);
  }
};

const getProfile = async (req, res, next) => {
  try {
    const user = await User.findById(req.user._id).select("-password");
    if (user) {
      res.json(user);
    } else {
      const error = new Error("User not found");
      error.statusCode = 404;
      throw error;
    }
  } catch (error) {
    return sendError(error, res, next);
  }
};

const changePassword = async (req, res, next) => {
  try {
    const { currentPassword, newPassword } = req.body;
    const user = await User.findById(req.user._id);

    if (!user) {
      const error = new Error("User not found");
      error.statusCode = 404;
      throw error;
    }

    // Check if current password is correct
    const isMatch = await user.matchPassword(currentPassword);
    if (!isMatch) {
      const error = new Error("Current password is incorrect");
      error.statusCode = 401;
      throw error;
    }

    // Update password (model middleware will handle hashing)
    user.password = newPassword;
    await user.save();

    res.json({ message: "Password updated successfully" });
  } catch (error) {
    return sendError(error, res, next);
  }
};

module.exports = { registerUser, loginUser, getProfile, changePassword };

