const Material = require("../models/Material");
const path = require("path");
const fs = require("fs");

// @desc  Get all materials
// @route GET /api/materials
// @access Private (all roles)
const getMaterials = async (req, res) => {
  try {
    const { subject, course, search } = req.query;
    const query = {};

    if (subject) query.subject = { $regex: subject, $options: "i" };
    if (course) query.course = { $regex: course, $options: "i" };
    if (search) {
      query.$or = [
        { title: { $regex: search, $options: "i" } },
        { subject: { $regex: search, $options: "i" } },
        { description: { $regex: search, $options: "i" } },
      ];
    }

    const materials = await Material.find(query).sort({ createdAt: -1 });
    res.json(materials);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

// @desc  Upload a new material
// @route POST /api/materials
// @access Private (admin, faculty)
const uploadMaterial = async (req, res) => {
  try {
    if (!req.files || !req.files.file) {
      return res.status(400).json({ message: "No file uploaded." });
    }

    const { title, description, subject, course, batch } = req.body;

    if (!title) {
      return res.status(400).json({ message: "Title is required." });
    }

    const uploadedFile = req.files.file;
    const ext = path.extname(uploadedFile.name).toLowerCase().replace(".", "");
    const safeName = `material_${Date.now()}_${uploadedFile.name.replace(/\s+/g, "_")}`;
    const uploadPath = path.join(__dirname, "../uploads", safeName);

    // Ensure uploads directory exists
    const uploadsDir = path.join(__dirname, "../uploads");
    if (!fs.existsSync(uploadsDir)) {
      fs.mkdirSync(uploadsDir, { recursive: true });
    }

    await uploadedFile.mv(uploadPath);

    const material = await Material.create({
      title,
      description: description || "",
      subject: subject || "",
      course: course || "",
      batch: batch || "",
      fileUrl: `/uploads/${safeName}`,
      fileName: uploadedFile.name,
      fileType: ext,
      fileSize: uploadedFile.size,
      uploadedBy: req.user._id,
      uploaderName: req.user.name,
      uploaderRole: req.user.role,
    });

    res.status(201).json(material);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

// @desc  Delete a material
// @route DELETE /api/materials/:id
// @access Private (admin or uploader)
const deleteMaterial = async (req, res) => {
  try {
    const material = await Material.findById(req.params.id);
    if (!material) {
      return res.status(404).json({ message: "Material not found." });
    }

    // Only admin or the uploader can delete
    if (
      req.user.role !== "admin" &&
      material.uploadedBy?.toString() !== req.user._id.toString()
    ) {
      return res.status(403).json({ message: "Not authorized to delete this material." });
    }

    // Delete the file from disk
    const filePath = path.join(__dirname, "../", material.fileUrl);
    if (fs.existsSync(filePath)) {
      fs.unlinkSync(filePath);
    }

    await material.deleteOne();
    res.json({ message: "Material deleted successfully." });
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

module.exports = { getMaterials, uploadMaterial, deleteMaterial };

