// @desc    Add a student
// @route   POST /api/students
const addStudent = async (req, res) => {
  const { name, rollNo, email, phone, batch, course, feesStatus } = req.body;

  try {
    const studentExists = await Student.findOne({ rollNo });
    if (studentExists) {
      return res.status(400).json({ message: "Student with this Roll No already exists" });
    }

    const student = await Student.create({
      name,
      rollNo,
      email,
      phone,
      batch,
      course,
      feesStatus,
    });

    res.status(201).json(student);
  } catch (error) {
    res.status(400).json({ message: error.message });
  }
};

// @desc    Update a student
// @route   PUT /api/students/:id
const updateStudent = async (req, res) => {
  try {
    const student = await Student.findById(req.params.id);

    if (student) {
      student.name = req.body.name || student.name;
      student.rollNo = req.body.rollNo || student.rollNo;
      student.email = req.body.email || student.email;
      student.phone = req.body.phone || student.phone;
      student.batch = req.body.batch || student.batch;
      student.course = req.body.course || student.course;
      student.feesStatus = req.body.feesStatus || student.feesStatus;

      const updatedStudent = await student.save();
      res.json(updatedStudent);
    } else {
      res.status(404).json({ message: "Student not found" });
    }
  } catch (error) {
    res.status(400).json({ message: error.message });
  }
};

// @desc    Delete a student
// @route   DELETE /api/students/:id
const deleteStudent = async (req, res) => {
  try {
    const student = await Student.findById(req.params.id);

    if (student) {
      await Student.deleteOne({ _id: student._id });
      res.json({ message: "Student removed" });
    } else {
      res.status(404).json({ message: "Student not found" });
    }
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

// @desc    Import students from CSV
// @route   POST /api/students/import
const importStudents = async (req, res) => {
  if (!req.file) {
    return res.status(400).json({ message: "Please upload a CSV file" });
  }

  const students = [];
  const filePath = req.file.path;

  fs.createReadStream(filePath)
    .pipe(csv())
    .on("data", (data) => {
      // Basic cleaning of keys (trim whitespace)
      const cleanedData = {};
      Object.keys(data).forEach(key => {
        cleanedData[key.trim()] = data[key].trim();
      });
      students.push(cleanedData);
    })
    .on("end", async () => {
      try {
        // Bulk insert
        await Student.insertMany(students, { ordered: false });
        fs.unlinkSync(filePath); // Delete temporary file
        res.status(201).json({ message: `${students.length} students imported successfully` });
      } catch (error) {
        fs.unlinkSync(filePath);
        res.status(400).json({ message: "Error importing students. Some records might be duplicates.", error: error.message });
      }
    });
};

module.exports = {
  getStudents,
  addStudent,
  updateStudent,
  deleteStudent,
  importStudents,
};

