      const record = att.records.find(r => r.student.toString() === studentId.toString());
      if (record && record.status === "present") presentCount++;
    });
    const totalAttendance = attendanceRecords.length;
    const attendancePercentage = totalAttendance > 0 ? Math.round((presentCount / totalAttendance) * 100) : 0;

    // 2. Calculate Fees
    const totalPaid = payments.reduce((sum, p) => sum + p.amount, 0);
    const totalFee = 50000; // Ideally fetched from Course
    const feesDue = totalFee - totalPaid;

    // 3. Format Latest Result
    let latestScore = null;
    if (latestResult) {
      const record = latestResult.records.find(r => r.student.toString() === studentId.toString());
      latestScore = {
        testName: latestResult.testName,
        subject: latestResult.subject,
        marks: record ? record.marks : 0,
        totalMarks: latestResult.totalMarks
      };
    }

    // 4. Get Next Class (Sequential only if batch was found)
    let nextClass = null;
    if (batch) {
      nextClass = await Timetable.findOne({ 
        batch: batch._id, 
        day: today 
      }).sort({ startTime: 1 }).lean();
    }

    // 5. Attendance Chart Data
    const chartData = attendanceRecords.slice(0, 7).reverse().map(att => {
      const record = att.records.find(r => r.student.toString() === studentId.toString());
      return {
        name: new Date(att.date).toLocaleDateString('en-US', { weekday: 'short' }),
        present: record && record.status === "present" ? 100 : 0
      };
    });

    res.json({
      student,
      summary: {
        attendancePercentage,
        feesDue,
        latestScore,
        nextClass,
      },
      notices,
      chartData: chartData.length > 0 ? chartData : [
        { name: 'Mon', present: 0 }, { name: 'Tue', present: 0 }, { name: 'Wed', present: 0 },
        { name: 'Thu', present: 0 }, { name: 'Fri', present: 0 }, { name: 'Sat', present: 0 }
      ]
    });

  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};


// @desc    Get student test results
// @route   GET /api/students/panel/results
const getStudentResults = async (req, res) => {
  try {
    const student = await Student.findOne({ email: req.user.email });
    if (!student) return res.status(404).json({ message: "Student profile not found." });

    const results = await Result.find({ "records.student": student._id })
      .sort({ createdAt: -1 })
      .populate("faculty", "name subject")
      .lean();

    const formatted = results.map(r => {
      const record = r.records.find(rec => rec.student.toString() === student._id.toString());
      return {
        _id: r._id,
        testName: r.testName,
        subject: r.subject,
        totalMarks: r.totalMarks,
        marks: record ? record.marks : 0,
        percentage: r.totalMarks ? Math.round((record.marks / r.totalMarks) * 100) : 0,
        date: r.createdAt,
        faculty: r.faculty?.name || "N/A"
      };
    });

    res.json(formatted);
  } catch (error) {
    res.status(500).json({ message: error.message });
  }
};

module.exports = {
  getDashboardData,
  getStudentResults
};

