  try {
    const filter = {};
    if (req.query.batch) filter.batch = req.query.batch;
    if (req.query.faculty) filter.faculty = req.query.faculty;

    const slots = await Timetable.find(filter)
      .populate("faculty", "name subject")
      .populate({ path: "batch", populate: { path: "course", select: "name" } })
      .sort({ startTime: 1 });

    // Group by day
    const grouped = {};
    for (const day of DAYS) grouped[day] = [];
    for (const slot of slots) {
      if (grouped[slot.day]) grouped[slot.day].push(slot);
    }

    res.json(grouped);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

