const createLog = async (req, res) => {
  try {
    const { facultyEmail, batch, subject, durationSeconds } = req.body;

    let facultyId = req.body.faculty;
    if (!facultyId && facultyEmail) {
      const faculty = await Faculty.findOne({ email: new RegExp(`^${facultyEmail}$`, "i") });
      if (!faculty) return res.status(404).json({ message: "Faculty profile not found for this email" });
      facultyId = faculty._id;
    }

    const log = await TeachingLog.create({ faculty: facultyId, batch, subject, durationSeconds });
    const populated = await log.populate([
      { path: "faculty", select: "name subject" },
      { path: "batch", populate: { path: "course", select: "name" } },
    ]);
    res.status(201).json(populated);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
};

// PATCH /api/timetable/logs/:id/verify
const verifyLog = async (req, res) => {
  try {
    const log = await TeachingLog.findByIdAndUpdate(
      req.params.id,
      { status: "Verified" },
      { new: true }
    ).populate("faculty", "name").populate("batch", "name");
    if (!log) return res.status(404).json({ message: "Log not found" });
    res.json(log);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

// GET /api/timetable/faculty-summary — total hours per faculty for admin
const getFacultySummary = async (req, res) => {
  try {
    const summary = await TeachingLog.aggregate([
      {
        $group: {
          _id: "$faculty",
          totalSeconds: { $sum: "$durationSeconds" },
          sessionCount: { $sum: 1 },
        },
      },
      { $sort: { totalSeconds: -1 } },
    ]);

    const populated = await Faculty.populate(summary, { path: "_id", select: "name subject status" });

    const result = populated.map((s) => ({
      faculty: s._id,
      totalSeconds: s.totalSeconds,
      sessionCount: s.sessionCount,
      totalHours: (s.totalSeconds / 3600).toFixed(1),
    }));

    res.json(result);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
};

module.exports = {
  getSlots, getWeekSlots, createSlot, updateSlot, deleteSlot,
  getLogs, createLog, verifyLog, getFacultySummary,
};

