  let token;

  if (
    req.headers.authorization &&
    req.headers.authorization.startsWith("Bearer")
  ) {
    try {
      token = req.headers.authorization.split(" ")[1];
      const decoded = jwt.verify(token, process.env.JWT_SECRET || "super_secret_jwt_key_srs_academy_2026");

      req.user = await User.findById(decoded.id).select("-password");
      return next();
    } catch (error) {
      error.statusCode = 401;
      error.message = "Not authorized, token failed";
      return next(error);
    }
  }

  if (!token) {
    const error = new Error("Not authorized, no token");
    error.statusCode = 401;
    return next(error);
  }
};

const admin = (req, res, next) => {
  if (req.user && req.user.role === "admin") {
    return next();
  }

  const error = new Error("Not authorized as an admin");
  error.statusCode = 403;
  return next(error);
};

const faculty = (req, res, next) => {
  if (req.user && (req.user.role === "faculty" || req.user.role === "admin")) {
    return next();
  }

  const error = new Error("Not authorized as faculty");
  error.statusCode = 403;
  return next(error);
};

// Generalized role-based authorization middleware
const authorize = (...roles) => {
  return (req, res, next) => {
    if (!req.user || !roles.includes(req.user.role)) {
