const express = require("express");
const router = express.Router();
const multer = require("multer");
const path = require("path");
const {
  getStudents,
  addStudent,
  updateStudent,
  deleteStudent,
  importStudents,
} = require("../controllers/studentController");
const { getDashboardData, getStudentResults } = require("../controllers/studentPanelController");
const { protect } = require("../middleware/authMiddleware");

// Multer Config for CSV Upload
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, "uploads/");
  },
  filename: (req, file, cb) => {
    cb(null, `${file.fieldname}-${Date.now()}${path.extname(file.originalname)}`);
  },
});

const upload = multer({
  storage: storage,
  fileFilter: (req, file, cb) => {
    if (path.extname(file.originalname) === ".csv") {
      cb(null, true);
    } else {
      cb(new Error("Only CSV files are allowed"), false);
    }
  },
});

router.route("/").get(getStudents).post(addStudent);
router.route("/:id").put(updateStudent).delete(deleteStudent);
router.post("/import", upload.single("file"), importStudents);

// Student Panel Routes
router.get("/panel/dashboard", protect, getDashboardData);
router.get("/panel/results", protect, getStudentResults);

module.exports = router;

