const sendAbsenteeNotification = async (studentName, parentPhone, subject, date) => {
  try {
    const formattedDate = new Date(date).toLocaleDateString('mr-IN', {
      weekday: 'long',
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });

    const message = `*अनुपस्थिती सूचना - SRS ACADEMY*\n\nप्रिय पालक,\n\nआपले पाल्य *${studentName}* हे *${subject}* या लेक्चरला ${formattedDate} रोजी *अनुपस्थित* होते.\n\nनियमित उपस्थिती ही विद्यार्थ्यांच्या शैक्षणिक प्रगतीसाठी अत्यंत महत्त्वाची आहे. कृपया आपल्या पाल्याला पुढील लेक्चरला उपस्थित राहण्यास सांगावे.\n\n_हा संदेश SRS Academy Management कडून स्वयंचलितरित्या पाठविण्यात आला आहे._`;

